public class DataColumnSidecarGossipValidatorRaceTest {

  @Test
  void concurrentValidationsBothDoWork_butOnlyOneIsAccepted() throws Exception {

    final Spec spec = TestSpecFactory.createMinimalFulu();
    final DataStructureUtil util = new DataStructureUtil(spec);

    final SignedBeaconBlockHeader header = util.randomSignedBeaconBlockHeader();

    // @audit we will validate the SAME sidecar (index=1) concurrently
    final DataColumnSidecar s2 = makeSidecar(spec, util, header, UInt64.ONE);

    final GossipValidationHelper gossip = mock(GossipValidationHelper.class);
    when(gossip.isSlotFromFuture(any())).thenReturn(false);
    when(gossip.isSlotFinalized(any())).thenReturn(false);
    when(gossip.isBlockAvailable(any())).thenReturn(true);
    when(gossip.getSlotForBlockRoot(any()))
        .thenReturn(Optional.of(header.getMessage().getSlot().minusMinZero(1)));
    when(gossip.currentFinalizedCheckpointIsAncestorOfBlock(any(), any())).thenReturn(true);
    when(gossip.isProposerTheExpectedProposer(any(), any(), any())).thenReturn(true);
    when(gossip.isSignatureValidWithRespectToProposerIndex(any(), any(), any(), any()))
        .thenReturn(true);


    final MetricsSystem metrics = mock(MetricsSystem.class, Answers.RETURNS_DEEP_STUBS);
    final TimeProvider time = () -> UInt64.valueOf(System.currentTimeMillis());
    final KZG kzg = mock(KZG.class);

    final MiscHelpersFulu helpers = mock(MiscHelpersFulu.class);
    when(helpers.verifyDataColumnSidecar(any())).thenReturn(true);
    when(helpers.verifyDataColumnSidecarInclusionProof(any())).thenReturn(true);

     // @audit Synchronize both calls inside the expensive step (KZG) to force the race
    final CyclicBarrier barrier = new CyclicBarrier(2);
    final AtomicInteger kzgCalls = new AtomicInteger(0);
    doAnswer(
            inv -> {
              kzgCalls.incrementAndGet();
              try {
                 // @audit both threads wait here so they've BOTH passed the early pre-check
                barrier.await(5, TimeUnit.SECONDS);
              } catch (BrokenBarrierException | TimeoutException e) {
                throw new RuntimeException(e);
              }
              return true;  // @audit  let KZG pass
            })
        .when(helpers)
        .verifyDataColumnSidecarKzgProofs(eq(kzg), any());

    final DataColumnSidecarGossipValidator validator =
        DataColumnSidecarGossipValidator.create(
            spec, new HashMap<>(), gossip, helpers, kzg, metrics, time);

    // @audit Preload the known-header set via reflection so fast-path is taken
    makeHeaderKnownValid(validator, header.hashTreeRoot());

    // @audit - validate the same tuple twice concurrently
    final ExecutorService pool = Executors.newFixedThreadPool(2);
    try {
      final Future<InternalValidationResult> f1 = pool.submit(() -> validator.validate(s2).join());
      final Future<InternalValidationResult> f2 = pool.submit(() -> validator.validate(s2).join());

      final InternalValidationResult r1 = f1.get(5, TimeUnit.SECONDS);
      final InternalValidationResult r2 = f2.get(5, TimeUnit.SECONDS);

      // @audit - assert that there is only one `ACCEPT`
      int accepts =
          (Objects.equals(r1, InternalValidationResult.ACCEPT) ? 1 : 0)
        + (Objects.equals(r2, InternalValidationResult.ACCEPT) ? 1 : 0);
      assertThat(accepts).as("Exactly one validation should be ACCEPT").isEqualTo(1);

      // @audit Expensive verification ran twice (proves duplicate work under the race)
      assertThat(kzgCalls.get()).isEqualTo(2);

      // @audit Only one unique tuple added for column index 1
      long countIndex1 =
          validator.getReceivedValidDataColumnSidecarInfoSet().stream()
              .filter(e -> e.columnIndex().equals(UInt64.ONE))
              .count();
      assertThat(countIndex1).isEqualTo(1L);
    } finally {
      pool.shutdownNow();
    }
  }

  private static void makeHeaderKnownValid(
      final DataColumnSidecarGossipValidator validator, final Bytes32 headerRoot) throws Exception {
    final Field f =
        DataColumnSidecarGossipValidator.class.getDeclaredField("validSignedBlockHeaders");
    f.setAccessible(true);
    @SuppressWarnings("unchecked")
    final Set<Bytes32> set = (Set<Bytes32>) f.get(validator);
    set.add(headerRoot);
  }

  private static DataColumnSidecar makeSidecar(
      final Spec spec,
      final DataStructureUtil util,
      final SignedBeaconBlockHeader header,
      final UInt64 index) {

    final UInt64 slot = header.getMessage().getSlot();

    // @audit Fulu schema at this slot
    final SchemaDefinitionsFulu fuluSchemas =
        spec.atSlot(slot).getSchemaDefinitions().toVersionFulu().orElseThrow();
    final DataColumnSidecarSchema schema = fuluSchemas.getDataColumnSidecarSchema();

    // @audit Small fixed number of proofs/commitments to keep it simple
    final int numberOfProofs = 2;

    final var dataColumn = util.randomDataColumn(slot, numberOfProofs);
    final var kzgCommitments =
        IntStream.range(0, numberOfProofs).mapToObj(__ -> util.randomKZGCommitment()).toList();
    final var kzgProofs =
        IntStream.range(0, numberOfProofs).mapToObj(__ -> util.randomKZGProof()).toList();
    final int inclusionLen = schema.getKzgCommitmentsInclusionProofSchema().getLength();
    final var inclusionProof =
        IntStream.range(0, inclusionLen).mapToObj(__ -> util.randomBytes32()).toList();

    return schema.create(index, dataColumn, kzgCommitments, kzgProofs, header, inclusionProof);
  }
}
```

## Mitigation
You can implement an in-flight map, mapping the key to a `SafeFuture<InternalValidationResult>`, so that only the first caller performs the expensive checks.

With this fix only the first caller for a key executes the work. Other concurrent callers see the same `future` and receive the same result . The final `add` remains the canonical guard for acceptance.

Note: you can try running the PoC after the mitigation, you will see the test fail with a time out error, as now only one thread ever runs the computation. The other thread never calls the PoC mocked method, triggering the timeout at `barrier.await(5, TimeUnit.SECONDS);`

