func TestService_BroadcastDataColumn(t *testing.T) {
	const (
		port        = 2000
		columnIndex = 12
		topicFormat = DataColumnSubnetTopicFormat
	)

	// Load the KZG trust setup.
	err := kzg.Start()
	require.NoError(t, err)

	gFlags := new(flags.GlobalFlags)
	gFlags.MinimumPeersPerSubnet = 1
	flags.Init(gFlags)

	// Reset config.
	defer flags.Init(new(flags.GlobalFlags))

	// Create two peers and connect them.
	p1, p2 := p2ptest.NewTestP2P(t), p2ptest.NewTestP2P(t)
	p1.Connect(p2)

	// Test the peers are connected.
	require.NotEqual(t, 0, len(p1.BHost.Network().Peers()), "No peers")

	// Create a host.
	_, pkey, ipAddr := createHost(t, port)

	service := &Service{
		ctx:                   t.Context(),
		host:                  p1.BHost,
		pubsub:                p1.PubSub(),
		joinedTopics:          map[string]*pubsub.Topic{},
		cfg:                   &Config{},
		genesisTime:           time.Now(),
		genesisValidatorsRoot: bytesutil.PadTo([]byte{'A'}, 32),
		subnetsLock:           make(map[uint64]*sync.RWMutex),
		subnetsLockLock:       sync.Mutex{},
		peers:                 peers.NewStatus(t.Context(), &peers.StatusConfig{ScorerParams: &scorers.Config{}}),
		custodyInfo:           &custodyInfo{},
	}

	// Create a listener.
	listener, err := service.startDiscoveryV5(ipAddr, pkey)
	require.NoError(t, err)

	service.dv5Listener = listener

	digest, err := service.currentForkDigest()
	require.NoError(t, err)

	subnet := peerdas.ComputeSubnetForDataColumnSidecar(columnIndex)
	topic := fmt.Sprintf(topicFormat, digest, subnet) + service.Encoding().ProtocolSuffix()

	roSidecars, _ := util.CreateTestVerifiedRoDataColumnSidecars(t, []util.DataColumnParam{{Index: columnIndex}})
	sidecar := roSidecars[0].DataColumnSidecar

	// Attempt to broadcast nil object should fail.
	var emptyRoot [fieldparams.RootLength]byte
	err = service.BroadcastDataColumnSidecar(emptyRoot, subnet, nil)
	require.ErrorContains(t, "attempted to broadcast nil", err)

	// Subscribe to the topic.
	sub, err := p2.SubscribeToTopic(topic)
	require.NoError(t, err)

	// libp2p fails without this delay
	time.Sleep(50 * time.Millisecond)

	// Broadcast to peers and wait.
	err = service.BroadcastDataColumnSidecar(emptyRoot, subnet, sidecar)
	require.NoError(t, err)

	// Receive the message.
	ctx, cancel := context.WithTimeout(t.Context(), 5*time.Second)
	defer cancel()

	msg, err := sub.Next(ctx)
	require.NoError(t, err)

	var result ethpb.DataColumnSidecar
	require.NoError(t, service.Encoding().DecodeGossip(msg.Data, &result))
	require.DeepEqual(t, &result, sidecar)
}


func TestService_Broadcast_UsesCurrentForkDigest_AcrossForkEpoch(t *testing.T) {
	params.SetupTestConfigCleanup(t)

	// Force a fork at epoch 1 so the fork digest changes between epoch 0 and 1.
	cfg := params.BeaconConfig().Copy()
	cfg.AltairForkEpoch = 1
	cfg.ForkVersionSchedule[bytesutil.ToBytes4(cfg.AltairForkVersion)] = primitives.Epoch(1)
	params.OverrideBeaconConfig(cfg)

	p1 := p2ptest.NewTestP2P(t)
	p2 := p2ptest.NewTestP2P(t)
	p1.Connect(p2)
	require.NotEqual(t, 0, len(p1.BHost.Network().Peers()), "No peers")

	s := &Service{
		host:                  p1.BHost,
		pubsub:                p1.PubSub(),
		joinedTopics:          map[string]*pubsub.Topic{},
		cfg:                   &Config{},
		genesisValidatorsRoot: bytesutil.PadTo([]byte{'A'}, 32),
	}

	// Use a static message type with a test topic format.
	msg := &ethpb.Fork{Epoch: 0, CurrentVersion: cfg.GenesisForkVersion, PreviousVersion: cfg.GenesisForkVersion}
	topicFmt := "/eth2/%x/testing"
	GossipTypeMapping[reflect.TypeOf(msg)] = topicFmt

	// Case 1: epoch 0 -> expect digest for epoch 0.
	s.genesisTime = time.Now()
	d0, err := s.currentForkDigest()
	require.NoError(t, err)
	expectedTopic0 := fmt.Sprintf(topicFmt, d0) + s.Encoding().ProtocolSuffix()
	sub0, err := p2.SubscribeToTopic(expectedTopic0)
	require.NoError(t, err)
	time.Sleep(50 * time.Millisecond)
	var wg sync.WaitGroup
	wg.Add(1)
	go func() {
		defer wg.Done()
		ctx, cancel := context.WithTimeout(t.Context(), 2*time.Second)
		defer cancel()
		incoming, err := sub0.Next(ctx)
		require.NoError(t, err)
		var got ethpb.Fork
		require.NoError(t, s.Encoding().DecodeGossip(incoming.Data, &got))
		if !proto.Equal(&got, msg) {
			t.Errorf("unexpected message: got %+v", &got)
		}
	}()
	require.NoError(t, s.Broadcast(t.Context(), msg))
	require.Equal(t, false, util.WaitTimeout(&wg, 2*time.Second))

	// Case 2: move local clock to epoch 1 -> expect new digest and topic.
	oneEpochDur := time.Duration(uint64(params.BeaconConfig().SlotsPerEpoch)*params.BeaconConfig().SecondsPerSlot) * time.Second
	s.genesisTime = time.Now().Add(-oneEpochDur)
	d1, err := s.currentForkDigest()
	require.NoError(t, err)
	require.NotEqual(t, d0, d1, "fork digest should change at epoch 1 after fork schedule override")
	expectedTopic1 := fmt.Sprintf(topicFmt, d1) + s.Encoding().ProtocolSuffix()
	sub1, err := p2.SubscribeToTopic(expectedTopic1)
	require.NoError(t, err)
	time.Sleep(50 * time.Millisecond)
	wg.Add(1)
	go func() {
		defer wg.Done()
		ctx, cancel := context.WithTimeout(t.Context(), 2*time.Second)
		defer cancel()
		incoming, err := sub1.Next(ctx)
		require.NoError(t, err)
		var got ethpb.Fork
		require.NoError(t, s.Encoding().DecodeGossip(incoming.Data, &got))
		if !proto.Equal(&got, msg) {
			t.Errorf("unexpected message: got %+v", &got)
		}
	}()
	require.NoError(t, s.Broadcast(t.Context(), msg))
	require.Equal(t, false, util.WaitTimeout(&wg, 2*time.Second))
}

func Test_Attestation_DialsBeforeFreshnessCheck_OnStale(t *testing.T) {
	// Ensure non-zero subnet peer threshold so discovery branch triggers.
	gFlags := new(flags.GlobalFlags)
	gFlags.MinimumPeersPerSubnet = 1
	flags.Init(gFlags)
	defer flags.Init(new(flags.GlobalFlags))

	p := p2ptest.NewTestP2P(t)
	svc := &Service{
		host:                  p.BHost,
		pubsub:                p.PubSub(),
		joinedTopics:          map[string]*pubsub.Topic{},
		cfg:                   &Config{},
		genesisTime:           time.Now(),
		genesisValidatorsRoot: bytesutil.PadTo([]byte{'A'}, 32),
		subnetsLock:           make(map[uint64]*sync.RWMutex),
		subnetsLockLock:       sync.Mutex{},
		peers:                 peers.NewStatus(t.Context(), &peers.StatusConfig{ScorerParams: &scorers.Config{}}),
	}

	// Prepare a stale attestation.
	att := util.HydrateAttestation(&ethpb.Attestation{AggregationBits: bitfield.NewBitlist(7)})
	currSlot := slots.CurrentSlot(svc.genesisTime)
	var staleSlot primitives.Slot
	// Ensure the slot is earlier than the allowed propagation range.
	if currSlot > params.BeaconConfig().AttestationPropagationSlotRange+2 {
		staleSlot = currSlot - (params.BeaconConfig().AttestationPropagationSlotRange + 2)
	} else {
		staleSlot = 0
	}
	att.Data.Slot = staleSlot

	GossipTypeMapping[reflect.TypeOf(att)] = AttestationSubnetTopicFormat

	preAttempts := getCounterVal(t, "p2p_attestation_subnet_attempted_broadcasts")
	preSaved := getCounterVal(t, "p2p_attestation_subnet_recovered_broadcasts")

	require.NoError(t, svc.BroadcastAttestation(t.Context(), 3 /* arbitrary subnet */, att))
	// Give the internal goroutine a brief moment to run.
	time.Sleep(100 * time.Millisecond)

	postAttempts := getCounterVal(t, "p2p_attestation_subnet_attempted_broadcasts")
	postSaved := getCounterVal(t, "p2p_attestation_subnet_recovered_broadcasts")

	// When there are no peers on the subnet, the broadcaster attempts discovery (dials)
	// before checking staleness. These counters reflect that path.
	require.Equal(t, true, postAttempts >= preAttempts+1)
	require.Equal(t, true, postSaved >= preSaved+1)
}

func Test_SyncCommittee_DialsBeforeFreshnessCheck_OnStale(t *testing.T) {
	// Ensure non-zero subnet peer threshold so discovery branch triggers.
	gFlags := new(flags.GlobalFlags)
