PoC unit test (`core/txpool/blobpool/poc_offload_path_reuses_stored_blobs_without_revalidating_osaka_cell_proofs_so_corrupted_disk_entries_could_leak_into_limbo_finality_tracking_test.go`):

```go
func TestPocOffloadPathReusesStoredBlobsWithoutRevalidatingOsakaCellProofsSoCorruptedDiskEntriesCouldLeakIntoLimboFinalityTracking(t *testing.T) {
    storage := t.TempDir()
    queuedir := filepath.Join(storage, pendingTransactionStore)
    if err := os.MkdirAll(queuedir, 0o700); err != nil {
        t.Fatalf("failed to create queue dir: %v", err)
    }

    store, err := billy.Open(billy.Options{Path: queuedir}, newSlotter(testMaxBlobsPerBlock), nil)
    if err != nil {
        t.Fatalf("failed to open blob store: %v", err)
    }

    key, err := crypto.GenerateKey()
    if err != nil {
        t.Fatalf("failed to create key: %v", err)
    }
    tx := makeMultiBlobTx(0, 1, 1, 1, 1, 0, key, types.BlobSidecarVersion1)
    sidecar := tx.BlobTxSidecar()
    if sidecar == nil {
        t.Fatalf("expected Osaka blob sidecar")
    }
    if len(sidecar.Proofs) == 0 {
        t.Fatalf("expected Osaka cell proofs on blob transaction")
    }
    proof := sidecar.Proofs[0]
    proof[0] ^= 0xff
    sidecar.Proofs[0] = proof

    encoded, err := rlp.EncodeToBytes(tx)
    if err != nil {
        t.Fatalf("failed to encode corrupted tx: %v", err)
    }
    if _, err := store.Put(encoded); err != nil {
        t.Fatalf("failed to persist corrupted tx: %v", err)
    }
    if err := store.Close(); err != nil {
        t.Fatalf("failed to close blob store: %v", err)
    }

    cfg := *params.MainnetChainConfig
    zero := uint64(0)
    cfg.OsakaTime = &zero
    cfg.CancunTime = &zero

    addr := crypto.PubkeyToAddress(key.PublicKey)
    statedb, err := state.New(types.EmptyRootHash, state.NewDatabaseForTesting())
    if err != nil {
        t.Fatalf("failed to create state: %v", err)
    }
    statedb.AddBalance(addr, uint256.NewInt(1_000_000_000), tracing.BalanceChangeUnspecified)
    if _, err := statedb.Commit(0, true, false); err != nil {
        t.Fatalf("failed to commit state: %v", err)
    }

    gasLimit := uint64(30_000_000)
    baseFee := big.NewInt(params.InitialBaseFee)
    excessBlobGas := uint64(0)
    ancestorHeader := &types.Header{
        Number:        big.NewInt(10),
        GasLimit:      gasLimit,
        GasUsed:       0,
        Time:          1,
        BaseFee:       new(big.Int).Set(baseFee),
        Difficulty:    big.NewInt(0),
        Root:          types.EmptyRootHash,
        ExcessBlobGas: new(uint64),
    }
    *ancestorHeader.ExcessBlobGas = excessBlobGas
    ancestorBlock := types.NewBlockWithHeader(ancestorHeader)

    chain := newReorgMockChain(&cfg, ancestorHeader, &types.Header{Number: big.NewInt(0)}, statedb)
    chain.blocks[ancestorBlock.Hash()] = ancestorBlock

    pool := New(Config{Datadir: storage}, chain, nil)
    if err := pool.Init(1, chain.CurrentBlock(), newReserver()); err != nil {
        t.Fatalf("failed to rehydrate blob pool: %v", err)
    }
    defer pool.Close()

    if err := pool.ValidateTxBasics(tx); err == nil {
        t.Fatalf("expected ValidateTxBasics to reject corrupted Osaka proofs")
    }

    metas := pool.index[addr]
    if len(metas) == 0 {
        t.Fatalf("expected corrupted Osaka blob to survive restart; bug appears fixed for %v", addr)
    }

    blockNumber := ancestorHeader.Number.Uint64() + 1
    oldHeader := &types.Header{
        ParentHash:    ancestorBlock.Hash(),
        Number:        new(big.Int).SetUint64(blockNumber),
        GasLimit:      gasLimit,
        GasUsed:       0,
        Time:          ancestorHeader.Time + 1,
        BaseFee:       new(big.Int).Set(baseFee),
        Difficulty:    big.NewInt(0),
        Root:          types.EmptyRootHash,
        ExcessBlobGas: new(uint64),
        Extra:         []byte{0x01},
    }
    *oldHeader.ExcessBlobGas = excessBlobGas
    oldBlock := types.NewBlockWithHeader(oldHeader).WithBody(types.Body{Transactions: []*types.Transaction{tx}})
    chain.blocks[oldBlock.Hash()] = oldBlock

    pool.head = oldHeader
    pool.state.SetNonce(addr, tx.Nonce()+1, tracing.NonceChangeUnspecified)
    inclusions := map[common.Hash]uint64{tx.Hash(): oldHeader.Number.Uint64()}
    pool.recheck(addr, inclusions)

    if _, ok := pool.index[addr]; ok {
        t.Fatalf("expected included blob to be evicted from pool index")
    }
    if pool.lookup.exists(tx.Hash()) {
        t.Fatalf("expected lookup to drop included transaction")
    }
    if got := len(pool.limbo.index); got != 1 {
        t.Fatalf("expected corrupted Osaka proofs to land in limbo; got %d entries", got)
    }

    reorgState, err := state.New(types.EmptyRootHash, state.NewDatabaseForTesting())
    if err != nil {
        t.Fatalf("failed to create reorg state: %v", err)
    }
    reorgState.AddBalance(addr, uint256.NewInt(1_000_000_000), tracing.BalanceChangeUnspecified)
    if _, err := reorgState.Commit(0, true, false); err != nil {
        t.Fatalf("failed to commit reorg state: %v", err)
    }
    chain.state = reorgState

    newHeader := &types.Header{
        ParentHash:    ancestorBlock.Hash(),
        Number:        new(big.Int).SetUint64(blockNumber),
        GasLimit:      gasLimit,
        GasUsed:       0,
        Time:          ancestorHeader.Time + 2,
        BaseFee:       new(big.Int).Set(baseFee),
        Difficulty:    big.NewInt(0),
        Root:          types.EmptyRootHash,
        ExcessBlobGas: new(uint64),
        Extra:         []byte{0x02},
    }
    *newHeader.ExcessBlobGas = excessBlobGas
    newBlock := types.NewBlockWithHeader(newHeader)
    chain.blocks[newBlock.Hash()] = newBlock
    chain.head = newHeader

    ch := make(chan core.NewTxsEvent, 1)
    sub := pool.SubscribeTransactions(ch, true)
    defer sub.Unsubscribe()

    pool.Reset(oldHeader, newHeader)

    var evt core.NewTxsEvent
    select {
    case evt = <-ch:
    default:
        t.Fatalf("expected reinjected blob announcement")
    }
    if len(evt.Txs) != 1 {
        t.Fatalf("expected single reorg reinject event, got %d", len(evt.Txs))
    }
    if evt.Txs[0].Hash() != tx.Hash() {
        t.Fatalf("unexpected tx hash in reinject event: got %s want %s", evt.Txs[0].Hash(), tx.Hash())
    }

    if !pool.lookup.exists(tx.Hash()) {
        t.Fatalf("expected corrupted transaction to be resurrected into pool")
    }

    rlpData := pool.getRLP(tx.Hash())
    if len(rlpData) == 0 {
        t.Fatalf("expected resurrected transaction payload")
    }
    var resurrected types.Transaction
    if err := rlp.DecodeBytes(rlpData, &resurrected); err != nil {
        t.Fatalf("failed to decode resurrected tx: %v", err)
    }
    if err := pool.ValidateTxBasics(&resurrected); err == nil {
        t.Fatalf("expected resurrected corrupted Osaka proofs to fail validation")
    }

    t.Logf("corrupted Osaka proofs persist through limbo reinjection and reinsertion events; bug still present for %v", addr)
}
```

The test passes today, demonstrating the vulnerability.


### Mitigation

Run `txpool.ValidateTransaction` (or the Osaka-specific subset) before writing to limbo and again when pulling from limbo, or delete limbo entries that fail validation before broadcasting them.

### Summary

 A missing deduplication and dial-throttling/backoff in ensurePeerConnections will cause repeated, immediate dials to the same peers whenever h.Network().ConnsToPeer(id) == 0. relayNodes duplicates within a single tick trigger multiple dials in one pass; across ticks, the same peers are re-dialed again without considering recent failures or pending dials. Under large or poisoned peer lists, this behavior can churn CPU, logs, and sockets, degrading node liveness and leading to missed duties.

### Root Cause

 No deduplication of peersToWatch within a single invocation
No awareness of in-flight dials or recent failures; decision is based only on len(ConnsToPeer) == 0
No backoff or rate-limiting; repeated invocations trigger repeated dials when connections are absent


```rust
for _, p := range peersToWatch {
    c := h.Network().ConnsToPeer(p.ID)
    if len(c) == 0 {
        _ = connectWithTimeout(ctx, h, p) // dials unconditionally
    }
}
```

### Internal Pre-conditions

Service.Start schedules ensurePeerConnections periodically (default TtfbTimeoutDuration).
peers.Status contains trusted peers and/or relayNodes is configured (CLI/env/config).
Network Host reports no active connections for the candidate peer IDs.

### External Pre-conditions

 relayNodes contains duplicates or many unreachable nodes; or trusted peers are unreachable.
Attacker/misconfig can inject many invalid/unreachable entries, or a fleet outage makes many peers unreachable.

### Attack Path

 Populate relayNodes with a very large list (order 10k) of non-routable/invalid addresses, optionally with duplicates.
Ensure ensurePeerConnections is invoked frequently (as the service already schedules).
Each tick:
All entries with no active connection are dialed without dedup or backoff.
Dials fail; next tick reattempts all again.
Secondary observation (log hygiene): When address resolution fails for a trusted peer, the error log includes the entire trustedPeers slice instead of the failing peer ID, increasing log noise. This is minor but included as a regression test.

### Impact

 Local DoS risk via resource churn:
Excess socket attempts and DNS lookups
Elevated CPU/log churn
Potential FD pressure and degraded responsiveness
In beacon nodes: increased likelihood of missed duties and degraded liveness under adverse conditions

### PoC

 ```rust
package p2p

import (
    "context"
    "testing"

    p2ptesting "github.com/OffchainLabs/prysm/v6/beacon-chain/p2p/testing"
    "github.com/OffchainLabs/prysm/v6/beacon-chain/p2p/peers"
