    ma "github.com/multiformats/go-multiaddr"
    logtest "github.com/sirupsen/logrus/hooks/test"
    "github.com/stretchr/testify/require"
)

// countingHost wraps a real libp2p host to count Connect calls while delegating everything else.
// Network() is real, so ConnsToPeer works and returns an empty slice when not connected.
type countingHost struct {
    inner host.Host
    calls int32
}

func (c *countingHost) ID() peer.ID                                   { return c.inner.ID() }
func (c *countingHost) Peerstore() peerstore.Peerstore                 { return c.inner.Peerstore() }
func (c *countingHost) Addrs() []ma.Multiaddr                          { return c.inner.Addrs() }
func (c *countingHost) Network() network.Network                       { return c.inner.Network() }
func (c *countingHost) Mux() protocol.Switch                           { return c.inner.Mux() }
func (c *countingHost) Connect(ctx context.Context, _ peer.AddrInfo) error { c.calls++; return nil }
func (c *countingHost) SetStreamHandler(pid protocol.ID, h network.StreamHandler)   { c.inner.SetStreamHandler(pid, h) }
func (c *countingHost) SetStreamHandlerMatch(id protocol.ID, f func(protocol.ID) bool, h network.StreamHandler) {
    c.inner.SetStreamHandlerMatch(id, f, h)
}
func (c *countingHost) RemoveStreamHandler(pid protocol.ID)            { c.inner.RemoveStreamHandler(pid) }
func (c *countingHost) NewStream(ctx context.Context, id peer.ID, p ...protocol.ID) (network.Stream, error) {
    return c.inner.NewStream(ctx, id, p...)
}
func (c *countingHost) Close() error                                   { return c.inner.Close() }
func (c *countingHost) ConnManager() connmgr.ConnManager               { return c.inner.ConnManager() }
func (c *countingHost) EventBus() event.Bus                            { return c.inner.EventBus() }

// TestEnsurePeerConnections_LogsTrustedPeersSliceOnAddressError reproduces the log leak:
// when peers.Address(trustedPeer) fails, the code logs the entire trustedPeers slice
// instead of the single trustedPeer. We capture the log and assert on its fields.
func TestEnsurePeerConnections_LogsTrustedPeersSliceOnAddressError(t *testing.T) {
    // Install a test logger to capture log entries from this package's logger.
    testLogger, hook := logtest.NewNullLogger()
    prevLogger := log.Logger
    log.Logger = testLogger
    defer func() { log.Logger = prevLogger }()

    // Create a peers.Status with a couple of trusted peers, but do NOT add any peer data.
    // Address() will return an error for these peers, triggering the error path.
    st := peers.NewStatus(context.Background(), &peers.StatusConfig{
        PeerLimit:    10,
        ScorerParams: &scorers.Config{},
    })
    id0, err := peer.Decode(p2ptesting.MockRawPeerId0)
    require.NoError(t, err)
    id1, err := peer.Decode(p2ptesting.MockRawPeerId1)
    require.NoError(t, err)
    st.SetTrustedPeers([]peer.ID{id0, id1})

    // Use the lightweight mock host; since peersToWatch remains empty, Network() is never called.
    h := &p2ptesting.MockHost{}

    // Run the function under test.
    ensurePeerConnections(context.Background(), h, st /* relayNodes */)

    // Find the error entry for the address failure and assert that it contains the full slice.
    var found bool
    for i := len(hook.Entries) - 1; i >= 0; i-- { // search from the end to be robust
        e := hook.Entries[i]
        if e.Message == "Could not get peer address" { // exact message in watch_peers.go
            found = true
            // The "peer" field should contain the entire trustedPeers slice (leak), not a single ID.
            val, ok := e.Data["peer"].([]peer.ID)
            require.True(t, ok, "expected field 'peer' to be []peer.ID, got %T", e.Data["peer"])
            require.Len(t, val, 2)
            // Order is not guaranteed; assert set-equality
            got := map[string]bool{val[0].String(): true, val[1].String(): true}
            require.True(t, got[id0.String()])
            require.True(t, got[id1.String()])
            break
        }
    }
    require.True(t, found, "expected an error log entry for 'Could not get peer address'")
}

// Build a valid multiaddr string (with /p2p/ID) from a libp2p host.
func multiaddrWithPeer(t *testing.T, h host.Host) string {
    addrs := h.Addrs()
    require.NotEmpty(t, addrs)
    return addrs[0].String() + "/p2p/" + h.ID().String()
}

// PoC 1: ensurePeerConnections dials the same peer twice in a single invocation if relayNodes contains duplicates.
func TestEnsurePeerConnections_DialsDuplicatesInSingleInvocation(t *testing.T) {
    // Real underlying libp2p host provides a real Network() for ConnsToPeer.
    inner, err := libp2p.New(libp2p.Transport(lbtcp.NewTCPTransport), libp2p.DefaultListenAddrs)
    require.NoError(t, err)
    t.Cleanup(func() { _ = inner.Close() })

    // Remote host only used to construct a valid multiaddr string.
    remote, err := libp2p.New(libp2p.Transport(lbtcp.NewTCPTransport), libp2p.DefaultListenAddrs)
    require.NoError(t, err)
    t.Cleanup(func() { _ = remote.Close() })

    // Wrap the host to count Connect() calls without actually dialing.
    h := &countingHost{inner: inner}

    // No trusted peers; use relayNodes with a duplicate entry for the same peer.
    st := peers.NewStatus(context.Background(), &peers.StatusConfig{PeerLimit: 10, ScorerParams: &scorers.Config{}})
    relay := multiaddrWithPeer(t, remote)
    ensurePeerConnections(context.Background(), h, st, relay, relay)

    require.Equal(t, int32(2), h.calls, "expected 2 Connect calls due to duplicate relayNodes entries")
}

// PoC 2: ensurePeerConnections re-dials on every invocation when no connection exists (ignores pending/recent failures).
func TestEnsurePeerConnections_RedialsOnEachInvocation(t *testing.T) {
    inner, err := libp2p.New(libp2p.Transport(lbtcp.NewTCPTransport), libp2p.DefaultListenAddrs)
    require.NoError(t, err)
    t.Cleanup(func() { _ = inner.Close() })

    remote, err := libp2p.New(libp2p.Transport(lbtcp.NewTCPTransport), libp2p.DefaultListenAddrs)
    require.NoError(t, err)
    t.Cleanup(func() { _ = remote.Close() })

    h := &countingHost{inner: inner}
    st := peers.NewStatus(context.Background(), &peers.StatusConfig{PeerLimit: 10, ScorerParams: &scorers.Config{}})
    relay := multiaddrWithPeer(t, remote)

    ensurePeerConnections(context.Background(), h, st, relay)
    ensurePeerConnections(context.Background(), h, st, relay)

    require.Equal(t, int32(2), h.calls, "expected a Connect call on each invocation while no connections exist")
}
go test ./beacon-chain/p2p -run '^TestEnsurePeerConnections_' -count=1 -v
````

### Mitigation

 Add a per-tick cap (e.g., N dials max) and a simple backoff map for failed peers.
Maintain a small “in-flight dials” set for the current tick to avoid parallel duplicates.

### Summary

The `newPublicKey` function in Erigon redundantly checks for the elliptic curve infinity point (0,0) after already delegating the validation to `elliptic.P256().IsOnCurve`.

 Since the `IsOnCurve` function explicitly rejects (0,0), it results in unnecessary code duplication and potential confusion.



### Root Cause

The function `newPublicKey` includes a redundant validation step for (0,0) despite relying on IsOnCurve, which already enforces the same rejection.


https://github.com/erigontech/erigon/blob/a29948de33065144a9378d45b3a161942e8637e7/erigon-lib/crypto/secp256r1/verifier.go#L24-L37

```go
	// Create the public key format
@>	publicKey := newPublicKey(x, y)

	// Check if they are invalid public key coordinates
	if publicKey == nil {
		return false
	}

	// Verify the signature with the public key,
	// then return true if it's valid, false otherwise
	return ecdsa.Verify(publicKey, hash, r, s)
    }
```

https://github.com/erigontech/erigon/blob/a29948de33065144a9378d45b3a161942e8637e7/erigon-lib/crypto/secp256r1/publickey.go#L26-L42

```go
func newPublicKey(x, y *big.Int) *ecdsa.PublicKey {
	// Check if the given coordinates are valid
	if x == nil || y == nil || !elliptic.P256().IsOnCurve(x, y) {
		return nil
	}

	// Check if the given coordinates are the reference point (infinity)
@>	if x.Sign() == 0 && y.Sign() == 0 {   // the validation is redundant.
		return nil
	}

	return &ecdsa.PublicKey{
		Curve: elliptic.P256(),
		X:     x,
		Y:     y,
	}
}
```
**@v0.0.1-go1.24.5.darwin-arm64/src/crypto/elliptic/nistec.go**

```go

func (curve *nistCurve[Point]) IsOnCurve(x, y *big.Int) bool {
	// IsOnCurve is documented to reject (0, 0), the conventional point at
	// infinity, which however is accepted by pointFromAffine.
@>	if x.Sign() == 0 && y.Sign() == 0 {
		return false
	}
	_, err := curve.pointFromAffine(x, y)
	return err == nil
}
```

