    const chain = getMockedBeaconChain({config});
    afterEachCallbacks.push(() => chain.close());

    const slot = 64;
    const blob = generateRandomBlob();
    const kzgCommitment = kzg.blobToKzgCommitment(blob);
    const cellsAndProofs = kzg.computeCellsAndKzgProofs(blob);

    const signedBeaconBlock = ssz.fulu.SignedBeaconBlock.defaultValue();
    signedBeaconBlock.message.slot = slot;
    signedBeaconBlock.message.body.executionPayload.transactions.push(transactionForKzgCommitment(kzgCommitment));
    signedBeaconBlock.message.body.blobKzgCommitments.push(kzgCommitment);

    const columnSidecars = getDataColumnSidecarsFromBlock(config, signedBeaconBlock, [cellsAndProofs]);
    const corruptedSidecar = {
      ...columnSidecars[0],
      kzgProofs: columnSidecars[0].kzgProofs.map((proof) => {
        const mutated = new Uint8Array(proof);
        mutated[0] = mutated[0] ^ 0xff;
        return mutated;
      }),
    };
    // Attack: mutate the gossip sidecar proofs to trip INVALID_KZG_PROOF handling

    const gossipSubnet = computeSubnetForDataColumnSidecar(chain.config, corruptedSidecar);
    const blockRoot = ssz.phase0.BeaconBlockHeader.hashTreeRoot(corruptedSidecar.signedBlockHeader.message);

    chain.clock.currentSlotWithGossipDisparity = slot + 1;
    chain.forkChoice.getFinalizedCheckpoint.mockReturnValue({epoch: 0, root: new Uint8Array(32)});
    chain.forkChoice.getBlockHex.mockReturnValue({slot: slot - 1, stateRoot: new Uint8Array(32)});
    chain.forkChoice.getHead.mockReturnValue({slot: slot - 1, root: blockRoot, stateRoot: new Uint8Array(32)});

    const epochCtx = {
      getBeaconProposer: vi.fn().mockReturnValue(corruptedSidecar.signedBlockHeader.message.proposerIndex),
      index2pubkey: [new Uint8Array(48)],
    };
    const regen = chain.regen as unknown as {
      getBlockSlotState?: ReturnType<typeof vi.fn>;
    };
    regen.getBlockSlotState = vi.fn().mockResolvedValue({slot: slot - 1, config, epochCtx});

    let caught: DataColumnSidecarGossipError | null = null;
    try {
      // Attack: submit the mutated sidecar through the gossip validation path
      await validateGossipDataColumnSidecar(chain, corruptedSidecar, gossipSubnet, null);
    } catch (error) {
      caught = error as DataColumnSidecarGossipError;
    }

    expect(caught).toBeInstanceOf(DataColumnSidecarGossipError);
    expect(caught!.action).toBe(GossipAction.REJECT);
    expect(caught!.type.code).toBe(DataColumnSidecarErrorCode.INVALID_KZG_PROOF);
    expect(caught!.type.slot).toBe(slot);
    expect(caught!.type.columnIdx).toBe(corruptedSidecar.index);

  });
});

```

### Mitigation

- Wrap `kzg.asyncVerifyCellKzgProofBatch` inside `validateDataColumnsSidecars` with a try/catch that converts failures into `DataColumnSidecarError` (mirroring gossip handling) so block verification rejects invalid proofs without crashing.
- Propagate structured failures up through `verifyBlocksDataAvailability` to maintain `DataAvailabilityStatus` semantics and add regression tests ensuring corrupted proofs yield deterministic rejection codes.

### Summary

Erigon PeerDAS implementation has a bug that cause a node to incorrectly compute which data columns peers are responsible for.


### Root Cause

Let's look at the code:

```go
func GetCustodyColumns(nodeID enode.ID, cgc uint64) (map[cltypes.CustodyIndex]bool, error) {
	// TODO: cache the following computations in terms of custody columns
1)	sampleSize := max(clparams.GetBeaconConfig().SamplesPerSlot, cgc)
	groups, err := GetCustodyGroups(nodeID, sampleSize)
	if err != nil {
		return nil, err
	}
	// compute all required custody columns
	custodyColumns := map[cltypes.CustodyIndex]bool{}
	for _, group := range groups {
		columns, err := ComputeColumnsForCustodyGroup(group)
		if err != nil {
			return nil, err
		}
		for _, column := range columns {
			custodyColumns[column] = true
		}
	}
	return custodyColumns, nil
}

```

Notice on line 1 code uses `max(clparams.GetBeaconConfig().SamplesPerSlot, cgc)`.

As a result, code will calculate custody for `max(8,4) = 8` groups for a peer with 4 custody groups.

This function is used in `refreshPeers`:
```go

func (c *columnDataPeers) refreshPeers(ctx context.Context) {
	run := func() {
