		}
		begin := time.Now()
		state := "connected"
		peers, err := c.sentinel.PeersInfo(ctx, &sentinelproto.PeersInfoRequest{
			State: &state,
		})
		if err != nil {
			log.Warn("[peerSelector] failed to get peers info", "err", err)
			return
		}
		var newPeers []peerData
