```

Thus, we have wrong peer selection, plus lack of peer banning. 
As a result, same wrong peers will keep being queried.


### Internal Pre-conditions

None

### External Pre-conditions

None

### Attack Path

Could happen during normal node operations.

### Impact

Nodes will not be able to retrieve missing columns for block validation.

### PoC

1) save the test as cl/das/utils/das_utils_test.go:

```go
package peerdasutils

import (
	"crypto/sha256"
	"encoding/binary"
	"encoding/hex"
	"sort"
	"testing"

	"github.com/erigontech/erigon/p2p/enode"
	"github.com/holiman/uint256"
	"github.com/stretchr/testify/require"
)

func getCustodyGroupsForTest(nodeID enode.ID, custodyGroupCount uint64, numberCustodyGroups uint64) []uint64 {
	currentID := uint256.NewInt(0).SetBytes(nodeID[:])
	custodyGroups := make([]uint64, 0)
	custodyGroupLookup := make(map[uint64]bool)

	for uint64(len(custodyGroups)) < custodyGroupCount {
		idBytes := currentID.Bytes32()
		for i := 0; i < len(idBytes)/2; i++ {
			idBytes[i], idBytes[len(idBytes)-i-1] = idBytes[len(idBytes)-i-1], idBytes[i]
		}
		hash := sha256.Sum256(idBytes[:])
		custodyGroup := binary.LittleEndian.Uint64(hash[:8]) % numberCustodyGroups

		if _, ok := custodyGroupLookup[custodyGroup]; !ok {
			custodyGroups = append(custodyGroups, custodyGroup)
			custodyGroupLookup[custodyGroup] = true
		}
		currentID.Add(currentID, uint256.NewInt(1))
	}

	sort.Slice(custodyGroups, func(i, j int) bool {
		return custodyGroups[i] < custodyGroups[j]
	})

	return custodyGroups
}

func computeColumnsForCustodyGroupForTest(custodyGroup uint64, numberColumns uint64, numberCustodyGroups uint64) []uint64 {
	columnsPerGroup := numberColumns / numberCustodyGroups
	columns := make([]uint64, columnsPerGroup)
	for i := uint64(0); i < columnsPerGroup; i++ {
		columns[i] = numberCustodyGroups*i + custodyGroup
	}
	return columns
}

func getCustodyColumnsForTest(nodeID enode.ID, cgc uint64, samplesPerSlot uint64, numberColumns uint64, numberCustodyGroups uint64) map[uint64]bool {
	sampleSize := max(samplesPerSlot, cgc)
	groups := getCustodyGroupsForTest(nodeID, sampleSize, numberCustodyGroups)

	custodyColumns := map[uint64]bool{}
	for _, group := range groups {
		columns := computeColumnsForCustodyGroupForTest(group, numberColumns, numberCustodyGroups)
		for _, column := range columns {
			custodyColumns[column] = true
		}
	}
	return custodyColumns
}

func TestCGCIssue(t *testing.T) {
	const (
		CUSTODY_REQUIREMENT = 4
		SAMPLES_PER_SLOT = 8
		NUMBER_OF_COLUMNS = 128
		NUMBER_OF_CUSTODY_GROUPS = 128
	)

	nodeIDHex := "0b5e1ea5c6d3f8a9e2d4c7b6a5948372615049382716054938271605493827165555"
	nodeIDBytes, err := hex.DecodeString(nodeIDHex)
	require.NoError(t, err)

	var peerNodeID enode.ID
	copy(peerNodeID[:], nodeIDBytes)

	actualGroups := getCustodyGroupsForTest(peerNodeID, CUSTODY_REQUIREMENT, NUMBER_OF_CUSTODY_GROUPS)
	actualPeerColumns := map[uint64]bool{}
	for _, group := range actualGroups {
		cols := computeColumnsForCustodyGroupForTest(group, NUMBER_OF_COLUMNS, NUMBER_OF_CUSTODY_GROUPS)
		for _, col := range cols {
			actualPeerColumns[col] = true
		}
	}

	t.Logf("Peer advertises CUSTODY_REQUIREMENT = %d", CUSTODY_REQUIREMENT)
	t.Logf("Peer's actual custody groups: %v", actualGroups)

	buggyGroups := getCustodyGroupsForTest(peerNodeID, max(SAMPLES_PER_SLOT, CUSTODY_REQUIREMENT), NUMBER_OF_CUSTODY_GROUPS)
	t.Logf("Code incorrectly calculates custody groups: %v", buggyGroups)
	t.Logf("Extra groups!: %v", buggyGroups[CUSTODY_REQUIREMENT:])


}

```

