            .unwrap()
            .iter()
            .map(kzg_commitment_to_versioned_hash)
            .collect();

        // Swap the EL response order to point each blob/proof pair at the wrong versioned hash.
        let mut swapped_with_indices = blobs_and_proofs.into_iter().enumerate().collect::<Vec<_>>();
        swapped_with_indices.swap(0, 1);

        let mismatch_indices: Vec<_> = swapped_with_indices
            .iter()
