            .into_iter()
            .map(|(_, blob_and_proof)| blob_and_proof)
            .collect();
        mock_get_blobs_v2_response(&mut mock_adapter, Some(swapped));

        mock_fork_choice_contains_block(&mut mock_adapter, vec![]);
        mock_adapter
            .expect_data_column_known_for_proposal()
