### Prysm

```go
// prysm_blob_schedule_poc.go
package main

import (
    "encoding/json"
    "fmt"
    "strings"
)

// blobScheduleEntry mirrors Prysm's params.BlobScheduleEntry struct, which only expects
// EPOCH and MAX_BLOBS_PER_BLOCK fields (both as strings in the YAML/JSON).
type blobScheduleEntry struct {
    Epoch           string `json:"EPOCH"`
    MaxBlobsPerBlock string `json:"MAX_BLOBS_PER_BLOCK"`
}

// beaconConfig is the minimal portion of Prysm's BeaconChainConfig that includes
// the blob schedule slice.
type beaconConfig struct {
    BlobSchedule []blobScheduleEntry `json:"BLOB_SCHEDULE"`
}

func tryDecode(label, payload string) {
    dec := json.NewDecoder(strings.NewReader(payload))
    dec.DisallowUnknownFields() // matches yaml.UnmarshalStrict behaviour

    var cfg beaconConfig
    err := dec.Decode(&cfg)
    if err != nil {
        fmt.Printf("[%s] failed: %v\n", label, err)
        return
    }
    fmt.Printf("[%s] succeeded: %#v\n", label, cfg)
}

func main() {
    // Legacy schedule accepted by Prysm today.
    legacy := `{
        "BLOB_SCHEDULE": [
            {"EPOCH": "1024", "MAX_BLOBS_PER_BLOCK": "18"}
        ]
    }`

    // Spec-compliant Fusaka schedule entry including TARGET_BLOBS_PER_BLOCK and
    // BASE_FEE_UPDATE_FRACTION per EIP-7892.
    fusaka := `{
        "BLOB_SCHEDULE": [
            {
                "EPOCH": "1024",
                "MAX_BLOBS_PER_BLOCK": "18",
                "TARGET_BLOBS_PER_BLOCK": "12",
                "BASE_FEE_UPDATE_FRACTION": "5007716"
            }
        ]
    }`

    tryDecode("legacy", legacy)
    tryDecode("fusaka", fusaka)
}
```

