/*
 * VULNERABILITY DESCRIPTION:
 * FULU-DISTRIBUTED-BLOB-PUBLISHING exception-handling vulnerability. The DBP path wraps any
 * Throwable thrown during constructDataColumnSidecars() in a RuntimeException, but the async
 * runner treats that as an internal failure and absorbs it. As a result the node silently drops the
 * data column publication without triggering error handling, metrics, or retries.
 *
 * LOCATION:
 * ethereum/statetransition/src/main/java/tech/pegasys/teku/statetransition/datacolumns/util/DataColumnSidecarELRecoveryManagerImpl.java:248
 *
 * TEST STATUS: pass_when_exploitable
 * BUILD STATUS: passed
 */
public class PocFuluDistributedBlobPublishingExceptionHandlingTest {

  private final Spec spec = TestSpecFactory.createMinimalFulu();
  private final DataStructureUtil dataStructureUtil = new DataStructureUtil(spec);
  private final StubAsyncRunner asyncRunner = new StubAsyncRunner();
  private final RecentChainData recentChainData = mock(RecentChainData.class);
  private final ExecutionLayerChannel executionLayer = mock(ExecutionLayerChannel.class);
  private final KZG kzg = mock(KZG.class);
  private final List<KZGCell> kzgCells =
      IntStream.range(0, 128).mapToObj(__ -> new KZGCell(Bytes.random(2048))).toList();
  private final CustodyGroupCountManager custodyGroupCountManager =
      createCustodyGroupCountManager(4, 8);
  private final Supplier<CustodyGroupCountManager> custodyGroupCountManagerSupplier =
      () -> custodyGroupCountManager;
  @SuppressWarnings("unchecked")
  private final Consumer<List<DataColumnSidecar>> dataColumnSidecarPublisher = mock(Consumer.class);
  private final TimeProvider timeProvider = StubTimeProvider.withTimeInMillis(ZERO);

  private final DataColumnSidecarELRecoveryManagerImpl dataColumnSidecarELRecoveryManager =
      new DataColumnSidecarELRecoveryManagerImpl(
          spec,
          asyncRunner,
          recentChainData,
          executionLayer,
          UInt64.valueOf(320),
          FutureItems.DEFAULT_FUTURE_SLOT_TOLERANCE,
          10,
          kzg,
          dataColumnSidecarPublisher,
          custodyGroupCountManagerSupplier,
          new StubMetricsSystem(),
          timeProvider,
          Duration.ofMillis(500),
          3);

  private UInt64 currentSlot = UInt64.valueOf(10);

  @BeforeEach
  void setup() {
    when(kzg.computeCells(any())).thenReturn(kzgCells);
    when(recentChainData.computeTimeAtSlot(any())).thenReturn(UInt64.ZERO);
    when(recentChainData.containsBlock(any())).thenReturn(false);
    setSlot(currentSlot);
  }

  private void setSlot(final UInt64 slot) {
    currentSlot = slot;
    dataColumnSidecarELRecoveryManager.onSlot(slot);
  }

  @Test
  @SuppressWarnings("unchecked")
  public void poc_fulu_distributed_blob_publishing_exception_handling() {
    reset(executionLayer, dataColumnSidecarPublisher, recentChainData, kzg);

    when(recentChainData.computeTimeAtSlot(any())).thenReturn(UInt64.ZERO);
    when(recentChainData.containsBlock(any())).thenReturn(false);
    // Attack scenario: by serving malformed blob data, an
    // attacker causes the KZG library to throw during constructDataColumnSidecars().
    when(kzg.computeCells(any()))
        .thenThrow(new IllegalArgumentException("Malformed KZG data"));

    // Attack step: schedule recovery so that the poisoned blobs will be processed synchronously.
    dataColumnSidecarELRecoveryManager.onSlot(currentSlot);

    final SignedBeaconBlock block = dataStructureUtil.randomSignedBeaconBlock(currentSlot.longValue());
    final List<BlobSidecar> blobSidecars = dataStructureUtil.randomBlobSidecarsForBlock(block);
    final List<BlobAndCellProofs> blobAndCellProofs =
        blobSidecars.stream()
            .map(
                blobSidecar ->
                    new BlobAndCellProofs(
                        blobSidecar.getBlob(),
                        IntStream.range(0, 128)
                            .mapToObj(__ -> dataStructureUtil.randomKZGProof())
                            .toList()))
            .toList();

    // Attack step: enqueue the malicious block through DBP so the vulnerable code path executes.
    dataColumnSidecarELRecoveryManager.onNewBlock(block, Optional.empty());

    final List<VersionedHash> versionedHashes = getVersionedHashesFromBlock(block);
    // Attack step: EL returns data that forces the mocked KZG layer to error out during processing.
    when(executionLayer.engineGetBlobAndCellProofsList(versionedHashes, currentSlot))
        .thenReturn(SafeFuture.completedFuture(blobAndCellProofs));

    // Attack scenario step: the catch(Throwable) clause wraps the KZG failure in RuntimeException,
    // which is treated as an internal failure by the async runner and never surfaces to callers.

    assertThatCode(asyncRunner::executeQueuedActions)
        .doesNotThrowAnyException();

    // Verify that the KZG computeCells method was called with malformed data
    // This proves the vulnerability was triggered (KZG called with bad data)
    verify(kzg, atLeastOnce()).computeCells(any());

    verify(executionLayer, atLeastOnce()).engineGetBlobAndCellProofsList(versionedHashes, currentSlot);
    // The failure suppresses downstream publication, so no sidecars ever reach the publisher.
    verify(dataColumnSidecarPublisher, never()).accept(any());

    // No runtime exception ever reaches this test, so the failure remains opaque to callers.
  }

  private List<VersionedHash> getVersionedHashesFromBlock(final SignedBeaconBlock block) {
    final SlotAndBlockRoot slotAndBlockRoot = block.getSlotAndBlockRoot();
    final DataColumnSidecarELRecoveryManagerImpl.RecoveryTask recoveryTask =
        dataColumnSidecarELRecoveryManager.getRecoveryTask(slotAndBlockRoot);

    if (recoveryTask == null) {
      throw new IllegalStateException("No recovery task found for block");
    }

    final SszList<SszKZGCommitment> sszKZGCommitments = recoveryTask.sszKZGCommitments();
    final List<BlobIdentifier> blobIdentifiers =
        IntStream.range(0, sszKZGCommitments.size())
            .mapToObj(
                index -> new BlobIdentifier(slotAndBlockRoot.getBlockRoot(), UInt64.valueOf(index)))
            .toList();

    final SpecVersion specVersion = spec.atSlot(slotAndBlockRoot.getSlot());
    final MiscHelpersDeneb miscHelpersDeneb =
        specVersion.miscHelpers().toVersionDeneb().orElseThrow();

    return blobIdentifiers.stream()
        .map(
            blobIdentifier ->
                miscHelpersDeneb.kzgCommitmentToVersionedHash(
                    sszKZGCommitments.get(blobIdentifier.getIndex().intValue()).getKZGCommitment()))
        .toList();
  }
}
```

### Mitigation

- Replace the broad `catch(Throwable)` with explicit handling that distinguishes between KZG failures, count mismatches, and batch-verification faults.
- Make the failures observable via structured logging and metrics, and define a retry policy (exponential backoff, quarantine the EL endpoint after repeated faults).
- Apply gossip-equivalent validation—recompute versioned hashes and run KZG checks—before publishing DBP-derived sidecars.

### Summary

Missing null and exception handling after `recoverCellsAndProofs` in `MiscHelpersFulu.recoverMatrix` could let malformed data column sidecars surface unhandled exceptions in the reconstruction flow, creating a resilience gap if a malicious custody peer can drive the path via gossip or other inputs.


### Root Cause

In `ethereum/spec/src/main/java/tech/pegasys/teku/spec/logic/versions/fulu/helpers/MiscHelpersFulu.java`, function `recoverMatrix`, the code assumes `kzg.recoverCellsAndProofs(cellWithColumnIds)` always returns a populated list and never throws. The method immediately iterates over the result (`kzgCellAndProofs.size()` and `.get(index)`) without checking for `null`, empty results, or catching `KZGException`, so malformed sidecars from gossip can trigger a `NullPointerException` or an uncaught runtime from the native layer.


### Internal Pre-conditions

1. [Teku node gathers partial columns for reconstruction] `MiscHelpersFulu.reconstructAllDataColumnSidecars` is invoked with at least `NUMBER_OF_COLUMNS / 2` sidecars so the code attempts to rebuild the missing matrix entries.
2. [Reconstruction path runs on gossip validation] `DataColumnSidecarGossipValidator` accepts the attacker-supplied sidecars far enough to call `recoverMatrix`, forwarding the untrusted cells and proofs into the native KZG binding.

### External Pre-conditions

1. [Malicious custody subnet peer controls payloads] The attacker can gossip `DataColumnSidecar` objects with mismatched cells or proofs that violate the KZG commitments.
2. [KZG binding signals failure through null/exception] The native `recoverCellsAndProofs` implementation returns `null` or throws when given the malformed payload, matching its documented failure behaviour.

### Attack Path

1. A malicious custody peer withholds some columns for a block while gossiping ≥50% malformed `DataColumnSidecar`s so Teku schedules matrix reconstruction (assumes gossip validation can be bypassed or satisfied).
2. Teku sorts the incoming sidecars and calls `recoverMatrix`, building `cellWithColumnIds` from the attacker-controlled data once the validator path accepts the payloads.
3. `kzg.recoverCellsAndProofs` receives the malformed cells and either returns `null` or throws (e.g., `KZGException`).
4. Teku immediately dereferences the result inside the parallel stream, triggering a `NullPointerException` or propagating the unchecked exception, which currently propagates beyond the reconstruction helper and may interrupt validator duties.

### Impact

Unhandled exceptions in this path may abort the data-availability reconstruction task, risking temporary loss of sampling progress or broader availability if the exception escapes task boundaries. Severity: Informational (robustness gap; end-to-end reachability and process crash still unproven).


### PoC

Run with `./gradlew :ethereum:spec:test --tests tech.pegasys.teku.spec.logic.versions.fulu.helpers.PocTekuFuluPeerdasDos001Test`

File path: `ethereum/spec/src/test/java/tech/pegasys/teku/spec/logic/versions/fulu/helpers/PocTekuFuluPeerdasDos001Test.java`

