/*
 * VULNERABILITY DESCRIPTION:
 * FULU-PEERDAS-SAMPLING: confirmed DoS vulnerability similar to Nimbus
 * recovery-panic bug. Implementation assumes recoverCellsAndProofs() never returns null and
 * that the native layer never throws, so malformed data can trigger NullPointerException or
 * uncaught runtime exceptions and crash the node.
 *
 * LOCATION:
 * ethereum/spec/src/main/java/tech/pegasys/teku/spec/logic/versions/fulu/helpers/MiscHelpersFulu.java — `MiscHelpersFulu.recoverMatrix`
 *
 * PROOF TRACE:
 * DataColumnSidecarTopicHandler.handleIncomingMessage
 * ↳ DataColumnSidecarGossipValidator.validate
 * ↳ MiscHelpersFulu.reconstructAllDataColumnSidecars
 * ↳ MiscHelpersFulu.recoverMatrix
 * ↳ KZG.recoverCellsAndProofs → crash
 *
 * TEST STATUS: pass_when_exploitable
 * BUILD STATUS: passed
 */

package tech.pegasys.teku.spec.logic.versions.fulu.helpers;

import static org.assertj.core.api.Assertions.assertThatThrownBy;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.util.List;
import java.util.stream.IntStream;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import tech.pegasys.teku.infrastructure.unsigned.UInt64;
import tech.pegasys.teku.kzg.KZG;
import tech.pegasys.teku.kzg.KZGException;
import tech.pegasys.teku.spec.Spec;
import tech.pegasys.teku.spec.TestSpecFactory;
import tech.pegasys.teku.spec.config.SpecConfigFulu;
import tech.pegasys.teku.spec.datastructures.blobs.versions.fulu.DataColumnSidecar;
import tech.pegasys.teku.spec.datastructures.blocks.SignedBeaconBlock;
import tech.pegasys.teku.spec.logic.versions.electra.helpers.PredicatesElectra;
import tech.pegasys.teku.spec.schemas.SchemaDefinitionsFulu;
import tech.pegasys.teku.spec.util.DataStructureUtil;

public class PocTekuFuluPeerdasDos001Test {

  private final Spec spec = TestSpecFactory.createMinimalFulu();
  private final SpecConfigFulu specConfig = SpecConfigFulu.required(spec.getGenesisSpecConfig());
  private final PredicatesElectra predicates = new PredicatesElectra(spec.getGenesisSpecConfig());
  private final SchemaDefinitionsFulu schemaDefinitionsFulu =
      SchemaDefinitionsFulu.required(spec.getGenesisSchemaDefinitions());
  private MiscHelpersFulu miscHelpersFulu;

  @BeforeEach
  void setup() {
    miscHelpersFulu = new MiscHelpersFulu(specConfig, predicates, schemaDefinitionsFulu);
  }

  @Test
  public void poc_fulu_peerdas_sampling_null_recovery_crashes_node() {
    final List<DataColumnSidecar> malformedSidecars = createMinimalSidecars();
    final KZG mockKzg = mock(KZG.class);
    when(mockKzg.recoverCellsAndProofs(any())).thenReturn(null);

    assertThatThrownBy(
            () -> miscHelpersFulu.reconstructAllDataColumnSidecars(malformedSidecars, mockKzg))
        .as("Null recovery list should crash due to unchecked access")
        .isInstanceOf(NullPointerException.class);
  }

  @Test
  public void poc_fulu_peerdas_sampling_recovery_exception_crashes_node() {
    final List<DataColumnSidecar> malformedSidecars = createMinimalSidecars();
    final KZG mockKzg = mock(KZG.class);
    final KZGException kzgException = new KZGException("recovery failure");
    when(mockKzg.recoverCellsAndProofs(any())).thenThrow(kzgException);

    assertThatThrownBy(
            () -> miscHelpersFulu.reconstructAllDataColumnSidecars(malformedSidecars, mockKzg))
        .as("KZG recovery exception should bubble out and crash the node")
        .isInstanceOf(KZGException.class)
        .isSameAs(kzgException);
  }

  private List<DataColumnSidecar> createMinimalSidecars() {
    final DataStructureUtil dataStructureUtil = new DataStructureUtil(spec);
    final int numberOfColumns = specConfig.getNumberOfColumns();
    final int minRequiredSidecars = numberOfColumns / 2;
    final SignedBeaconBlock sharedBlock =
        dataStructureUtil.randomSignedBeaconBlockWithCommitments(5);

    return IntStream.range(0, minRequiredSidecars)
        .mapToObj(
            i ->
                dataStructureUtil.randomDataColumnSidecarWithInclusionProof(
                    sharedBlock, UInt64.valueOf(i)))
        .toList();
  }
}
```

### Mitigation

Validate the return value from `kzg.recoverCellsAndProofs` before iterating (null/size checks), wrap the call in a try/catch for `KZGException`, and treat any failure as invalid gossip so the node rejects the message, penalises the peer, and continues without crashing.

## Summary
The specification requires `get_custody_groups()` to return a sorted `Sequence[CustodyIndex]`, but the Lighthouse implementation does not sort the custody groups in the main function (`get_custody_groups()`). Instead:

1. The helper function (`get_custody_groups_ordered()`) preserves computation order (the order in which groups were generated).
2. The main function converts the result into a `HashSet`, which is unordered.

This discrepancy could lead to inconsistent behavior between different implementations, even if the custody groups themselves are correct.

## Details
The spec explicitly states:
https://github.com/ethereum/consensus-specs/blob/8e0d0d48e81d6c7c5a8253ab61340f5ea5bac66a/specs/fulu/das-core.md#get_custody_groups
```python
return sorted(custody_groups)
```
This ensures that all implementations return custody groups in the same order, regardless of how they were computed.

The implementation of `get_custody_groups()` in Lighthouse:
https://github.com/sigp/lighthouse/blob/unstable/consensus/types/src/data_column_custody_group.rs#L16-L33
```rust
pub fn get_custody_groups(
    raw_node_id: [u8; 32],
    custody_group_count: u64,
    spec: &ChainSpec,
) -> Result<HashSet<CustodyIndex>, DataColumnCustodyGroupError> {
    if custody_group_count == spec.number_of_custody_groups {
        Ok(HashSet::from_iter(0..spec.number_of_custody_groups))
    } else {
        get_custody_groups_ordered(raw_node_id, custody_group_count, spec)
            .map(|custody_groups| custody_groups.into_iter().collect())
    }
}
```
It converts the ordered list into a `HashSet`, losing all ordering. If the result is later converted back to a list (e.g., for serialization), the order may vary across implementations.

## POC
```rust
#[cfg(test)]
mod tests {
    use super::*;
    use std::collections::HashSet;

    #[test]
    fn test_vec_to_hashset_order_not_preserved() {
        // Step 1: Create an ordered vector with predictable sequence
        let ordered_vec = vec![0, 1, 2, 3, 4];

        // Step 2: Convert the vector to HashSet (which doesn't preserve order)
        let hashset: HashSet<_> = ordered_vec.clone().into_iter().collect();

        // Step 3: Convert HashSet back to Vec to observe the order
        let vec_from_hashset: Vec<_> = hashset.into_iter().collect();

        // Assertion 1: Verify the order is different (HashSet is unordered)
        // Note: This might theoretically fail if HashSet coincidentally maintains order,
        // but in practice it's extremely unlikely for nontrivial cases
        assert_ne!(
            ordered_vec, vec_from_hashset,
            "HashSet conversion should not preserve the original vector's order"
        );

        // Assertion 2: Verify the content remains identical (just order changes)
        let expected_set: HashSet<_> = ordered_vec.into_iter().collect();
        let result_set: HashSet<_> = vec_from_hashset.into_iter().collect();
        assert_eq!(
            expected_set, result_set,
            "HashSet conversion should preserve all elements despite order change"
        );
    }
}
```
The result:
```rust
running 1 test
test tests::test_vec_to_hashset_order_not_preserved ... ok

test result: ok. 1 passed; 0 failed; 0 ignored; 0 measured; 0 filtered out; finished in 0.00s
```

## Impact
1. Interoperability Risk: If other clients follow the spec strictly (returning sorted lists), but Lighthouse returns an unordered `HashSet`, systems that rely on deterministic ordering (e.g., for proofs, signatures, or Merkle tree construction) may behave differently.
2. Testing & Debugging Difficulty: If two implementations compute the same custody groups but return them in different orders, test comparisons may fail even if the underlying logic is correct.
3. Potential Consensus Issues: If sorting is required for some protocol logic (e.g., attestation ordering), Lighthouse’s unsorted output could cause unexpected behavior.

## Recommendation
Consider using `BTreeSet` instead of `HashSet`.

## Summary
**Go loop variable capture in broadcastAndReceiveBlobs will cause network propagation failures for blob sidecars as concurrent goroutines will broadcast with incorrect indices and data**

## Root Cause
In proposer.go the goroutines in `broadcastAndReceiveBlobs` and `broadcastAndReceiveDataColumns` capture for-range loop variables by reference instead of value, causing race conditions where goroutines use incorrect indices and data when broadcasting

```go
// In broadcastAndReceiveBlobs
for subIdx, sc := range sidecars {
    eg.Go(func() error {
        if err := vs.P2P.BroadcastBlob(eCtx, uint64(subIdx), sc); err != nil { // ISSUE: subIdx and sc are from outer scope
            // ...
```

## Internal Pre-conditions
1. The `broadcastAndReceiveBlobs` function needs to be called with multiple sidecars
2. Normal execution timing where goroutines execute after loop completes (virtually guaranteed in production)

## External Pre-conditions
1. None - this is a purely internal logic bug that will manifest under normal conditions

## Attack Path
1. **User/validator submits a block with multiple blob sidecars**
2. **broadcastAndReceiveBlobs is called with these sidecars**
3. **For-loop creates goroutines for each sidecar without copying loop variables**
4. **The loop completes, with subIdx=len(sidecars)-1 and sc=sidecars[len(sidecars)-1]**
5. **Goroutines execute with these final values**
6. **All goroutines broadcast the last sidecar to the last subnet index**
7. **Peers reject malformed/incorrect broadcasts**

## Impact
The consensus layer network suffers from incomplete blob sidecar propagation. Peers will reject incorrectly indexed blobs, leading to consensus failures on blob availability. In the worst case, all but the last blob could be completely dropped from the network, breaking blob availability sampling and potentially causing validators to miss attestations.

## PoC
```go
package main

import (
	"fmt"
	"sync"
	"time"
)

// Simulates P2P behavior to demonstrate the bug
type FakeP2P struct {
	mu      sync.Mutex
	records []string
}

func (p *FakeP2P) BroadcastBlob(index uint64, data string) {
	p.mu.Lock()
	defer p.mu.Unlock()
	p.records = append(p.records, fmt.Sprintf("%d:%s", index, data))
}

func buggyBroadcast(p2p *FakeP2P, blobs []string) {
	var wg sync.WaitGroup
	wg.Add(len(blobs))

	for idx, blob := range blobs {
		go func() {
			defer wg.Done()
			// Simulate processing time
			time.Sleep(10 * time.Millisecond)
			// BUG: Using idx and blob from loop scope
			p2p.BroadcastBlob(uint64(idx), blob)
		}()
	}
	wg.Wait()
}

func fixedBroadcast(p2p *FakeP2P, blobs []string) {
	var wg sync.WaitGroup
	wg.Add(len(blobs))

	for idx, blob := range blobs {
		// FIX: Copy loop variables
		idx := idx
		blob := blob
		go func() {
			defer wg.Done()
			time.Sleep(10 * time.Millisecond)
			p2p.BroadcastBlob(uint64(idx), blob)
		}()
	}
	wg.Wait()
}

func main() {
	blobs := []string{"BlobA", "BlobB", "BlobC"}

	buggyP2P := &FakeP2P{}
	buggyBroadcast(buggyP2P, blobs)
	fmt.Println("Buggy broadcasts:")
	for _, r := range buggyP2P.records {
		fmt.Println(r)
	}

	fixedP2P := &FakeP2P{}
	fixedBroadcast(fixedP2P, blobs)
	fmt.Println("\nFixed broadcasts:")
	for _, r := range fixedP2P.records {
		fmt.Println(r)
	}
}
```

## Mitigation
Copy loop variables before launching goroutines:

```go
for subIdx, sc := range sidecars {
    subIdx := subIdx // Create local copy for goroutine
    sc := sc         // Create local copy for goroutine

    eg.Go(func() error {
        if err := vs.P2P.BroadcastBlob(eCtx, uint64(subIdx), sc); err != nil {
            return errors.Wrap(err, "broadcast blob failed")
        }
        // ...
    })
}
```

Similarly fix `broadcastAndReceiveDataColumns` for the `roSidecar` loop variable.

### Summary

parseTransaction skipping ValidateTxBasics during restart will cause a persistent Osaka blob queue freeze for execution client operators as a pre-Osaka blob sender will resurrect disk-persisted Osaka-incompatible blobs that block all later valid transactions for that account.

### Root Cause

In core/txpool/blobpool/blobpool.go::parseTransaction the restart callback appends disk-resurrected blob transactions directly into `p.index` without routing them through `ValidateTxBasics`, so Osaka gas-cap and blob version checks mandated by the execution-specs Osaka transaction validation procedure step 3 (https://github.com/ethereum/execution-specs/blob/5ddb904fa7ba27daeff423e78466744c51e8cb6a/src/ethereum/forks/osaka/transactions.py) are skipped after a reboot, leaving an invalid head element that permanently blocks the sender queue.

```go
// core/txpool/blobpool/blobpool.go :: parseTransaction
if _, ok := p.index[sender]; !ok {
	if err := p.reserver.Hold(sender); err != nil {
		return err
	}
	p.index[sender] = []*blobTxMeta{}
	p.spent[sender] = new(uint256.Int)
}
// restart path never calls ValidateTxBasics before queueing the entry
p.index[sender] = append(p.index[sender], meta)
p.spent[sender] = new(uint256.Int).Add(p.spent[sender], meta.costCap)
```


### Internal Pre-conditions

1. [Execution client operator accepts attacker-controlled blob] The blob pool must persist a transaction for the attacker's address whose `Gas` exceeds `params.MaxTxGas` or whose sidecar remains at `BlobSidecarVersion0` before Osaka rules activate.
2. [Node operator restarts after Osaka grace expires] The local chain clock must advance beyond `OsakaTime + conversionTimeWindow`, making the persisted entry incompatible with OSK-TX-VALIDATION procedure step 3.

### External Pre-conditions

1. [Ethereum mainnet fork schedule reaches Osaka] The network must enable Osaka so TX_MAX_GAS_LIMIT = 2**24 and blob version-1 enforcement are in effect per https://github.com/ethereum/execution-specs/blob/5ddb904fa7ba27daeff423e78466744c51e8cb6a/src/ethereum/forks/osaka/transactions.py.


### Attack Path

1. Attacker (controlling their own sender address) submits Osaka-incompatible blob transactions before the fork, ensuring the node stores the entries on disk.
2. After Osaka activation, the node restarts; `parseTransaction` rehydrates the persisted entry without `ValidateTxBasics`, leaving an invalid head element in the sender queue.
3. The attacker (or legitimate operator using the same key) broadcasts a valid Osaka-compliant blob transaction, but `Pending` and miner intake stop at the invalid head, so no subsequent transaction from that account becomes visible until the disk queue is purged manually.

### Impact

The execution client operator cannot propagate or include any otherwise valid Osaka blob transactions for the affected account; the queue stays frozen across restarts until disk entries are manually purged.


### PoC

Path: `core/txpool/blobpool/poc_parsetransaction_restart_path_skips_validatetxbasics_so_legacy_v0_or_over_gas_blobs_survive_osaka_boot_and_freeze_the_account_queue_until_operators_purge_the_disk_entries_test.go`

```go
package blobpool

import (
	"errors"
	"os"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/ethereum/go-ethereum/core"
	"github.com/ethereum/go-ethereum/core/state"
	"github.com/ethereum/go-ethereum/core/tracing"
	"github.com/ethereum/go-ethereum/core/txpool"
	"github.com/ethereum/go-ethereum/core/types"
	"github.com/ethereum/go-ethereum/crypto"
	"github.com/ethereum/go-ethereum/params"
	"github.com/ethereum/go-ethereum/rlp"
	"github.com/holiman/billy"
	"github.com/holiman/uint256"
)

func TestPocParsetransactionRestartPathSkipsValidatetxbasicsSoLegacyV0OrOverGasBlobsSurviveOsakaBootAndFreezeTheAccountQueueUntilOperatorsPurgeTheDiskEntries(t *testing.T) {
	storage := t.TempDir()

	scenarios := []struct {
		name         string
		mutateTx     func(unsigned *types.BlobTx) error
		expectAddErr func(error) bool
		assertMeta   func(t *testing.T, meta *blobTxMeta)
	}{
		{
			name: "gas_cap_breach",
			mutateTx: func(unsigned *types.BlobTx) error {
				if err := unsigned.Sidecar.ToV1(); err != nil {
					return err
				}
				unsigned.Gas = params.MaxTxGas + 1
				return nil
			},
			expectAddErr: func(err error) bool {
				return errors.Is(err, core.ErrGasLimitTooHigh)
			},
			assertMeta: func(t *testing.T, meta *blobTxMeta) {
				if meta.execGas <= params.MaxTxGas {
					t.Fatalf("expected exec gas to exceed cap, got %d", meta.execGas)
				}
			},
		},
		{
			name: "legacy_sidecar_v0",
			mutateTx: func(unsigned *types.BlobTx) error {
				unsigned.Gas = 21000
				return nil
			},
			expectAddErr: func(err error) bool {
				return err != nil && strings.Contains(err.Error(), "legacy blob tx is not supported")
			},
			assertMeta: func(t *testing.T, meta *blobTxMeta) {
				if meta.version != types.BlobSidecarVersion0 {
					t.Fatalf("expected legacy sidecar to survive, got version %d", meta.version)
				}
			},
		},
	}

	for _, tc := range scenarios {
		t.Run(tc.name, func(t *testing.T) {
			datadir := filepath.Join(storage, tc.name)
			queuedir := filepath.Join(datadir, pendingTransactionStore)

			key, err := crypto.GenerateKey()
			if err != nil {
				t.Fatalf("failed to create key: %v", err)
			}
			addr := crypto.PubkeyToAddress(key.PublicKey)

			unsigned := makeUnsignedTxWithTestBlob(0, 1, 1, 1, 0)
			if err := tc.mutateTx(unsigned); err != nil {
				t.Fatalf("failed to mutate tx for scenario %s: %v", tc.name, err)
			}

			signer := types.LatestSigner(params.MainnetChainConfig)
			signed := types.MustSignNewTx(key, signer, unsigned)

			makeState := func() *state.StateDB {
				statedb, err := state.New(types.EmptyRootHash, state.NewDatabaseForTesting())
				if err != nil {
					t.Fatalf("failed to create state: %v", err)
				}
				statedb.AddBalance(addr, uint256.NewInt(1_000_000_000), tracing.BalanceChangeUnspecified)
				if _, err := statedb.Commit(0, true, false); err != nil {
					t.Fatalf("failed to commit state: %v", err)
				}
				return statedb
			}

			makeChain := func(statedb *state.StateDB) *testBlockChain {
				cfg := *params.MainnetChainConfig
				zero := uint64(0)
				cfg.CancunTime = &zero
				cfg.OsakaTime = &zero

				chain := &testBlockChain{
					config:  &cfg,
					basefee: uint256.NewInt(params.InitialBaseFee),
					blobfee: uint256.NewInt(params.BlobTxMinBlobGasprice),
					statedb: statedb,
				}
				deadlineSeconds := uint64(time.Duration(conversionTimeWindow).Seconds())
				// Move past the Osaka conversion deadline so v0 blobs are permanently invalid.
				chain.setHeadTime(*cfg.OsakaTime + deadlineSeconds + 1)
				return chain
			}

			// Control: the live admission path must reject the invalid payload.
			if err := os.MkdirAll(queuedir, 0o700); err != nil {
				t.Fatalf("failed to create queue dir: %v", err)
			}
			controlPool := New(Config{Datadir: datadir}, makeChain(makeState()), nil)
			if err := controlPool.Init(1, controlPool.chain.CurrentBlock(), newReserver()); err != nil {
				t.Fatalf("failed to init control pool: %v", err)
			}
			if errs := controlPool.Add([]*types.Transaction{signed}, true); len(errs) != 1 || !tc.expectAddErr(errs[0]) {
				t.Fatalf("expected Add() to reject invalid tx, got %v", errs)
			}
			if err := controlPool.Close(); err != nil {
				t.Fatalf("failed to close control pool: %v", err)
			}

			// Reset the datadir to simulate a cold restart with only the persisted blob.
			if err := os.RemoveAll(datadir); err != nil {
				t.Fatalf("failed to reset datadir: %v", err)
			}
			if err := os.MkdirAll(queuedir, 0o700); err != nil {
				t.Fatalf("failed to recreate queue dir: %v", err)
			}

			// Persist the invalid transaction directly to disk, bypassing validation.
			store, err := billy.Open(billy.Options{Path: queuedir}, newSlotter(testMaxBlobsPerBlock), nil)
			if err != nil {
				t.Fatalf("failed to open blob store: %v", err)
			}
			encoded, err := rlp.EncodeToBytes(signed)
			if err != nil {
				t.Fatalf("failed to encode tx: %v", err)
			}
			if _, err := store.Put(encoded); err != nil {
				t.Fatalf("failed to persist tx: %v", err)
			}
			if err := store.Close(); err != nil {
				t.Fatalf("failed to close blob store: %v", err)
			}

			// Rehydrate the pool and confirm the invalid entry survives.
			rehydratePool := New(Config{Datadir: datadir}, makeChain(makeState()), nil)
			if err := rehydratePool.Init(1, rehydratePool.chain.CurrentBlock(), newReserver()); err != nil {
				t.Fatalf("failed to rehydrate blob pool: %v", err)
			}

			entries := rehydratePool.index[addr]
			if len(entries) == 0 {
				t.Fatalf("expected resurrected entry for %v; bug appears fixed", addr)
			}
			tc.assertMeta(t, entries[0])

			// Tail injection: add a valid Osaka-era blob transaction behind the resurrected head.
			tailUnsigned := makeUnsignedTxWithTestBlob(1, 1, 1, 1, 0)
			if err := tailUnsigned.Sidecar.ToV1(); err != nil {
				t.Fatalf("failed to upgrade tail sidecar to v1: %v", err)
			}
			tailUnsigned.Gas = params.MaxTxGas
			tail := types.MustSignNewTx(key, signer, tailUnsigned)

			headUnsigned := makeUnsignedTxWithTestBlob(0, 1, 1, 1, 0)
			if err := headUnsigned.Sidecar.ToV1(); err != nil {
				t.Fatalf("failed to upgrade replacement head sidecar to v1: %v", err)
			}
			headUnsigned.Gas = params.MaxTxGas
			headReplacement := types.MustSignNewTx(key, signer, headUnsigned)

			errList := rehydratePool.Add([]*types.Transaction{tail}, true)
			if len(errList) != 1 || errList[0] != nil {
				t.Fatalf("expected Add() to accept tail tx, got %v", errList)
			}
			entries = rehydratePool.index[addr]
			if len(entries) != 2 {
				t.Fatalf("expected tail tx to queue behind resurrected head, got %d entries", len(entries))
			}
			if entries[1].nonce != 1 {
				t.Fatalf("expected tail nonce 1, got %d", entries[1].nonce)
			}

			pending := rehydratePool.Pending(txpool.PendingFilter{
				BlobTxs:     true,
				BlobVersion: types.BlobSidecarVersion1,
				GasLimitCap: params.MaxTxGas,
			})
			if _, ok := pending[addr]; ok {
				t.Fatalf("expected invalid head to block tail v1 tx exposure for %v", addr)
			}

			if err := rehydratePool.Close(); err != nil {
				t.Fatalf("failed to close rehydrate pool: %v", err)
			}

			// Simulate operator purge: clear persisted blobs and ensure the queue recovers.
			if err := os.RemoveAll(datadir); err != nil {
				t.Fatalf("failed to purge datadir: %v", err)
			}
			if err := os.MkdirAll(queuedir, 0o700); err != nil {
				t.Fatalf("failed to recreate queue dir after purge: %v", err)
			}

			recoveredPool := New(Config{Datadir: datadir}, makeChain(makeState()), nil)
			if err := recoveredPool.Init(1, recoveredPool.chain.CurrentBlock(), newReserver()); err != nil {
				t.Fatalf("failed to init recovered pool: %v", err)
			}
			if liveEntries := recoveredPool.index[addr]; len(liveEntries) != 0 {
				t.Fatalf("expected queue to clear after purge, still have %d entries", len(liveEntries))
			}

			errList = recoveredPool.Add([]*types.Transaction{headReplacement}, true)
			if len(errList) != 1 || errList[0] != nil {
				t.Fatalf("expected Add() to accept replacement head after purge, got %v", errList)
			}
			errList = recoveredPool.Add([]*types.Transaction{tail}, true)
			if len(errList) != 1 || errList[0] != nil {
				t.Fatalf("expected Add() to accept tail tx after purge, got %v", errList)
			}
			pending = recoveredPool.Pending(txpool.PendingFilter{
				BlobTxs:     true,
				BlobVersion: types.BlobSidecarVersion1,
				GasLimitCap: params.MaxTxGas,
			})
			lazies, ok := pending[addr]
			if !ok || len(lazies) == 0 {
				t.Fatalf("expected pending txs once invalid head is purged for %v", addr)
			}
			var tailFound bool
			for _, lazy := range lazies {
				if lazy.Hash == tail.Hash() {
					tailFound = true
					break
				}
			}
			if !tailFound {
				t.Fatalf("expected tail tx hash %s to surface after purge", tail.Hash())
			}
			if err := recoveredPool.Close(); err != nil {
				t.Fatalf("failed to close recovered pool: %v", err)
			}
		})
	}
}
