+++ b/core/vm/contracts_test.go
@@ -433,3 +433,30 @@ func BenchmarkPrecompiledP256Verify(bench *testing.B) {
 }

 func TestPrecompiledP256Verify(t *testing.T) { testJson("p256Verify", "0b", t) }
+
+func TestModExpRequiredGasCustom(t *testing.T) {
+    // Create MODEXP precompile with Osaka rules
+    modexp := &bigModExp{
+        eip7883: true,  // Enable Osaka fork
+    }
+    
+    // Test case: baseLen=1025, expLen=0, modLen=0
