// newUint64 creates a pointer to a uint64 value
func newUint64(val uint64) *uint64 { return &val }

// TestPreCheckBlobTxMaxBlobs tests that preCheck() does not fail when a blob transaction
// has 7 blobs when isOsaka is false (i.e., before Osaka fork).
func TestPreCheckBlobTxMaxBlobs(t *testing.T) {
	// Create a test configuration that enables Cancun but not Osaka
	config := &params.ChainConfig{
		ChainID:             big.NewInt(1),
		HomesteadBlock:      big.NewInt(0),
		DAOForkBlock:        big.NewInt(0),
		DAOForkSupport:      true,
		EIP150Block:         big.NewInt(0),
		EIP155Block:         big.NewInt(0),
		EIP158Block:         big.NewInt(0),
		ByzantiumBlock:      big.NewInt(0),
		ConstantinopleBlock: big.NewInt(0),
		PetersburgBlock:     big.NewInt(0),
		IstanbulBlock:       big.NewInt(0),
		MuirGlacierBlock:    big.NewInt(0),
		BerlinBlock:         big.NewInt(0),
		LondonBlock:         big.NewInt(0),
		PragueTime:          newUint64(0),    // Enable Prague
		OsakaTime:           newUint64(1000), // Disable Osaka (set to future time)
	}

	// Create test database and state
	statedb, _ := state.New(types.EmptyRootHash, state.NewDatabaseForTesting())

	// Create a test account with sufficient balance
	key, _ := crypto.GenerateKey()
	addr := crypto.PubkeyToAddress(key.PublicKey)
	statedb.SetBalance(addr, uint256.NewInt(1000000000000000000), tracing.BalanceChangeUnspecified) // 1 ETH
	statedb.SetNonce(addr, 0, tracing.NonceChangeUnspecified)

	// Create 7 empty blobs and their commitments/proofs
	var blobs []kzg4844.Blob
	var commitments []kzg4844.Commitment
	var proofs []kzg4844.Proof
	var blobHashes []common.Hash

	for i := 0; i < 7; i++ {
		blob := new(kzg4844.Blob)
		commitment, _ := kzg4844.BlobToCommitment(blob)
		proof, _ := kzg4844.ComputeBlobProof(blob, commitment)

		blobs = append(blobs, *blob)
		commitments = append(commitments, commitment)
		proofs = append(proofs, proof)

		// Create versioned hash (version 1)
		hasher := sha256.New()
		blobHash := kzg4844.CalcBlobHashV1(hasher, &commitment)
		blobHashes = append(blobHashes, blobHash)
	}

	// Create blob transaction with 7 blobs
	blobTx := &types.BlobTx{
		ChainID:    uint256.NewInt(1),
		Nonce:      0,
		GasTipCap:  uint256.NewInt(1000000000), // 1 gwei
		GasFeeCap:  uint256.NewInt(2000000000), // 2 gwei
		Gas:        100000,
		To:         common.Address{0x01},
		Value:      uint256.NewInt(0),
		Data:       []byte{},
		BlobFeeCap: uint256.NewInt(1000000000), // 1 gwei
		BlobHashes: blobHashes,
		Sidecar: &types.BlobTxSidecar{
			Version:     types.BlobSidecarVersion0,
			Blobs:       blobs,
			Commitments: commitments,
			Proofs:      proofs,
		},
	}

	// Sign the transaction
	signer := types.NewCancunSigner(config.ChainID)
	tx := types.MustSignNewTx(key, signer, blobTx)

	// Create EVM context
	blockNumber := big.NewInt(1)
	blockTime := uint64(100) // Before Osaka fork (OsakaTime = 1000)

	evmConfig := vm.Config{}
	evm := vm.NewEVM(vm.BlockContext{
		CanTransfer: CanTransfer,
		Transfer:    Transfer,
		GetHash:     func(uint64) common.Hash { return common.Hash{} },
		BlockNumber: blockNumber,
		Time:        blockTime,
		BaseFee:     big.NewInt(1000000000), // 1 gwei
		BlobBaseFee: big.NewInt(1000000000), // 1 gwei
	}, statedb, config, evmConfig)

	// Convert transaction to message
	msg, err := TransactionToMessage(tx, signer, big.NewInt(1000000000)) // 1 gwei base fee
	if err != nil {
		t.Fatalf("Failed to convert transaction to message: %v", err)
	}

	// Create state transition
	st := newStateTransition(evm, msg, new(GasPool).AddGas(1000000))

	// Test preCheck - this should NOT fail with 7 blobs when isOsaka is false
	err = st.preCheck()
	if err != nil {
		t.Errorf("preCheck() failed with 7 blobs when isOsaka is false: %v", err)
	}

	// Verify that isOsaka is indeed false
	if config.IsOsaka(blockNumber, blockTime) {
		t.Error("Expected isOsaka to be false, but it was true")
	}

	// Verify that Cancun is enabled
	if !config.IsPrague(blockNumber, blockTime) {
		t.Error("Expected Cancun to be enabled, but it was not")
	}

	t.Logf("Successfully passed preCheck() with 7 blobs when isOsaka is false")
}
```

### Mitigation

Consider modifying Besu to disable the max blobs per transaction when Osaka or EIP7594 is disabled.

### Summary

A missing deduplication between finalized and head-chain iterations in `onDataColumnSidecarsByRange` within Lodestar’s PeerDAS Req/Resp handler allows a single `DataColumnSidecarsByRange` request to replay previously served `(slot,column)` pairs, grow the response beyond its documented budget, and keep the worker thread occupied long enough to threaten validator liveness.


### Root Cause

In `packages/beacon-node/src/network/reqresp/handlers/dataColumnSidecarsByRange.ts — onDataColumnSidecarsByRange` the second loop over the head chain does not filter out slots already streamed from the finalized archive, so finalized data are replayed, ordering is no longer monotonic, and no per-request quota prevents the duplication.

### Internal Pre-conditions

1. An adversarial peer remains connected to the Lodestar Req/Resp server and can issue `DataColumnSidecarsByRange` calls.
2. The peer requests a range that overlaps finalized slots and continues into the nonfinalized head chain while staying within `MAX_REQUEST_BLOCKS_DENEB`, so request validation passes.

### External Pre-conditions

Finalized sidecars must exist in the archive so the handler has data to replay; no additional external protocol changes are required.

### Attack Path

1. The peer submits a single `DataColumnSidecarsByRange` request covering three consecutive slots and requesting all custody columns.
2. Lodestar streams the finalized archive first, then iterates the head chain. Because the head-chain loop includes slots already served, the same `(slot,column)` pairs are emitted again, producing 256 responses against the intended 192-budget (`count × columns`).
3. Column fetch callbacks run 2048 times although the expected upper bound is 1536, extending synchronous processing time beyond a 10 ms per-request budget and demonstrating liveness degradation risk.

### Impact

This is an availability degradation: a single request monopolizes the PeerDAS Req/Resp worker, causes deadline misses, and risks starving other validator duties. We observed 256 response chunks versus the 192 budget and 2048 column fetch operations versus 1536 allowed in our harness. Severity: Informational (availability)

### PoC

Run with `npx vitest run packages/beacon-node/test/unit/network/reqresp/fulu-req-02.test.ts --typecheck=false --pool=threads`:

```ts
import {afterEach, beforeEach, describe, expect, it, vi} from "vitest";
import {ChainConfig, createChainForkConfig, defaultChainConfig} from "@lodestar/config";
import {ResponseOutgoing} from "@lodestar/reqresp";
import {fulu} from "@lodestar/types";
import {
  onDataColumnSidecarsByRange,
  validateDataColumnSidecarsByRangeRequest,
} from "../../../../src/network/reqresp/handlers/dataColumnSidecarsByRange.js";
import * as responseValidation from "../../../../src/network/reqresp/utils/dataColumnResponseValidation.js";
import {IBeaconChain} from "../../../../src/chain/index.js";
import {IBeaconDb} from "../../../../src/db/index.js";
import {Buffer} from "node:buffer";
import {performance} from "node:perf_hooks";

describe("beacon-node / network / reqresp / dataColumnSidecarsByRange", () => {
  const chainConfig: ChainConfig = createChainForkConfig({
    ...defaultChainConfig,
    ALTAIR_FORK_EPOCH: 0,
    BELLATRIX_FORK_EPOCH: 0,
    CAPELLA_FORK_EPOCH: 0,
    DENEB_FORK_EPOCH: 0,
    ELECTRA_FORK_EPOCH: 0,
    FULU_FORK_EPOCH: 0,
    MAX_REQUEST_BLOCKS_DENEB: 3,
  });

  beforeEach(() => {
    vi.restoreAllMocks();
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it("clamps range count to config bounds and serves slots in ascending order", async () => {
    const overSizedCount = chainConfig.MAX_REQUEST_BLOCKS_DENEB + 10;
    const request: fulu.DataColumnSidecarsByRangeRequest = {
      startSlot: 5,
      count: overSizedCount,
      columns: [0, 1],
    };

    const bounded = validateDataColumnSidecarsByRangeRequest(chainConfig, request);
    expect(bounded.count).toBe(chainConfig.MAX_REQUEST_BLOCKS_DENEB);

    const finalizedSlots: Record<number, (Uint8Array | null)[]> = {
      5: [Uint8Array.of(5, 0), Uint8Array.of(5, 1)],
      6: [Uint8Array.of(6, 0), Uint8Array.of(6, 1)],
    };
    const headBlocks = [
      {slot: 5, blockRoot: toRootHex(5)},
      {slot: 6, blockRoot: toRootHex(6)},
      {slot: 7, blockRoot: toRootHex(7)},
    ];
    const unfinalizedByRoot: Record<string, (Uint8Array | null)[]> = {
      [toRootKey(5)]: [Uint8Array.of(5, 0), Uint8Array.of(5, 1)],
      [toRootKey(6)]: [Uint8Array.of(6, 0), Uint8Array.of(6, 1)],
      [toRootKey(7)]: [Uint8Array.of(7, 0), Uint8Array.of(7, 1)],
    };

    const chain = createChainStub({
      earliestAvailableSlot: 5,
      custodyColumns: [0, 1],
      finalizedSlot: 6,
      headBlocks,
      chainConfig,
    });

    const db = createDbStub({
      finalized: async (slot, cols) => finalizedSlots[slot] ?? cols.map(() => null),
      unfinalized: async (root, cols) => {
        const key = Buffer.from(root).toString("hex");
        return unfinalizedByRoot[key] ?? cols.map(() => null);
      },
    });

    const responses = await drainGenerator(onDataColumnSidecarsByRange(bounded, chain, db));
    const dataSignatures = responses.map((chunk) => Array.from(chunk.data));
    const sorted = [...dataSignatures].sort((a, b) => (a[0]! - b[0]!) || (a[1]! - b[1]!));
    expect(dataSignatures).toEqual(sorted);
    expect(dataSignatures[0]).toEqual([5, 0]);
    expect(dataSignatures[dataSignatures.length - 1]).toEqual([7, 1]);
  });

  it("escalates missing columns through the unavailability handler", async () => {
    const request: fulu.DataColumnSidecarsByRangeRequest = {
      startSlot: 600,
      count: 1,
      columns: [0],
    };

    const chain = createChainStub({
      earliestAvailableSlot: 600,
      custodyColumns: [0],
      finalizedSlot: 592,
      headBlocks: [
        {slot: 600, blockRoot: toRootHex(600)},
      ],
      chainConfig,
    });

    const unavailableSpy = vi.spyOn(responseValidation, "handleColumnSidecarUnavailability");

    const db = createDbStub({
      unfinalized: async () => [null],
      block: async () => null,
      blockArchive: async () => null,
    });

    await drainGenerator(onDataColumnSidecarsByRange(request, chain, db));

    expect(unavailableSpy).toHaveBeenCalledTimes(1);
    expect(unavailableSpy.mock.calls[0][0]).toMatchObject({
      slot: 600,
      unavailableColumnIndices: [0],
      requestedColumns: [0],
    });
  });

  it("keeps single-request response bounded without duplicate slot replays", async () => {
    const columns = Array.from({length: 64}, (_, i) => i as number);
    const request: fulu.DataColumnSidecarsByRangeRequest = {
      startSlot: 5,
      count: chainConfig.MAX_REQUEST_BLOCKS_DENEB,
      columns,
    };

    const {chain, slotByRoot} = createOverlappingChainStub({
      finalizedSlot: 6,
      headSlot: 6 + chainConfig.MAX_REQUEST_BLOCKS_DENEB,
      custodyColumns: columns,
      chainConfig,
    });

    const recorder = createSlotColumnRecorder();
    const db = createFloodingDbStub({
      slotByRoot,
      onFinalizedFetch: recorder.recordFinalized,
      onUnfinalizedFetch: recorder.recordUnfinalized,
    });

    const responses = await drainGenerator(onDataColumnSidecarsByRange(request, chain, db));
    const expectedUpperBound = request.count * columns.length;
    const duplicates = recorder.duplicates();

    expect(responses.length).toBeLessThanOrEqual(expectedUpperBound);
    expect(duplicates).toEqual([]);
  });

  it("completes single ByRange stream before attestation deadline", async () => {
    const columns = Array.from({length: 128}, (_, i) => i as number);
    const request: fulu.DataColumnSidecarsByRangeRequest = {
      startSlot: 5,
      count: chainConfig.MAX_REQUEST_BLOCKS_DENEB,
      columns,
    };

    const {chain, slotByRoot} = createOverlappingChainStub({
      finalizedSlot: 6,
      headSlot: 6 + chainConfig.MAX_REQUEST_BLOCKS_DENEB * 32,
      custodyColumns: columns,
      chainConfig,
    });

    let operations = 0;
    const db = createFloodingDbStub({
      slotByRoot,
      onFinalizedFetch: (_slot, cols) => {
        operations += cols.length;
      },
      onUnfinalizedFetch: (_slot, cols) => {
        operations += cols.length;
      },
    });

    let deadlineMissed = false;
    const deadlineMs = 10; // tight budget but still within realistic single-request window

    const drainPromise = (async () => {
      const t0 = performance.now();
      await drainGenerator(onDataColumnSidecarsByRange(request, chain, db));
      return performance.now() - t0;
    })();

    await Promise.race([
      drainPromise,
      new Promise<void>((resolve) => {
        setTimeout(() => {
          deadlineMissed = true;
          resolve();
        }, deadlineMs).unref?.();
      }),
    ]);

    const duration = await drainPromise;
    const allowedOps = request.count * columns.length;

    expect(deadlineMissed).toBe(false);
    expect(duration).toBeLessThanOrEqual(deadlineMs);
    expect(operations).toBeLessThanOrEqual(allowedOps);
  });
});

function toRootHex(slot: number): string {
  return `0x${slot.toString(16).padStart(64, "0")}`;
}

function toRootKey(slot: number): string {
  return toRootHex(slot).slice(2);
}

function createOverlappingChainStub({
  finalizedSlot,
  headSlot,
  custodyColumns,
  chainConfig,
}: {
  finalizedSlot: number;
  headSlot: number;
  custodyColumns: number[];
  chainConfig: ChainConfig;
}): {chain: IBeaconChain; slotByRoot: Map<string, number>} {
  const logger = {
    debug: vi.fn(),
    verbose: vi.fn(),
    warn: vi.fn(),
    info: vi.fn(),
  };

  const headChain = buildDescendingChain(headSlot, 5);
  const slotByRoot = new Map<string, number>();
  for (const {slot, blockRoot} of headChain) {
    slotByRoot.set(blockRoot.slice(2).toLowerCase(), slot);
  }

  const forkChoice = {
    getFinalizedBlock: () => ({slot: finalizedSlot}),
    getHeadRoot: () => toRootHex(headSlot),
    getAllAncestorBlocks: () => headChain,
  };

  return {
    chain: {
      config: chainConfig,
      custodyConfig: {custodyColumns},
      earliestAvailableSlot: 0,
      forkChoice,
      logger,
      metrics: null,
    } as unknown as IBeaconChain,
    slotByRoot,
  };
}

function buildDescendingChain(headSlot: number, minSlot: number) {
  const chain = [] as {slot: number; blockRoot: string}[];
  for (let slot = headSlot; slot >= minSlot; slot--) {
    chain.push({slot, blockRoot: toRootHex(slot)});
  }
  for (let slot = headSlot; slot >= minSlot; slot--) {
    if (slot % 2 === 0) {
      chain.push({slot, blockRoot: toRootHex(slot)});
    }
  }
  return chain;
}

function createChainStub({
  earliestAvailableSlot,
  custodyColumns,
  finalizedSlot,
  headBlocks,
  chainConfig,
}: {
  earliestAvailableSlot: number;
  custodyColumns: number[];
  finalizedSlot: number;
  headBlocks: {slot: number; blockRoot: string}[];
  chainConfig: ChainConfig;
}): IBeaconChain {
  const logger = {
    debug: vi.fn(),
    verbose: vi.fn(),
    warn: vi.fn(),
    info: vi.fn(),
  };

  const forkChoice = {
    getFinalizedBlock: () => ({slot: finalizedSlot}),
    getHeadRoot: () => headBlocks[headBlocks.length - 1]?.blockRoot ?? "0x00",
    getAllAncestorBlocks: () => headBlocks,
  };

  return {
    config: chainConfig,
    custodyConfig: {custodyColumns},
    earliestAvailableSlot,
    forkChoice,
    logger,
    metrics: null,
  } as unknown as IBeaconChain;
}

function createDbStub({
  finalized,
  unfinalized,
  block,
  blockArchive,
}: {
  finalized?: (slot: number, cols: number[]) => Promise<(Uint8Array | null)[]>;
  unfinalized?: (root: Uint8Array, cols: number[]) => Promise<(Uint8Array | null)[]>;
  block?: () => Promise<Uint8Array | null>;
  blockArchive?: (slot: number) => Promise<Uint8Array | null>;
} = {}): IBeaconDb {
  return {
    dataColumnSidecarArchive: {
      getManyBinary: vi.fn(async (slot: number, cols: number[]) => (finalized ? finalized(slot, cols) : cols.map(() => null))),
    },
    dataColumnSidecar: {
      getManyBinary: vi.fn(async (root: Uint8Array, cols: number[]) => (unfinalized ? unfinalized(root, cols) : cols.map(() => null))),
    },
    block: {
      getBinary: vi.fn(async () => (block ? block() : null)),
    },
    blockArchive: {
      getBinary: vi.fn(async (slot: number) => (blockArchive ? blockArchive(slot) : null)),
    },
  } as unknown as IBeaconDb;
}

interface FloodingDbOptions {
  slotByRoot?: Map<string, number>;
  onFinalizedFetch?: (slot: number, cols: number[]) => void;
  onUnfinalizedFetch?: (slot: number | undefined, cols: number[]) => void;
}

function createFloodingDbStub(options: FloodingDbOptions = {}): IBeaconDb {
  const {slotByRoot, onFinalizedFetch, onUnfinalizedFetch} = options;
  return {
    dataColumnSidecarArchive: {
      getManyBinary: vi.fn(async (slot: number, cols: number[]) => {
        onFinalizedFetch?.(slot, cols);
        return emulateAggregatorCost(cols);
      }),
    },
    dataColumnSidecar: {
      getManyBinary: vi.fn(async (root: Uint8Array, cols: number[]) => {
        const key = Buffer.from(root).toString("hex").toLowerCase();
        const slot = slotByRoot?.get(key);
        onUnfinalizedFetch?.(slot, cols);
        return emulateAggregatorCost(cols);
      }),
    },
    block: {
      getBinary: vi.fn(async () => null),
    },
    blockArchive: {
      getBinary: vi.fn(async () => null),
    },
  } as unknown as IBeaconDb;
}

function emulateAggregatorCost(cols: number[]): (Uint8Array | null)[] {
  const scratch = new Uint8Array(1024);
  for (let i = 0; i < cols.length * 500; i++) {
    const idx = (i * 13) & 1023;
    scratch[idx] ^= scratch[(idx + cols[i % cols.length]) & 1023] ^ (i & 0xff);
  }
  return cols.map((column) => Uint8Array.from([column & 0xff, (column * 3) & 0xff]));
}

function createSlotColumnRecorder() {
  const finalized = new Map<number, Map<number, number>>();
  const unfinalized = new Map<number, Map<number, number>>();

  function bump(store: Map<number, Map<number, number>>, slot: number | undefined, cols: number[]) {
    if (slot === undefined) return;
    let columnCounts = store.get(slot);
    if (!columnCounts) {
      columnCounts = new Map();
      store.set(slot, columnCounts);
    }
    for (const col of cols) {
      columnCounts.set(col, (columnCounts.get(col) ?? 0) + 1);
    }
  }

  return {
    recordFinalized(slot: number, cols: number[]) {
      bump(finalized, slot, cols);
    },
    recordUnfinalized(slot: number | undefined, cols: number[]) {
      bump(unfinalized, slot, cols);
    },
    duplicates(): Array<{slot: number; column: number; count: number; source: "finalized" | "unfinalized"}> {
      const out: Array<{slot: number; column: number; count: number; source: "finalized" | "unfinalized"}> = [];
      for (const [slot, columnCounts] of finalized) {
        for (const [column, count] of columnCounts) {
          if (count > 1) out.push({slot, column, count, source: "finalized"});
        }
      }
      for (const [slot, columnCounts] of unfinalized) {
        for (const [column, count] of columnCounts) {
          if (count > 1) out.push({slot, column, count, source: "unfinalized"});
        }
      }
      return out.sort((a, b) => (a.slot - b.slot) || (a.column - b.column));
    },
  };
}

async function drainGenerator(iterable: AsyncIterable<ResponseOutgoing>): Promise<ResponseOutgoing[]> {
  const out: ResponseOutgoing[] = [];
  for await (const chunk of iterable) {
    out.push(chunk);
  }
  return out;
}

```



### Mitigation

1. When iterating the head chain, skip any block whose slot is at or below the finalized boundary so finalized content is never replayed.
2. Produce head-chain responses in true ascending order and optionally track `(slot,column)` pairs per request to suppress duplicates before emitting data.
3. Enforce a per-request work budget (time or fetch count) and terminate the stream once the budget is exhausted instead of continuing to serve data.
4. Independently, reject requests with `startSlot` earlier than the node’s `earliestAvailableSlot` before performing any I/O.

### Summary

Missing length-equality enforcement combined with Fusaka V5 blob-serving handler’s unguarded indexing will stop block production for Nethermind validators after a single malformed EIP-4844 blob transactions which will trigger failures in `engine_getBlobsV2` / `engine_getPayloadV5` / `BlobsBundleV2` during payload assembly.

There will be a parallel submission to the EF Bug Bounty program for the Pectra / `engine_getPayloadV4` manifestation affecting `engine_getBlobsV1` and `BlobsBundleV1`.

### Root Cause

1. `nethermind/src/Nethermind/Nethermind.Crypto/IBlobProofsManager.cs`, `IBlobProofsVerifier.ValidateHashes(ShardBlobNetworkWrapper blobs, byte[][] blobVersionedHashes)` does not enforce `blobVersionedHashes.Length == blobs.Blobs.Length` (nor equality with commitments/proofs), allowing malformed txs.
2. in `nethermind/src/Nethermind/Nethermind.Merge.Plugin/Handlers/GetBlobsHandlerV2.cs` (V5) together with `nethermind/src/Nethermind/Nethermind.TxPool/Collections/BlobTxDistinctSortedPool.cs` (`TryGetBlobAndProofV1`), the code indexes `wrapper.Blobs[indexOfBlob]` without guarding `indexOfBlob >= wrapper.Blobs.Length`. The handler disposes then re-throws, violating V5’s all-or-nothing semantics (should return `Result.Success(null)` for partial availability).
3. `nethermind/src/Nethermind/Nethermind.Merge.Plugin/Data/BlobsBundleV2.cs` allocates arrays by mutated N and, when `N < M`, degrades to empty arrays in a catch path.

### Internal Pre-conditions

none

### External Pre-conditions

38% of validators run Nethermind as their EL.


### Attack Path

1. Attacker crafts a blob tx where `blobVersionedHashes` length (N) is greater than the sidecar’s actual blob count (M), with each hash individually well-formed (prefix 0x01, 32 bytes).
2. Attacker sets high gas tip so the malformed tx is likely to be selected during payload building.
3. Nethermind validators accept and propagate the malformed tx.
4. The tx remains in the pool across proposal attempts and is considered during each block construction by Nethermind validators.
5. The CL calls `engine_getPayloadV5`; the EL constructs `BlobsBundleV2` sized by N while only M blobs exist in the sidecar.
4. The CL calls `engine_getBlobsV2([realHash, extraHash])`. Because both hashes are present in `BlobIndex`, V5 handler assumes availability and asks the pool for `indexOfBlob`.
5. `TryGetBlobAndProofV1` indexes `wrapper.Blobs[1]` (for the extra hash) and triggers `IndexOutOfRangeException` (no bounds check). The V5 handler disposes and re-throws, producing an RPC error (instead of returning `Data == null`).
6. The CL cannot obtain blobs and skips the proposal for that slot. As long as the malformed tx persists Nethermind-based proposers repeatedly miss slots.

### Impact

1. 38% of the network capacity is removed.
2. 38% of validators lose block rewards and fees.
3. 38% of validators lose stake due coordinated inactivity leak penalties.

### PoC

1. Add in `./src/Nethermind/Nethermind.Merge.Plugin.Test/EngineModuleTests.V5.cs`
2. Test: `dotnet test ./src/Nethermind/Nethermind.Merge.Plugin.Test/Nethermind.Merge.Plugin.Test.csproj`
```
    [Test]
    public async Task GetPayloadV5_and_engine_getBlobsV2_should_fail_for_blob_txs_with_extra_hashes()
    {
        MergeTestBlockchain chain = await CreateBlockchain(releaseSpec: Osaka.Instance, mergeConfig: new MergeConfig()
        {
            NewPayloadBlockProcessingTimeout = (int)TimeSpan.FromDays(1).TotalMilliseconds
        });
        IEngineRpcModule rpcModule = chain.EngineRpcModule;

        // 1) Build a valid 1-blob tx for Osaka and then mutate it to have an extra versioned hash (N > M).
        Transaction blobTx = Build.A.Transaction
            .WithShardBlobTxTypeAndFields(1, spec: Osaka.Instance)
            .WithMaxFeePerGas(1.GWei())
            .WithMaxPriorityFeePerGas(1.GWei())
            .WithMaxFeePerBlobGas(1000.Wei())
            .SignedAndResolved(chain.EthereumEcdsa, TestItem.PrivateKeyA).TestObject;

        ShardBlobNetworkWrapper wrapper = (ShardBlobNetworkWrapper)blobTx.NetworkWrapper!;
        byte[] originalHash = blobTx.BlobVersionedHashes![0]!;
        byte[] extraHash = new byte[KzgPolynomialCommitments.BytesPerBlobVersionedHash];
        extraHash[0] = KzgPolynomialCommitments.KzgBlobHashVersionV1; // well-formed version byte but no underlying blob
        blobTx.BlobVersionedHashes = [originalHash, extraHash];

        // Mempool admission should still succeed because equality of lengths is not validated.
        chain.TxPool.SubmitTx(blobTx, TxHandlingOptions.None).Should().Be(AcceptTxResult.Accepted);

        // 2) Start payload building and get V5 payloadId.
        Task blockImprovementWait = chain.WaitForImprovedBlock();
        Hash256 headHash = chain.BlockTree.HeadHash;
        ForkchoiceStateV1 forkchoiceState = new(headHash, headHash, headHash);
        PayloadAttributes payloadAttributes = new()
        {
            Timestamp = chain.BlockTree.Head!.Timestamp + 1,
            PrevRandao = TestItem.KeccakH,
            SuggestedFeeRecipient = TestItem.AddressF,
            Withdrawals = [],
            ParentBeaconBlockRoot = TestItem.KeccakE
        };

        string payloadId = (await rpcModule.engine_forkchoiceUpdatedV3(forkchoiceState, payloadAttributes)).Data!.PayloadId!;
        await blockImprovementWait;

        // 3) engine_getPayloadV5 should succeed and the bundle should reflect only actual M blobs (not the extra hash).
        ResultWrapper<GetPayloadV5Result?> payloadResult = await rpcModule.engine_getPayloadV5(Bytes.FromHexString(payloadId));
        payloadResult.Result.Should().Be(Result.Success);
        payloadResult.Data.Should().NotBeNull();
        payloadResult.Data!.BlobsBundle.Should().NotBeNull();
        BlobsBundleV2 bundle = payloadResult.Data!.BlobsBundle!;
        // Because bundle sizing uses tx.GetBlobCount() (BlobVersionedHashes.Length), it reflects N (2),
        // but only the actual M (1) blob/proof entries are populated. The extra entries remain null.
        bundle.Blobs.Length.Should().Be(2);
        bundle.Commitments.Length.Should().Be(2);
        bundle.Proofs.Length.Should().Be(2 * Ckzg.CellsPerExtBlob);
        bundle.Blobs.Count(b => b == null).Should().Be(1);
        bundle.Commitments.Count(c => c == null).Should().Be(1);
        // Leading proof cells match the actual wrapper proofs; trailing cells (for the extra hash) are null.
        bundle.Proofs.Take(Ckzg.CellsPerExtBlob).Should().BeEquivalentTo(wrapper.Proofs);
        bundle.Proofs.Skip(Ckzg.CellsPerExtBlob).Should().OnlyContain(cell => cell == null);

        // Sanity: engine_getBlobsV2 with only the real hash returns the blob and proofs.
        ResultWrapper<IEnumerable<BlobAndProofV2>?> ok = await rpcModule.engine_getBlobsV2([originalHash]);
        ok.Result.Should().Be(Result.Success);
        ok.Data.Should().NotBeNull();
        BlobAndProofV2 only = ok.Data!.Single();
        only.Blob.Should().BeEquivalentTo(wrapper.Blobs[0]);
        only.Proofs.Length.Should().Be(Ckzg.CellsPerExtBlob);
        only.Proofs.Should().BeEquivalentTo(wrapper.Proofs.Take(Ckzg.CellsPerExtBlob));

        // 4) Request using the mutated (N > M) set. Both hashes are present in the blob index (2),
        // but only the first has underlying blob/proofs. The handler will throw when accessing index 1.
        chain.TxPool.GetBlobCounts(blobTx.BlobVersionedHashes!).Should().Be(2);
        Func<Task> badRequest = () => rpcModule.engine_getBlobsV2(blobTx.BlobVersionedHashes!);
        await badRequest.Should().ThrowAsync<IndexOutOfRangeException>();
    }
```

### Mitigation

- Enforce strict length equality during admission and/or verification: require `BlobVersionedHashes.Length == wrapper.Blobs.Length == wrapper.Commitments.Length == wrapper.Proofs.Length / Ckzg.CellsPerExtBlob` in `ValidateHashes`/`ValidateLengths` or mempool validators.
- Harden V5 serving in `BlobTxDistinctSortedPool.TryGetBlobAndProofV1`, guard `indexOfBlob >= wrapper.Blobs.Length` and return `false`; ensure `GetBlobsHandlerV2` returns `Result.Success(null)` on partial availability (no exceptions).
- Bundle sanity: validate that `BlobsBundleV2` sizes are consistent with sidecar lengths; on mismatch, fail fast or exclude malformed txs from payload building.

### Summary

Lighthouse returns custody groups in discovery order (`Vec`) rather than sorted, while the Fulu spec requires the returned custody groups to be sorted. This creates a cross-client consistency gap; to my knowledge it does not cause risk to network liveness or safety but may impact the columns advertised and clients that expect ordered lists.

### Root Cause

The [consensus spec](https://github.com/ethereum/consensus-specs/blob/9d377fd53d029536e57cfda1a4d2c700c59f86bf/specs/fulu/das-core.md#get_custody_groups) returns a sorted list of custody groups:

```python
def get_custody_groups(node_id: NodeID, custody_group_count: uint64) -> Sequence[CustodyIndex]:
    current_id = uint256(node_id)
    custody_groups: List[CustodyIndex] = []
    while len(custody_groups) < custody_group_count:
        custody_group = CustodyIndex(
            bytes_to_uint64(hash(uint_to_bytes(current_id))[0:8]) % NUMBER_OF_CUSTODY_GROUPS
        )
        if custody_group not in custody_groups:
            custody_groups.append(custody_group)
        if current_id == UINT256_MAX:
            current_id = uint256(0)
        else:
            current_id += 1
    assert len(custody_groups) == len(set(custody_groups))
    return sorted(custody_groups)
```

Lighthouse [returns](https://github.com/sigp/lighthouse/blob/unstable/consensus/types/src/data_column_custody_group.rs#L45-L77) a `Vec` preserving discovery order, not sorted order:

```rust
pub fn get_custody_groups_ordered(
    raw_node_id: [u8; 32],
    custody_group_count: u64,
    spec: &ChainSpec,
) -> Result<Vec<CustodyIndex>, DataColumnCustodyGroupError> {
    if custody_group_count > spec.number_of_custody_groups {
        return Err(DataColumnCustodyGroupError::InvalidCustodyGroupCount(custody_group_count));
    }

    let mut custody_groups = vec![];
    let mut current_id = U256::from_be_slice(&raw_node_id);
    while custody_groups.len() < custody_group_count as usize {
        let mut node_id_bytes = [0u8; 32];
        node_id_bytes.copy_from_slice(current_id.as_le_slice());
        let hash = ethereum_hashing::hash_fixed(&node_id_bytes);
        let hash_prefix: [u8; 8] = hash[0..8].try_into().expect("hash_fixed produces a 32 byte array");
        let hash_prefix_u64 = u64::from_le_bytes(hash_prefix);
        let custody_group = hash_prefix_u64.safe_rem(spec.number_of_custody_groups).expect("spec.number_of_custody_groups must not be zero");
        if !custody_groups.contains(&custody_group) {
            custody_groups.push(custody_group);
        }
        current_id = current_id.wrapping_add(U256::from(1u64));
    }

    Ok(custody_groups)
}
```

By contrast, for example, Prysm [sorts the resulting custody groups](https://github.com/OffchainLabs/prysm/blob/develop/beacon-chain/core/peerdas/das_core.go#L84) before returning them:

```golang
func CustodyGroups(nodeId enode.ID, custodyGroupCount uint64) ([]uint64, error) {
    // ... code omitted for brevity ...
    slices.Sort[[]uint64](custodyGroups)
    return custodyGroups, nil
}
```

### Internal Pre-conditions

None

### External Pre-conditions

None

### Attack Path

1. A cross-client integration expects `sorted(custody_groups)` per spec.
2. Lighthouse provides a discovery-ordered `Vec`.
3. The mismatch causes nondeterministic comparisons or differing column-prefix selections across clients for the same NodeID.

### Impact

To my knowledge it does not cause risk to network liveness or safety but may have an impact on the columns advertised and on the clients that expect ordered lists. Cross-client differences in the ordering of custody groups can lead to different first-N column selections for sampling/custody and to mismatches in tools that compare outputs directly.

### PoC

No response

### Mitigation

1. In `get_custody_groups_ordered`, sort the `Vec` before returning to match the spec requirement.
2. Update tests to assert sorted outputs for compliance.

### Summary

Any peer can advertise an out-of-range custody group count (cgc) greater than the configured `NumberOfCustodyGroups`. The value is propagated into PeerDAS peer selection without sanitization. When a single connected peer has an oversized cgc, the selection routine returns a fatal error instead of skipping the bad peer, aborting the entire data column sidecar retrieval for all peers. This enables a low-cost Denial of Service of data availability requests.

### Root Cause

The peer's custody group count is read from metadata or ENR and used as-is to derive PeerDAS info. If `custodyGroupCount > NumberOfCustodyGroups`, `peerdas.CustodyGroups` returns [`ErrCustodyGroupCountTooLarge`](https://github.com/OffchainLabs/prysm/blob/develop/beacon-chain/core/peerdas/das_core.go#L33). The caller `computeIndicesByRootByPeer` treats this as fatal and returns an error, collapsing the whole peer exploration step rather than filtering the bad peer.

```golang
// beacon-chain/p2p/custody.go
func (s *Service) CustodyGroupCountFromPeer(pid peer.ID) uint64 {
    // metadata -> ENR -> default CustodyRequirement
    return s.custodyGroupCountFromPeerENR(pid)
}

// beacon-chain/core/peerdas/das_core.go
func CustodyGroups(nodeId enode.ID, custodyGroupCount uint64) ([]uint64, error) {
    numberOfCustodyGroups := params.BeaconConfig().NumberOfCustodyGroups
    if custodyGroupCount > numberOfCustodyGroups {
        return nil, ErrCustodyGroupCountTooLarge
    }
    // ...
}

// beacon-chain/sync/data_column_sidecars.go
func computeIndicesByRootByPeer(p2p prysmP2P.P2P, slotByBlockRoot map[[32]byte]primitives.Slot, indicesByBlockRoot map[[32]byte]map[uint64]bool, peers map[peer.ID]bool) (map[peer.ID]map[[32]byte]map[uint64]bool, error) {
    for peer := range peers {
        nodeID, err := prysmP2P.ConvertPeerIDToNodeID(peer)
        if err != nil { return nil, errors.Wrapf(err, "convert peer ID to node ID for peer %s", peer) }
        custodyGroupCount := p2p.CustodyGroupCountFromPeer(peer)
        dasInfo, _, err := peerdas.Info(nodeID, custodyGroupCount)
        if err != nil { return nil, errors.Wrapf(err, "peerdas info for peer %s", peer) }
        // ...
    }
    // ...
}
```

### Internal Pre-conditions

None

### External Pre-conditions

A peer advertises `cgc > NumberOfCustodyGroups` in metadata or ENR.

### Attack Path

1. Attacker connects and publishes an oversized cgc via metadata or ENR.
2. Victim node requests sidecars and invokes peer exploration (`computeIndicesByRootByPeer`).
3. The function calls `peerdas.Info(nodeID, custodyGroupCount)` which calls `CustodyGroups` and returns `ErrCustodyGroupCountTooLarge`.
4. The error is treated as fatal; the function returns an error and the entire sidecar retrieval step aborts for all peers.

### Impact

PeerDAS sidecar retrieval fails, degrading data availability, reconstruction, etc. Attack cost is minimal: one malicious peer with crafted metadata/ENR can repeatedly trigger the abort path.

Additionally the same loop can also abort early due to non-DAS errors, such as nodeID conversion failure or a `ChainState` lookup error for a given peer.


### Full Callstack Path

```text
FetchDataColumnSidecars (prysm/beacon-chain/sync/data_column_sidecars.go)
  └─ requestDirectSidecarsFromPeers
     └─ computeIndicesByRootByPeer
        ├─ P2P.ConvertPeerIDToNodeID
        ├─ P2P.CustodyGroupCountFromPeer
        │   ├─ peers.Metadata OR peers.ENR
        │   └─ peerdas.CustodyGroupCountFromRecord (ENR)
        └─ peerdas.Info(nodeID, custodyGroupCount)
           ├─ CustodyGroups(nodeID, custodyGroupCount)
           │   └─ if custodyGroupCount > NumberOfCustodyGroups → ErrCustodyGroupCountTooLarge
           └─ (error bubbles)
        → computeIndicesByRootByPeer returns error
     → requestDirectSidecarsFromPeers aborts
  → FetchDataColumnSidecars step fails
```

### PoC

No response

### Mitigation

Make `computeIndicesByRootByPeer` robust: on any per-peer failure (invalid cgc, bad nodeID conversion, missing chain state), skip that peer and continue rather than returning a fatal error.

```golang
// file: prysm/beacon-chain/sync/data_column_sidecars.go (excerpt)
// Mitigation: skip bad peers in computeIndicesByRootByPeer
for peer := range peers {
    // Convert PeerID -> NodeID
    nodeID, err := prysmP2P.ConvertPeerIDToNodeID(peer)
    if err != nil {
        log.WithError(err).WithField("peer", peer).Debug("Skipping peer: cannot convert peer ID to node ID")
        continue
    }

    // Derive PeerDAS info
    custodyGroupCount := p2p.CustodyGroupCountFromPeer(peer)
    dasInfo, _, err := peerdas.Info(nodeID, custodyGroupCount)
    if err != nil {
        log.WithError(err).WithFields(logrus.Fields{"peer": peer, "cgc": custodyGroupCount}).Debug("Skipping peer: invalid PeerDAS info")
        continue
    }

    // Check chain state
    peerChainState, err := p2p.Peers().ChainState(peer)
    if err != nil {
        log.WithError(err).WithField("peer", peer).Debug("Skipping peer: cannot retrieve chain state")
        continue
    }
    if peerChainState == nil {
        log.WithField("peer", peer).Debug("Skipping peer: nil chain state")
        continue
    }

    // ... populate peersByIndex / headSlotByPeer using dasInfo and peerChainState ...
}
```

### Summary

When syncing, Besu can accept and canonize blocks whose RLP encoded size exceeds the `EIP-7934` cap (8,388,608 bytes) because the fast-sync validation path either returns early or bypasses the size check entirely.

This violates the `EIP-7934` rule that oversized blocks must be rejected. A malicious peer can deliver ≥8 MiB blocks during syncing, risking DoS (disk/memory blow-up) and consensus divergence versus clients that enforce the cap.

### Root Cause

Code branch: https://github.com/hyperledger/besu.git at main

Code commit: https://github.com/hyperledger/besu/commit/58660aa2936980c9c3df04b1e09050a034c83d0e

Besu enforces the `EIP-7934` size cap in the full validation path (good), but skips it in syncing paths:

- Full import path properly rejects oversized blocks via an early size check:

```java
// besu/ethereum/core/src/main/java/org/hyperledger/besu/ethereum/MainnetBlockValidator.java
// validateAndProcessBlock(...) – size check enforced
final int blockSize = block.getSize();
if (blockSize > maxRlpBlockSize) {
  final String errorMessage =
      "Block size of " + blockSize + " bytes exceeds limit of " + maxRlpBlockSize + " bytes";
  var retval = new BlockProcessingResult(errorMessage);
  handleFailedBlockProcessing(block, retval, true, context);
  return retval;
}
```

- But the sync validator returns early when `BodyValidationMode.NONE`, skipping any body/size checks:

```java
// besu/ethereum/core/src/main/java/org/hyperledger/besu/ethereum/MainnetBlockValidator.java
// validateBlockForSyncing(...)
if (bodyValidationMode == BodyValidationMode.FULL) {
  throw new UnsupportedOperationException(
      "Full body validation is not supported for syncing blocks");
}

// Header-only check
if (!blockHeaderValidator.validateHeader(header, context, headerValidationMode)) {
  ...
  return false;
}

// EARLY EXIT: no body or size validation when NONE
if (bodyValidationMode == BodyValidationMode.NONE) {
  return true;
}

// LIGHT mode validates light body properties, but no size check here either
if (!blockBodyValidator.validateBodyLight(context, block, receipts, ommerValidationMode)) {
  ...
  return false;
}
return true;
```

- The fast-sync path using `SyncBlock` bypasses the validator entirely and directly appends the block:

```java
// besu/ethereum/eth/src/main/java/org/hyperledger/besu/ethereum/eth/sync/fastsync/ImportSyncBlocksStep.java
final BlockImportResult blockImportResult =
    importer.importSyncBlockForSyncing(
        protocolContext,
        blockWithReceipts.getBlock(),
        blockWithReceipts.getReceipts(),
        transactionIndexingEnabled);
return blockImportResult.isImported();
```

```java
// besu/ethereum/core/src/main/java/org/hyperledger/besu/ethereum/mainnet/MainnetBlockImporter.java
// importSyncBlockForSyncing(...) – directly appends SyncBlock, no size validation
if (importWithTxIndexing) {
  context.getBlockchain().appendSyncBlock(syncBlock, receipts);
} else {
  context.getBlockchain().appendSyncBlockWithoutIndexingTransactions(syncBlock, receipts);
}
return new BlockImportResult(true);
```

- Contrast: `EIP-7934` cap is wired correctly for full validation/build:

```java
// besu/ethereum/core/src/main/java/org/hyperledger/besu/ethereum/MainnetBlockValidatorBuilder.java
private static final int OSAKA_MAX_BLOCK_SIZE = 10_485_760; // 10 MB
private static final int OSAKA_SAFETY_MARGIN = 2_097_152;   // 2 MB
private static final int OSAKA_MAX_RLP_BLOCK_SIZE = OSAKA_MAX_BLOCK_SIZE - OSAKA_SAFETY_MARGIN; // 8,388,608

public static BlockValidator osaka(
    final BlockHeaderValidator blockHeaderValidator,
    final BlockBodyValidator blockBodyValidator,
    final BlockProcessor blockProcessor) {
  return new MainnetBlockValidator(
      blockHeaderValidator, blockBodyValidator, blockProcessor, OSAKA_MAX_RLP_BLOCK_SIZE);
}
```

**Notes**
- go-ethereum enforces the cap both in validation and during block assembly, preventing oversized payloads from being built or accepted.

Reference:
- [`EIP-7934`](https://github.com/ethereum/EIPs/blob/master/EIPS/eip-7934.md)

### Internal Pre-conditions

- Node is on Osaka (or a fork schedule enabling EIP-7934) so that Besu’s `osaka` protocol spec and builder are active.
- Sync path uses either:
  - `importBlockForSyncing(...)` with `BodyValidationMode.NONE` (common in bulk import/offline import), or
  - Fast sync path `ImportSyncBlocksStep` → `importSyncBlockForSyncing(...)` with `SyncBlock`.


### External Pre-conditions

- An attacker can supply a block whose RLP-encoded execution block exceeds the 8,388,608-byte cap (e.g., ≥ 8 MiB), but is otherwise header-valid.
- Delivery through devp2p sync (fast sync) or tooling (e.g., ERA1 import) is possible; CL gossip caps at ~10 MiB do not constrain this EL import path.


### Attack Path

1. Malicious peer constructs an execution block with RLP size > 8,388,608 bytes (EIP-7934 cap), but ≤ CL gossip tolerance (~10 MiB), with matching header roots.
2. During fast syncing, Besu receives the block and receipts.
3. Fast-sync importer calls `importSyncBlockForSyncing(...)`, which appends the `SyncBlock` directly without invoking the size check.
4. Alternatively, using `importBlockForSyncing(...)` with `BodyValidationMode.NONE`, Besu runs header-only checks and returns `true` early, again skipping the size test.
5. The oversized block is stored and can become canonical if it extends the head.

### Impact

The impact of the issue could be: 
- **Standards violation**: EIP-7934 requires rejecting oversized blocks; Besu accepts them in sync paths.
- **Consensus divergence**: Other clients (e.g., go-ethereum) enforce the cap during validation and block building, so Besu can diverge from honest peers/networks.
- **DoS risk**: Accepting/storing ≥8 MiB bodies increases disk and memory pressure; repeated delivery can cause resource exhaustion.


### PoC

_No response_

### Mitigation

- Enforce the RLP-encoded block size cap uniformly across all import paths:
  - Add the same `block.getSize() > maxRlpBlockSize` check in `validateBlockForSyncing(...)` before any early return, regardless of `BodyValidationMode`.
  - In `importSyncBlockForSyncing(...)`, compute or derive the RLP size for `SyncBlock` and reject if it exceeds the cap (e.g., use header RLP size + `SyncBlockBody.getRlp().size()`, or materialize a `Block` and call `getSize()` with minimal overhead).
- Add tests covering:
  - `validateBlockForSyncing(..., BodyValidationMode.NONE)` rejecting oversized blocks.
  - Fast-sync `importSyncBlockForSyncing(...)` rejection of oversized `SyncBlock`.

### Summary

In the Fulu path, `BeaconProposerIndexAtSlot()` returns the proposer for the current epoch's lookahead segment when asked for a slot in a historical epoch (outside the lookahead window). During cross-epoch reorgs, this causes valid blocks to be rejected due to proposer mismatch. Liveness is impacted.

Related code: https://github.com/OffchainLabs/prysm/blob/0ea5e2cf9da520c515752600b949a37858a4954d/beacon-chain/core/helpers/validators.go#L320-L372

### Root Cause

In [`BeaconProposerIndexAtSlot()`](https://github.com/OffchainLabs/prysm/blob/0ea5e2cf9da520c515752600b949a37858a4954d/beacon-chain/core/helpers/validators.go#L320-L372), historical epoch queries trigger [`UpdateProposerIndicesInCache()`](https://github.com/OffchainLabs/prysm/blob/0ea5e2cf9da520c515752600b949a37858a4954d/beacon-chain/core/helpers/validators.go#L348) which ignores the `epoch` parameter and unconditionally caches [the first segment of the current state's proposer lookahead](https://github.com/OffchainLabs/prysm/blob/develop/beacon-chain/core/helpers/beacon_committee.go#L547-L551) (current epoch data) for the requested historical epoch. Subsequent [`cachedProposerIndexAtSlot()`](https://github.com/OffchainLabs/prysm/blob/0ea5e2cf9da520c515752600b949a37858a4954d/beacon-chain/core/helpers/validators.go#L344) calls return wrong proposers from this polluted cache.

### Internal Pre-conditions

1. Fulu lookahead enabled (state has `ProposerLookahead` with multiple segments).

### External Pre-conditions

1. A cross-epoch reorg causes the node to verify blocks from an earlier epoch.

### Attack Path

1. Natural: Cross-epoch reorg → `BeaconProposerIndexAtSlot(historicalSlot)` → `UpdateProposerIndicesInCache()` caches current lookahead for historical epoch → wrong proposer → proposer mismatch → block rejection.
2. Adversarial: Attacker controls proposer slots at epoch boundary (e.g., last slot of epoch N-1 and first slot of epoch N). Attacker builds a private 2-block fork, waits for honest nodes to advance to epoch N, then broadcasts the fork. When honest nodes attempt to validate the epoch N-1 block, `BeaconProposerIndexAtSlot()` reads current epoch N lookahead → wrong proposer → proposer mismatch → block rejection → deterministic rejection prevents reorg completion.

### Impact

* Persistent reorg denial: Cross-epoch reorgs fail permanently. `BeaconProposerIndexAtSlot()` returns current epoch proposers for historical blocks → block verification fails → block import stuck → node cannot sync past epoch boundary.

* Liveness impact: Nodes stay on stale fork. **Non-self-healing** due to deterministic cache pollution: once `UpdateProposerIndicesInCache()` stores wrong data for a historical epoch, every subsequent `cachedProposerIndexAtSlot()` call for that epoch returns the same incorrect proposer.

### PoC

Add the following unit test to this test file: https://github.com/OffchainLabs/prysm/blob/0ea5e2cf9da520c515752600b949a37858a4954d/beacon-chain/core/helpers/beacon_committee_test.go

```go
func TestBeaconProposerIndexAtSlot_FuluHistoricalEpochBug_SentinelHeads(t *testing.T) {
    helpers.ClearCache()
    ctx := t.Context()

    validators := make([]*ethpb.Validator, 128)
    for i := 0; i < len(validators); i++ {
        validators[i] = &ethpb.Validator{
            ExitEpoch:        params.BeaconConfig().FarFutureEpoch,
            EffectiveBalance: params.BeaconConfig().MaxEffectiveBalance,
        }
    }

    spe := params.BeaconConfig().SlotsPerEpoch
	require.Equal(t, primitives.Slot(32), spe)

    // mkLookahead builds a two-segment lookahead with a unique sentinel at [segment0][offset0].
    mkLookahead := func(sentinel uint64) []uint64 {
        la := make([]uint64, spe*2)
        // Segment 0 (current epoch): put a unique sentinel at offset 0.
        la[0] = sentinel
        for i := uint64(1); i < uint64(spe); i++ {
            la[i] = sentinel + i // keeps it recognizable but not used by this test
        }
        // Segment 1 (next epoch): filler values, not used by this test.
        for i := uint64(0); i < uint64(spe); i++ {
            la[uint64(spe)+i] = 100 + sentinel + i
        }
        return la
    }

    // Heads to test and their unique sentinels:
    // If the bug is present, querying "previous epoch" from each head will
    // incorrectly return the head's own lookahead[0] (i.e., the sentinel).
    cases := []struct {
        headEpoch primitives.Epoch
        sentinel  uint64
    }{
        {headEpoch: 5, sentinel: 10},
        {headEpoch: 6, sentinel: 20},
        {headEpoch: 7, sentinel: 30},
    }

    for _, tc := range cases {
        t.Run(fmt.Sprintf("head_epoch_%d_sentinel_%d", tc.headEpoch, tc.sentinel), func(t *testing.T) {
            helpers.ClearCache() // isolate cache between subtests

            // Initialize a Fulu state anchored at the head epoch with the crafted lookahead.
            st, err := state_native.InitializeFromProtoFulu(&ethpb.BeaconStateFulu{
                Validators:        validators,
                Slot:              primitives.Slot(tc.headEpoch) * spe, // head at epoch boundary
                ProposerLookahead: mkLookahead(tc.sentinel),
                BlockRoots:        make([][]byte, params.BeaconConfig().SlotsPerHistoricalRoot),
                StateRoots:        make([][]byte, params.BeaconConfig().SlotsPerHistoricalRoot),
                RandaoMixes:       make([][]byte, params.BeaconConfig().EpochsPerHistoricalVector),
            })
            require.NoError(t, err)

			// Get end slot for previous epoch
            targetEpochPrev := tc.headEpoch - 1
            endSlotPrevAnchor, err := slots.EpochEnd(targetEpochPrev - 1)
            require.NoError(t, err)

			// Get end slot for epoch before previous epoch
            targetEpochPrevPrev := targetEpochPrev - 1
            endSlotPrevPrevAnchor, err := slots.EpochEnd(targetEpochPrevPrev - 1)
            require.NoError(t, err)

            // Use distinct fake roots to avoid cross-test cache collisions.
            var fakeRootPrev [32]byte
            fakeRootPrev[0], fakeRootPrev[1], fakeRootPrev[2] = 0xAB, 0xCD, 0xEF
            fakeRootPrev[3] = byte(tc.headEpoch) // differentiate per subtest

            var fakeRootPrevPrev [32]byte
            fakeRootPrevPrev[0], fakeRootPrevPrev[1], fakeRootPrevPrev[2] = 0xDE, 0xAD, 0xBE
            fakeRootPrevPrev[3] = byte(tc.headEpoch ^ 0x55) // another distinct tag

            // Prepare distinct state_roots entries for the two anchor slots.
            idxPrev := endSlotPrevAnchor % params.BeaconConfig().SlotsPerHistoricalRoot
            idxPrevPrev := endSlotPrevPrevAnchor % params.BeaconConfig().SlotsPerHistoricalRoot

            // Sanity check: ensure the two anchors do not collide in the ring buffer.
            require.NotEqual(t, idxPrev, idxPrevPrev, "anchor indices collide in state_roots ring")

            stateRoots := make([][]byte, params.BeaconConfig().SlotsPerHistoricalRoot)
            stateRoots[idxPrev] = fakeRootPrev[:]
            stateRoots[idxPrevPrev] = fakeRootPrevPrev[:]

            require.NoError(t, st.SetStateRoots(stateRoots))

            // Query the first slot of the previous epoch from this head's point of view.
            targetSlotPrev := primitives.Slot(targetEpochPrev) * spe
            gotPrev, err := helpers.BeaconProposerIndexAtSlot(ctx, st, targetSlotPrev)
            require.NoError(t, err)

            // Additionally, query the first slot of the epoch two epochs prior.
            targetSlotPrevPrev := primitives.Slot(targetEpochPrevPrev) * spe
            gotPrevPrev, err := helpers.BeaconProposerIndexAtSlot(ctx, st, targetSlotPrevPrev)
            require.NoError(t, err)

            // If the bug exists, both results will equal the sentinel (i.e., head lookahead[0]).
            if gotPrev == primitives.ValidatorIndex(tc.sentinel) && gotPrevPrev == primitives.ValidatorIndex(tc.sentinel) {
                t.Errorf(
                    "BUG CONFIRMED (multi-epoch pollution): headEpoch=%d targetEpochs={%d,%d} got={%d,%d}; both match sentinel=%d; expected proposers derived from their respective anchor states",
                    tc.headEpoch, targetEpochPrev, targetEpochPrevPrev, gotPrev, gotPrevPrev, tc.sentinel,
                )
            }
        })
    }
}
```

