import static org.mockito.ArgumentMatchers.anyInt;
import static org.mockito.Mockito.atLeastOnce;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.reset;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.verifyNoInteractions;

class DataColumnSidecarSubnetBackboneSubscriberTest {

  private Spec spec;
  private UInt256 nodeId;
  private int initialGroups;
  private int increasedGroups;

  @BeforeEach
  void setup() {
    spec =
            TestSpecFactory.createMinimalFulu(
                    b ->
                            b.fuluBuilder(
                                    fb ->
                                            fb.dataColumnSidecarSubnetCount(16)
                                                    .numberOfCustodyGroups(16)
                                                    .numberOfColumns(128)
                                                    .cellsPerExtBlob(128)));

    nodeId = UInt256.valueOf(12345);
    initialGroups = 4;
    increasedGroups = 8;
  }

  @Test
  void subnetsNotUpdatedUntilNextEpoch_whenGroupCountChangesMidEpoch() {
    final int slotsPerEpoch = spec.getSlotsPerEpoch(UInt64.ZERO);

    Eth2P2PNetwork p2p = mock(Eth2P2PNetwork.class);
    DataColumnSidecarSubnetBackboneSubscriber subscriber =
            new DataColumnSidecarSubnetBackboneSubscriber(spec, p2p, nodeId, initialGroups);

    // initial subscriptions at slot 0
    subscriber.onSlot(UInt64.ZERO);
    // just check that *some* subscriptions happened
    verify(p2p,atLeastOnce()).subscribeToDataColumnSidecarSubnetId(anyInt());

    reset(p2p);

    // mid-epoch change: bump CGC
    subscriber.onGroupCountUpdate(increasedGroups, increasedGroups);
    subscriber.onSlot(UInt64.valueOf(1));

    // nothing should happen mid-epoch, EVEN though we increased CGC and now the DA checks will already check on the updated
    //sampling size.
    verifyNoInteractions(p2p);

    // next epoch -> update happens
    subscriber.onSlot(UInt64.valueOf(slotsPerEpoch));

    // assert that *now* we subscribed to something
    verify(p2p, atLeastOnce()).subscribeToDataColumnSidecarSubnetId(anyInt());
  }
}
