```java
@Test
  void checkDataAvailability_forcesWait_untilLastMissingColumnCompletesTest() {
    //This test will simulate the effect of NOT having the subnets.
    when(currentSlotProvider.getCurrentSlot()).thenReturn(UInt64.ZERO);

    final Bytes32 blockRoot = dataStructureUtil.randomBytes32();
    final int totalCols = SPEC_CONFIG_FULU.getNumberOfColumns();

    // start with a sampling size increase this slot
    final int oldSample = 12;
    final int newSample = Math.min(totalCols, oldSample + 16);

    final int missingIdx = 5; // we will intentionally miss this one from the old sampling size indices

    // the calculation for indices is hardcoded here for ease
    final List<UInt64> custodyIndices =
            IntStream.range(0, oldSample)
                    .filter(i -> i != missingIdx)
                    .mapToObj(UInt64::valueOf)
                    .toList();

    final List<UInt64> samplingIndices =
            IntStream.range(0, newSample).mapToObj(UInt64::valueOf).toList();
    final CustodyGroupCountManager cgcManager = mock(CustodyGroupCountManager.class);
    when(cgcManager.getCustodyColumnIndices()).thenReturn(custodyIndices);
    when(cgcManager.getSamplingColumnIndices()).thenReturn(samplingIndices);

    // ensure that Custody has all old-sample (except missingIdx)
    for (UInt64 idx : custodyIndices) {
      when(custody.hasCustodyDataColumnSidecar(
              new DataColumnSlotAndIdentifier(UInt64.ZERO, blockRoot, idx)))
              .thenReturn(SafeFuture.completedFuture(true));
    }

    // old sample size missingIdx is not in custody
    when(custody.hasCustodyDataColumnSidecar(
            new DataColumnSlotAndIdentifier(UInt64.ZERO, blockRoot, UInt64.valueOf(missingIdx))))
            .thenReturn(SafeFuture.completedFuture(false));

    // For the *extra indices introduced by the immediate sampling increase
    // behave as if we can't receive them over gossip: return a never-completing future
    // simply because there are no subnets subscribed yet.
    final List<UInt64> extraIndices =
            IntStream.range(oldSample, newSample).mapToObj(UInt64::valueOf).toList();
    for (UInt64 idx : extraIndices) {
      when(custody.hasCustodyDataColumnSidecar(
              new DataColumnSlotAndIdentifier(UInt64.ZERO, blockRoot, idx)))
              .thenReturn(SafeFuture.completedFuture(false));
    }

    final List<SafeFuture<DataColumnSidecar>> extraGates =
            extraIndices.stream().map(__ -> new SafeFuture<DataColumnSidecar>()).toList();

    final SafeFuture<DataColumnSidecar> missingGate = new SafeFuture<>();

    // Stub/mock the retriever:
    for (int i = 0; i < newSample; i++) {
      final UInt64 idx = UInt64.valueOf(i);
      final var id = new DataColumnSlotAndIdentifier(UInt64.ZERO, blockRoot, idx);

      if (i == missingIdx) {
        when(retriever.retrieve(id)).thenReturn(missingGate);
      } else if (i >= oldSample) {
        final int gateIdx = i - oldSample;
        when(retriever.retrieve(id)).thenReturn(extraGates.get(gateIdx));
      } else {
        when(retriever.retrieve(id))
                .thenReturn(
                        SafeFuture.completedFuture(
                                dataStructureUtil.randomDataColumnSidecar(
                                        dataStructureUtil.randomSignedBeaconBlockHeader(UInt64.ZERO), idx)));
      }
    }
    when(custody.onNewValidatedDataColumnSidecar(any(), any())).thenReturn(SafeFuture.COMPLETE);

    final DasSamplerBasic sampler =
            new DasSamplerBasic(SPEC, currentSlotProvider, db, custody, retriever, () -> cgcManager);

    final SafeFuture<List<UInt64>> result = sampler.checkDataAvailability(UInt64.ZERO, blockRoot);

    //Expect that we CANNOT complete yet
    // Even if we later deliver the missing old-sample column, we still lack all the "extra" columns
    //introduced by cgc/sampling change
    // due to not being subscribed to their subnets yet.
    assertThat(result).isNotDone();

    // Deliver the original missing old-sample column
    final var deliveredOld =
            dataStructureUtil.randomDataColumnSidecar(
                    dataStructureUtil.randomSignedBeaconBlockHeader(UInt64.ZERO), UInt64.valueOf(missingIdx));
    missingGate.complete(deliveredOld);

    // Still can't complete because the new-sample "extra" columns can't arrive as we missing the new column subnet subs
    assertThat(result).isNotDone();
  }
