```
`custody_columns_for_epoch` truncates the advertised list to that epoch’s custody count, explaining why a range that crosses into an epoch with more assignments loses the new indices.

```rust
pub fn custody_columns_for_epoch(
        &self,
        epoch_opt: Option<Epoch>,
        spec: &ChainSpec,
    ) -> &[ColumnIndex] {
        let custody_group_count = if let Some(epoch) = epoch_opt {
            self.custody_group_count_at_epoch(epoch, spec) as usize
        } else {
            self.custody_group_count_at_head(spec) as usize
        };

        let all_columns_ordered = self
            .all_custody_columns_ordered
            .get()
            .expect("all_custody_columns_ordered should be initialized");
        &all_columns_ordered[..custody_group_count]
    }
```

`add()` still tracks the full `count * columns.len()` expectation, so the missing indices propagate as verification failures rather than being tolerated.

```rust
// beacon_node/network/src/sync/network_context/requests/data_columns_by_range.rs:25-52 
fn add(&mut self, data_column: Self::Item) -> Result<bool, LookupVerifyError> {
        if data_column.slot() < self.request.start_slot
            || data_column.slot() >= self.request.start_slot + self.request.count
        {
            return Err(LookupVerifyError::UnrequestedSlot(data_column.slot()));
        }
        if !self.request.columns.contains(&data_column.index) {
            return Err(LookupVerifyError::UnrequestedIndex(data_column.index));
        }
        if !data_column.verify_inclusion_proof() {
            return Err(LookupVerifyError::InvalidInclusionProof);
        }
        if self.items.iter().any(|existing| {
            existing.slot() == data_column.slot() && existing.index == data_column.index
        }) {
            return Err(LookupVerifyError::DuplicatedData(
                data_column.slot(),
                data_column.index,
            ));
        }

        self.items.push(data_column);

        Ok(self.items.len() >= self.request.count as usize * self.request.columns.len())
    }
