### Mitigation

The most straightforward fix is as follows:

```rust
impl BlobsByRangeRequest {
    pub fn max_blobs_requested(&self, epoch: Epoch, spec: &ChainSpec) -> u64 {
        // Hardcoded to MainnetEthSpec’s 32 slots/epoch for this mitigation demo; for production
        // support, replace this with the EthSpec-specific value.
        let slots_per_epoch: u64 = 32;
        let mut total: u64 = 0;
        let mut slot = Slot::new(self.start_slot);

        for _ in 0..self.count {
            let slot_epoch = slot.epoch(slots_per_epoch);
            total = total.saturating_add(spec.max_blobs_per_block(slot_epoch));
            slot = slot + 1;
        }
        total
    }
}
```

Replace `TestBlobsByRangeRequest` with the above logic and rerun the PoC test, it will pass with the following logs:

