    fn input(&self) -> &Bytes { self.inner.input() }
    fn access_list(&self) -> Option<&alloy_eips::eip2930::AccessList> { self.inner.access_list() }
    fn blob_versioned_hashes(&self) -> Option<&[B256]> { self.inner.blob_versioned_hashes() }
