    );

    // Seed the provider with a post-Osaka head block to satisfy forkchoice semantics.
    let mut block = Block::default();
    block.header.number = 1;
    block.header.timestamp = activation_timestamp + 1;
    let head_hash = block.header.hash_slow();

    let provider = Arc::new(MockEthProvider::default().with_chain_spec((*chain_spec).clone()));
    provider.add_block(head_hash, block);

    // Prepare a transaction pool backed by an in-memory blob store.
    let blob_store = InMemoryBlobStore::default();
    let pool: Pool<
        MockTransactionValidator<EthPooledTransaction>,
        CoinbaseTipOrdering<EthPooledTransaction>,
        InMemoryBlobStore,
    > = Pool::new(
        MockTransactionValidator::default(),
        CoinbaseTipOrdering::default(),
        blob_store.clone(),
        PoolConfig::default(),
    );

    // Insert a legacy EIP-4844 sidecar into the blob store.
    let blob = Blob::repeat_byte(0x01);
    let commitment = Bytes48::repeat_byte(0x11);
    let proof = Bytes48::repeat_byte(0x22);
    let legacy_sidecar = BlobTransactionSidecar {
        blobs: vec![blob],
        commitments: vec![commitment],
        proofs: vec![proof],
    };
    let versioned_hash = legacy_sidecar
        .versioned_hashes()
        .next()
        .expect("sidecar produces a versioned hash");
    let tx_hash = B256::repeat_byte(0x33);

    blob_store
        .insert(tx_hash, BlobTransactionSidecarVariant::Eip4844(legacy_sidecar.clone()))
        .expect("blob store insert succeeds");

    // Sanity: legacy sidecar lives in the pool's blob cache.
    assert!(
        matches!(
            pool.blob_store()
                .get(tx_hash)
                .expect("blob lookup succeeds"),
            Some(sidecar) if sidecar.is_eip4844()
        ),
        "pool cache should still hold an EIP-4844 sidecar",
    );

    // Instantiate Engine API with the configured components.
    let payload_store = spawn_test_payload_service::<EthEngineTypes>();
    let (to_engine, _engine_rx) = unbounded_channel();
    let client = ClientVersionV1 {
        code: ClientCode::RH,
        name: "Reth".to_owned(),
        version: "v0.0.test".to_owned(),
