    // Act: query both blob endpoints for the same versioned hash.
    let available_v1 = pool
        .get_blobs_for_versioned_hashes_v1(&[versioned_hash])
        .expect("pool blob lookup succeeds");
    let blobs_v2 = api
        .get_blobs_v2_metered(vec![versioned_hash])
        .expect("engine_getBlobsV2 call succeeds in the vulnerable state");

    // Assert: pool can serve the legacy blob, but the Engine API fails to upgrade it to cell proofs
