        blobsResponse.Result.Should().Be(Result.Success);
        blobsResponse.Data.Should().NotBeNull();
        blobsResponse.Data!.Should().NotBeEmpty();

        foreach (BlobAndProofV2 blobAndProof in blobsResponse.Data!)
