func newPublicKey(x, y *big.Int) *ecdsa.PublicKey {
    // Explicit rejection of nil coordinates
    if x == nil || y == nil {
        return nil  // REJECT
    }

    // Explicit rejection of point-at-infinity (0,0)
    if x.Sign() == 0 && y.Sign() == 0 {
