	"github.com/ethereum/go-ethereum/crypto"
	"github.com/ethereum/go-ethereum/event"
	// "github.com/ethereum/go-ethereum/params"
	// "github.com/ethereum/go-ethereum/core/txpool"
	"github.com/holiman/uint256"
)

func TestEIP7935(t *testing.T) {
	t.Parallel()

	_ = testTxPoolConfig

	pool, key := setupPool()
	defer pool.Close()

	addr := crypto.PubkeyToAddress(key.PublicKey)
	resetState := func() (*state.StateDB) {
		statedb, _ := state.New(types.EmptyRootHash, state.NewDatabaseForTesting())
		statedb.AddBalance(addr, uint256.NewInt(100000000000000), tracing.BalanceChangeUnspecified)

		pool.chain = newTestBlockChain(pool.chainconfig, 60_000_000, statedb, new(event.Feed)) // @ref EIP-7935
		<-pool.requestReset(nil, nil)
		return statedb
	}
	_ = resetState()

	Txs := types.Transactions{}

	Txs = append(Txs, pricedTransaction(uint64(0), 60_000_000, big.NewInt(1), key))
	errs := pool.addRemotesSync(Txs)

	if len(errs) != 0 {
		fmt.Printf("errs: %v\n", errs)
	}

	Txs2 := types.Transactions{}

	Txs2 = append(Txs2, pricedTransaction(uint64(1), 60_000_001, big.NewInt(1), key))
	errs = pool.addRemotesSync(Txs2)

	if len(errs) != 0 {
		fmt.Printf("errs: %v\n", errs)
	}
}

func TestEIP7825BadCase(t *testing.T) {
	t.Parallel()

	_ = testTxPoolConfig

	pool, key := setupPool()
	defer pool.Close()

	pool.chainconfig.LondonBlock = big.NewInt(0)
    var osakaZero uint64 = 0
    pool.chainconfig.OsakaTime = &osakaZero

	addr := crypto.PubkeyToAddress(key.PublicKey)
	resetState := func() (*state.StateDB) {
		statedb, _ := state.New(types.EmptyRootHash, state.NewDatabaseForTesting())
		statedb.AddBalance(addr, uint256.NewInt(100000000000000), tracing.BalanceChangeUnspecified)

		pool.chain = newTestBlockChain(pool.chainconfig, 60_000_000, statedb, new(event.Feed)) // @ref EIP-7935
		<-pool.requestReset(nil, nil)
		return statedb
	}
	_ = resetState()

	Txs := types.Transactions{}

	Txs = append(Txs, pricedTransaction(uint64(0), 60_000_000, big.NewInt(1), key))
	errs := pool.addRemotesSync(Txs)

	if len(errs) != 0 {
		fmt.Printf("errs: %v\n", errs)
	}

	Txs2 := types.Transactions{}

	Txs2 = append(Txs2, pricedTransaction(uint64(0), 60_000_001, big.NewInt(1), key))
	errs = pool.addRemotesSync(Txs2)

	if len(errs) != 0 {
		fmt.Printf("errs: %v\n", errs)
	}
}
```

The `TestEIP7935` function represents the intended behavior of EIP-7935.
The `TestEIP7825BadCase` function illustrates the issue where EIP-7825 prevents EIP-7935 from functioning as intended.

As shown in the screenshot below, the `TestEIP7935` function excludes only transactions that exceed the 60M gas limit, in accordance with EIP-7935.
