        let sidecars_construction_started = Arc::new(dashmap::DashMap::new());

        let (controller, mutator_handle) = Controller::new(
            chain_config.clone_arc(),
            pubkey_cache,
            store_config,
            anchor_block.clone_arc(),
            anchor_state,
            tick,
            event_channels,
            execution_engine,
            None,
            fc_to_attestation_verifier_tx,
            fc_to_p2p_tx,
            fc_to_pool_tx,
            fc_to_subnet_tx,
            fc_to_sync_tx,
            fc_to_validator_tx,
            storage,
            core::iter::empty(),
            true,
            [].into(),
            sidecars_construction_started,
        )?;

        // 2) Build a minimal DataColumnSidecar for a non-sampled column (index 0).
        let column: ContiguousList<Cell<Minimal>, <Minimal as types::preset::Preset>::MaxBlobCommitmentsPerBlock> =
            ContiguousList::try_from(Vec::new()).unwrap();
        let kzg_commitments: ContiguousList<
            KzgCommitment,
            <Minimal as types::preset::Preset>::MaxBlobCommitmentsPerBlock,
        > = ContiguousList::try_from(Vec::new()).unwrap();
        let kzg_proofs: ContiguousList<
            KzgProof,
            <Minimal as types::preset::Preset>::MaxBlobCommitmentsPerBlock,
        > = ContiguousList::try_from(Vec::new()).unwrap();

        let sidecar = Arc::new(DataColumnSidecar::<Minimal> {
            index: 0,
            column,
            kzg_commitments,
            kzg_proofs,
            signed_block_header: anchor_block.to_header(),
            kzg_commitments_inclusion_proof:
                types::fulu::primitives::BlobCommitmentsInclusionProof::<Minimal>::default(),
        });

        // 3) Call the real HTTP publish path with sidecars first, expecting a fatal failure.
        let (api_to_p2p_tx, _api_to_p2p_rx) = mpsc::unbounded::<ApiToP2p<Minimal>>();

        let result = super::publish_signed_block_v2_with_data_column_sidecar(
            anchor_block,
            vec![sidecar],
            super::BroadcastValidation::Gossip,
            controller.clone_arc(),
            api_to_p2p_tx,
        )
        .await;

        // Any Ignore(false) from sidecar validation must abort publication.
        assert!(matches!(result, Err(super::Error::UnableToPublishBlock)));

        tokio::task::spawn_blocking(|| drop(mutator_handle)).await?;

        Ok(())
    }
```

### Mitigation


- In REST publish implementations, submit only sampled columns to fork‑choice while still publishing all sidecars to p2p.
- Alternatively, treat `Ignore(false)` from non‑sampled indices as non‑fatal in `submit_data_column_sidecars(...)`. Distinguish non‑sampled vs delay cases and only abort on non‑publishable failures.

### Summary

In the `doAnnounceBlockRange` function, the code directly constructs and sends outgoing `BlockRangeUpdatePacket` messages without performing validation checks on the block range data.

Without these validations, erigon may broadcast invalid block range updates to peers. Some peers (such as go-ethereum) perform validation on received block range messages and will treat the response as invalid, potentially disconnecting or downgrading erigon nodes that send malformed data. This affects network connectivity and peer reputation.

Location of `doAnnounceBlockRange` function: https://github.com/erigontech/erigon/blob/fdd9d9ef475f2a0bf1bd170d2d6adc0103f9faed/p2p/sentry/sentry_multi_client/sentry_multi_client.go#L168-L210

```go
func (cs *MultiClient) doAnnounceBlockRange(ctx context.Context) {
	sentries := cs.Sentries()
	status, err := cs.statusDataProvider.GetStatusData(ctx)
	if err != nil {
		cs.logger.Error("blockRangeUpdate", "err", err)
		return
	}

	bestHash := gointerfaces.ConvertH256ToHash(status.BestHash)
	cs.logger.Debug("sending status data", "start", status.MinimumBlockHeight, "end", status.MaxBlockHeight, "hash", hex.EncodeToString(bestHash[:]))

	request := eth.BlockRangeUpdatePacket{
		Earliest:   status.MinimumBlockHeight,
		Latest:     status.MaxBlockHeight,
		LatestHash: gointerfaces.ConvertH256ToHash(status.BestHash),
	}

	data, err := rlp.EncodeToBytes(&request)
	if err != nil {
		cs.logger.Error("blockRangeUpdate", "err", err)
		return
	}

	for _, s := range sentries {
		handshake, err := s.HandShake(ctx, &emptypb.Empty{})
		if err != nil {
			cs.logger.Error("blockRangeUpdate", "err", err)
			continue // continue sending message to other sentries
		}

		version := direct.ProtocolToUintMap[handshake.Protocol]
		if version >= direct.ETH69 {
			_, err := s.SendMessageToAll(ctx, &sentryproto.OutboundMessageData{
				Id:   sentryproto.MessageId_BLOCK_RANGE_UPDATE_69,
				Data: data,
			})
			if err != nil {
				cs.logger.Error("blockRangeUpdate", "err", err)
				continue // continue sending message to other sentries
			}
		}
	}
}
```

Additionally, the `findFirstCompleteBlock` function may return `math.MaxUint64` when no complete block body is available, which could result in an invalid block range being broadcast.

Call stack: `doAnnounceBlockRange` -> `GetStatusData` -> `MinimumBlockAvailable` -> `findFirstCompleteBlock`.

Code locations:
`doAnnounceBlockRange` -> `GetStatusData`: https://github.com/erigontech/erigon/blob/fdd9d9ef475f2a0bf1bd170d2d6adc0103f9faed/p2p/sentry/sentry_multi_client/sentry_multi_client.go#L170
`GetStatusData` -> `MinimumBlockAvailable`: https://github.com/erigontech/erigon/blob/fdd9d9ef475f2a0bf1bd170d2d6adc0103f9faed/p2p/sentry/status_data_provider.go#L136
`MinimumBlockAvailable` -> `findFirstCompleteBlock`: https://github.com/erigontech/erigon/blob/fdd9d9ef475f2a0bf1bd170d2d6adc0103f9faed/db/snapshotsync/freezeblocks/block_reader.go#L459
`findFirstCompleteBlock` returns `math.MaxUint64`: https://github.com/erigontech/erigon/blob/fdd9d9ef475f2a0bf1bd170d2d6adc0103f9faed/db/snapshotsync/freezeblocks/block_reader.go#L475

For example, go-ethereum client implements a `Validate()` method that checks if `earliestBlock` exceeds `latestBlock` or if `latestBlockHash` is a zero hash, and will treat the response as invalid if these conditions are not met:

```go
func (p *BlockRangeUpdatePacket) Validate() error {
	if p.EarliestBlock > p.LatestBlock {
		return errors.New("earliest > latest")
	}
	if p.LatestBlockHash == (common.Hash{}) {
		return errors.New("zero latest hash")
	}
	return nil
}
```

Code location: https://github.com/ethereum/go-ethereum/blob/659342a52300d9cd8218face5528a91e7434a8fb/eth/protocols/eth/handshake.go#L210-L219

Note: The field names differ between go-ethereum (`EarliestBlock`, `LatestBlock`, `LatestBlockHash`) and Erigon (`Earliest`, `Latest`, `LatestHash`), but the validation logic is analogous.

### Mitigation

Add validation for the `BlockRangeUpdatePacket` before encoding and sending:
```go
func (cs *MultiClient) doAnnounceBlockRange(ctx context.Context) {
	sentries := cs.Sentries()
	status, err := cs.statusDataProvider.GetStatusData(ctx)
	if err != nil {
		cs.logger.Error("blockRangeUpdate", "err", err)
		return
	}

	bestHash := gointerfaces.ConvertH256ToHash(status.BestHash)

	// Add validation before constructing the packet
	if status.MinimumBlockHeight == math.MaxUint64 || status.MaxBlockHeight == math.MaxUint64 {
		cs.logger.Debug("skipping block range announcement: no complete blocks available")
		return
	}

	if status.MinimumBlockHeight > status.MaxBlockHeight {
		cs.logger.Warn("invalid block range: earliest > latest", "earliest", status.MinimumBlockHeight, "latest", status.MaxBlockHeight)
		return
	}

	if bestHash == (common.Hash{}) {
		cs.logger.Warn("invalid block range: best hash is zero")
		return
	}

	cs.logger.Debug("sending status data", "start", status.MinimumBlockHeight, "end", status.MaxBlockHeight, "hash", hex.EncodeToString(bestHash[:]))

	request := eth.BlockRangeUpdatePacket{
		Earliest:   status.MinimumBlockHeight,
		Latest:     status.MaxBlockHeight,
		LatestHash: bestHash,
	}

	data, err := rlp.EncodeToBytes(&request)
	if err != nil {
		cs.logger.Error("blockRangeUpdate", "err", err)
		return
	}

	for _, s := range sentries {
		handshake, err := s.HandShake(ctx, &emptypb.Empty{})
		if err != nil {
			cs.logger.Error("blockRangeUpdate", "err", err)
			continue // continue sending message to other sentries
		}

		version := direct.ProtocolToUintMap[handshake.Protocol]
		if version >= direct.ETH69 {
			_, err := s.SendMessageToAll(ctx, &sentryproto.OutboundMessageData{
				Id:   sentryproto.MessageId_BLOCK_RANGE_UPDATE_69,
				Data: data,
			})
			if err != nil {
				cs.logger.Error("blockRangeUpdate", "err", err)
				continue
			}
		}
	}
}
```
This prevents broadcasting malformed block range announcements that could cause erigon nodes to be downgraded by peers.

### Summary

Unconditional throw on post‑Fulu blob validation will cause an inability to sync past the fork for Teku nodes as a syncing node will import a batch that spans the fork boundary, call blob validator on the first post‑Fulu block, throw, and abort the batch.

### Root Cause

In [BlobSidecarManagerImpl.java:146-188](https://github.com/Consensys/teku/blob/f91f8bb7c0a2f3e3a72278efdf485f935876d7d9/ethereum/statetransition/src/main/java/tech/pegasys/teku/statetransition/blobs/BlobSidecarManagerImpl.java#L146-L188), the`DataAndValidationResult` method throws for Fulu blocks, and historical batch loop feeds it post‑Fulu blocks when the batch starts/ends pre‑Fulu:
```java
public DataAndValidationResult<BlobSidecar> createAvailabilityCheckerAndValidateImmediately(
    final SignedBeaconBlock block, final List<BlobSidecar> blobSidecars) {
  // [...]

  if (spec.atSlot(block.getSlot()).getMilestone().isGreaterThanOrEqualTo(SpecMilestone.FULU)) {
    // @audit Post-Fulu unconditional throw breaks historical batch on boundary
    throw new RuntimeException(
        String.format("PeerDAS block %s shouldn't be verified in BlobSidecarManager", block));
  }

  // [...]
}
```

And historical sync in [HistoricalBatchFetcher.java](https://github.com/Consensys/teku/blob/f91f8bb7c0a2f3e3a72278efdf485f935876d7d9/beacon/sync/src/main/java/tech/pegasys/teku/beacon/sync/historical/HistoricalBatchFetcher.java) validates every block in a boundary batch if first or last slot requires blobs:
```java
private SafeFuture<Boolean> requestBlocksAndBlobSidecarsByRange() {
  // [...]
  if (blobSidecarManager.isAvailabilityRequiredAtSlot(endSlot)
      || blobSidecarManager.isAvailabilityRequiredAtSlot(requestParams.getStartSlot())) {
    // [...]
    // @audit Boundary batch triggers blob requests validation across range
    blobSidecarsRequest =
        peer.requestBlobSidecarsByRange(
            requestParams.getStartSlot(),
            requestParams.getCount(),
            requestManager::processBlobSidecar);
  } else {
    blobSidecarsRequest = SafeFuture.COMPLETE;
  }

  return SafeFuture.allOfFailFast(blocksRequest, blobSidecarsRequest)
      .thenApply(__ -> shouldRetryBlocksAndBlobSidecarsByRangeRequest());
}

private void validateBlobSidecars(
    final UInt64 firstSlotInBatch,
    final UInt64 latestSlotInBatch,
    final Collection<SignedBeaconBlock> blocks) {
  // @audit Gate on first/last slot only, but loop feeds post-Fulu too
  if (!blobSidecarManager.isAvailabilityRequiredAtSlot(firstSlotInBatch)
      && !blobSidecarManager.isAvailabilityRequiredAtSlot(latestSlotInBatch)) {
    return;
  }
  LOG.trace("Validating blob sidecars for a batch");
  blocks.forEach(this::validateBlobSidecars);
}

private void validateBlobSidecars(final SignedBeaconBlock block) {
  final List<BlobSidecar> blobSidecars =
      blobSidecarsBySlotToImport.getOrDefault(
          block.getSlotAndBlockRoot(), Collections.emptyList());

  LOG.trace("Validating {} blob sidecars for block {}", blobSidecars.size(), block.getRoot());
  // @audit Calls immediate blob validator for each block, including Fulu
  final DataAndValidationResult<BlobSidecar> validationResult =
      blobSidecarManager.createAvailabilityCheckerAndValidateImmediately(block, blobSidecars);

  if (validationResult.isFailure()) {
    final String causeMessage =
        validationResult
            .cause()
            .map(cause -> " (" + ExceptionUtil.getRootCauseMessage(cause) + ")")
            .orElse("");
    throw new IllegalArgumentException(
        String.format(
            "Blob sidecars validation for block %s failed: %s%s",
            block.getRoot(), validationResult.validationResult(), causeMessage));
  }
}
```

### Internal Pre-conditions

1. Sync service needs to pick a batch whose first or last slot is pre‑Fulu so that `validateBlobSidecars(first, last, blocks)` does not early‑return.
2. The same batch must include at least one post‑Fulu block (so per‑block loop reaches post‑Fulu).

### External Pre-conditions

1. The Fulu fork is activated on the network (blocks exist on both sides of boundary).
2. The node falls behind at least one batch around the fork.

### Attack Path

1. Operator restarts a Teku node or starts initial sync after Fulu activates.
2. Historical sync requests a by‑range batch where first/last slot is pre‑Fulu but the batch spans into post‑Fulu.
3. The validator loop calls `createAvailabilityCheckerAndValidateImmediately` on the first post‑Fulu block.
4. BlobSidecarManager throws RuntimeException and batch import aborts with exception.

### Impact

The Teku node cannot sync past the Fulu fork and remains stuck behind the boundary.

### PoC

_No response_

### Mitigation

In `HistoricalBatchFetcher.validateBlobSidecars`, skip per‑block blob validation when `spec.atSlot(block.getSlot()).getMilestone() >= FULU`.

### Summary

Using `max(custody_group_count, samples_per_slot)` for custody group sampling goes against `EIP-7918` and will cause an over-sampling of groups/columns for Lighthouse nodes, as the sampling helpers will request more groups than exist or than required, inflating work and risking stalls.

### Root Cause

In the `ChainSpec` PeerDAS helpers, custody groups use `max`:

https://github.com/sigp/lighthouse/blob/1fb94ce432f08b110e531e1ce2e44b13b1392e5f/consensus/types/src/chain_spec.rs#L817-L819

```rust
/// Returns the number of custody groups to sample per slot.
pub fn sampling_size_custody_groups(&self, custody_group_count: u64) -> Result<u64, String> {
    Ok(std::cmp::max(custody_group_count, self.samples_per_slot))//@audit
}
```

and `sampling_size_columns` multiplies that by columns/group:

```rust
    pub fn sampling_size_columns<E: EthSpec>(
        &self,
        custody_group_count: u64,
    ) -> Result<usize, String> {
        let sampling_size_groups = self.sampling_size_custody_groups(custody_group_count)?;
        let columns_per_custody_group = self.data_columns_per_group::<E>();

        let sampling_size_columns = columns_per_custody_group
            .safe_mul(sampling_size_groups)
            .map_err(|_| "Computing sampling size should not overflow")?;

        Ok(sampling_size_columns as usize)
    }
```



This should be `min(custody_group_count, samples_per_slot)` to cap by what exists and by the target sampling rate.

### Internal Pre-conditions

1. `self.samples_per_slot = 8`.
2. `custody_group_count` is either greater than 8 (e.g., 64) or less than 8 (e.g., 4).

### External Pre-conditions

None

### Attack Path

1. Node calls `sampling_size_custody_groups(64)` with `samples_per_slot = 8`.
2. Function returns 64 because of the issue, not 8.
3. `sampling_size_columns` multiplies by columns/group, requesting an oversized column sample.
4. Scheduler over-requests columns.

### Impact

- Spec violation when `CGC > SAMPLES_PER_SLOT` (oversampling):
The helper is meant to return the peer-sampling budget, which must not exceed the per-slot target. With `custody_group_count=64` and `samples_per_slot=8`, the current `max(64, 8) = 64` returns `8 times` the allowed peer-sampling. Downstream, `sampling_size_columns::<E>` multiplies by `data_columns_per_group::<E>()`, inflating column requests and KZG verification work, which increases the probability that DA checks miss slot deadlines. This can result in delayed imports and missed attestations.

- Logical error when `CGC < SAMPLES_PER_SLOT ` (asking for groups that do not exist):
With `custody_group_count=4` and `samples_per_slot=8`, the function returns `8`, instructing callers to sample more peer groups than exist. For a peer-only helper, the correct cap is the availability of groups and the per-slot target: `min(CGC, SAMPLES_PER_SLOT)`. Returning 8 here pushes callers to construct requests that cannot be satisfied and still amplifies to too many columns in `sampling_size_columns::<E>`.

The overall impact affects liveness because of the delayed imports and missed attestations mentioned.


As per EIP-7918, there is a fixed per-slot sampling target that must not be exceeded by the peer-sampling component of the logic. This is currently not the case as the current max(CGC, SAMPLES_PER_SLOT) violates this requirement in both directions.

https://eips.ethereum.org/EIPS/eip-7918#blob-kzg-proof-verification-cost
```text
Nodes peer-sample SAMPLES_PER_SLOT (8) columns each slot (in addition to custodied columns).
```

Because this bug directly touches the runtime behavior and can cause real missed attestations , which can affect liveness, Low severity is warranted.

### PoC


Paste this test in `consensus/state_processing/src/per_slot_processing.rs`

It sets `samples_per_slot = 8`, then calls `sampling_size_custody_groups(64)` and expects `64` instead of the intended cap of `8`.
It also checks `sampling_size_columns::<MainnetEthSpec>(4)` behaves as if 8 groups were used (oversampling).

But it returns `max(groups, samples_per_slot)` which is precisely the wrong behavior. The test passes, showing the implementation is currently doing that.

Note: you must add the following in cargo.toml of `consensus/state_processing`

```toml
anyhow = { workspace = true }
```


```rust

mod tests {

use anyhow::Result;//@audit see cargo.toml
use types::{ChainSpec, MainnetEthSpec};

fn mk_spec(samples_per_slot: usize) -> ChainSpec {
    let mut spec = ChainSpec::mainnet();
    spec.samples_per_slot = samples_per_slot as u64;
    spec
}


#[test]
fn test_poc_sampling_columns_never_exceeds_selected_groups_columns() -> Result<()> {
    let spec = mk_spec(8);
    let groups: usize = 4;

    // Baseline available columns if we actually sampled only 4 groups.
    let cols_per_group: usize = 2;
    let total_cols: usize = groups * cols_per_group;

    // Call helpers using the integer type they expect (u64 is typical in ChainSpec).
    let groups_u64: u64 = groups as u64;
    let max_groups: u64 = spec.sampling_size_custody_groups(groups_u64).unwrap();
    let col_target: usize = spec.sampling_size_columns::<MainnetEthSpec>(groups_u64).unwrap();

    // @audit - we confirm it uses the wrong amount because the function uses max(groups, samples_per_slot)
    let expected_groups_buggy: u64 = std::cmp::max(groups as u64, spec.samples_per_slot);
    assert_eq!(
        max_groups, expected_groups_buggy,
        "This PoC passes only while the bug exists (sampling_size_custody_groups uses max)"
    );

    // @audit oversampling pushes the target at/above the 4-group baseline.
    assert!(
        col_target >= total_cols,
        "This PoC passes only while the bug exists (columns reflect oversampling >= baseline)"
    );

    Ok(())
}



}
```

### Mitigation

```diff

pub fn sampling_size_custody_groups(&self, custody_group_count: u64) -> Result<u64, String> {
-    Ok(std::cmp::max(custody_group_count, self.samples_per_slot))
+   Ok(std::cmp::min(custody_group_count, self.samples_per_slot))
}
```

### Summary

 *   **Description**: The function `from_ssz_unchecked` is implemented with `GenericArray::from_slice(bytes)`. According to `generic-array` documentation and standard Rust behavior, this function will panic if the length of the input `bytes` slice does not exactly match the compile-time generic length `N`.
    *   **Impact**: A remote attacker can craft a malicious SSZ-encoded P2P message (e.g., `BeaconBlock`, `BlobSidecar`, or `Attestation`) where a fixed-size byte vector field is encoded with an incorrect length. When a Grandine node receives and attempts to parse this message, the call to `from_ssz_unchecked` will trigger a panic. In a production client, an unhandled panic in a network processing thread will crash the entire node, constituting a Denial of Service (DoS). An attacker could use this to systematically take validators offline, jeopardizing network liveness and potentially impacting finality. This falls under the Fusaka audit scope of "infinite resource generation or client shutdown."
    *   **Root Cause**:
https://github.com/grandinetech/grandine/blob/57da4967a7f4c00cc9c6de11a2ca5f7636169b6a/ssz/src/byte_vector.rs#L63-#68
        ```rust
        // ssz/src/byte_vector.rs:63-68
        fn from_ssz_unchecked(_context: &C, bytes: &[u8]) -> Result<Self, ReadError> {
            // ...
            // `from_slice` panics on length mismatch instead of returning an error.
            let bytes = GenericArray::from_slice(bytes).clone().into();
            Ok(Self { bytes })
        }
        ```
    *   **Evidence**: This vulnerability pattern (panic on untrusted input) is a well-known DoS vector. The function is named `unchecked`, implying the caller is responsible for length validation. However, for defense-in-depth, a critical network-facing parser should never panic on invalid data, regardless of its name. A bug in a higher-level SSZ parsing function could inadvertently pass an invalid slice, making this "unchecked" function the last line of defense before a crash. The Ethereum consensus spec's networking rules implicitly require clients to gracefully handle malformed data, typically by dropping the message and penalizing the peer, not by crashing.
    *   **Reproduction Steps**:
        1.  Identify a P2P message containing a `ByteVector`, such as a `BeaconBlockHeader` with its 32-byte `parent_root`.
        2.  Craft a valid SSZ message but tamper with the bytes for `parent_root` to be only 31 bytes long, while ensuring the overall message structure is otherwise plausible enough to reach the deserializer.
        3.  Send this message to a Grandine peer over the network.
        4.  The node's SSZ deserializer will eventually call `ByteVector::<U32>::from_ssz_unchecked` with the 31-byte slice.
        5.  `GenericArray::from_slice` panics, terminating the task and likely the entire client.
    *   **Mitigation**: Replace the panicking operation with one that returns a `Result`. The function should handle the error gracefully, even if it is "unchecked," to prevent catastrophic failure.
        ```rust
        // Recommended Fix
        fn from_ssz_unchecked(_context: &C, bytes: &[u8]) -> Result<Self, ReadError> {
            let array: &GenericArray<u8, N> = bytes.try_into().map_err(|_| {
                ReadError::InvalidByteLength {
                    len: bytes.len(),
                    expected: N::USIZE,
                }
            })?;
            let bytes = (*array).into();
            Ok(Self { bytes })
        }
        ```

### Root Cause

https://github.com/grandinetech/grandine/blob/57da4967a7f4c00cc9c6de11a2ca5f7636169b6a/ssz/src/byte_vector.rs#L63-#68


