	require.NoError(t, err, "Panic should be caught and not returned as error")

	// In a real scenario, this would hide the fact that attestation processing failed
	// The block would be considered processed successfully when it actually wasn't
	t.Log("WARNING: Panic was silently caught - attestation processing failed but was not reported!")
