    var blobFixture = new BlobTestFixture();
    var v1Bundle = blobFixture.createBlobProofBundle(KZG_PROOF);
    var versionedHash = v1Bundle.getVersionedHash();
    when(transactionPool.getBlobProofBundle(versionedHash)).thenReturn(v1Bundle);

    var requestContext = buildRequestContext(versionedHash);
    var response = getSuccessResponse(requestContext);
    assertThat(extractResult(response)).isNull();
